__d(function(e,a,i,o,t,s,r){t.exports={fr:[{id:"cf_001",category:"cashflow",title:"Le bonus inattendu",scenario:"Tu re\xe7ois un bonus de $3 000 au travail. Que fais-tu ?",choice_liability:{label:"Acheter le dernier smartphone haut de gamme + accessoires",feedback:"Tu viens de transformer $3 000 en un objet qui vaut $1 800 demain et $0 dans 3 ans. C'est ce que Kiyosaki appelle nourrir la colonne des passifs."},choice_asset:{label:"Investir dans un fonds indiciel diversifi\xe9 qui g\xe9n\xe8re un revenu mensuel",feedback:"Ton bonus travaille maintenant pour toi chaque mois \u2014 tant que tu ne le vends pas. C'est le r\xe9flexe actif que Philia Vault t'entra\xeene \xe0 d\xe9velopper."}},{id:"cf_002",category:"cashflow",title:"L'augmentation de salaire",scenario:"Tu obtiens une augmentation de $400/mois. Comment g\xe8res-tu ce surplus ?",choice_liability:{label:"Passer \xe0 un appartement plus grand et une voiture neuve",feedback:"Lifestyle inflation : tes d\xe9penses ont absorb\xe9 l'augmentation avant qu'elle ne cr\xe9e quoi que ce soit. Ton cashflow net reste \xe0 z\xe9ro."},choice_asset:{label:"Automatiser un virement de $350 vers un compte d'investissement",feedback:"L'automatisation est le secret des riches. Tu ne vois pas l'argent, il n'est jamais d\xe9pens\xe9 \u2014 il s'accumule et travaille."}},{id:"cf_003",category:"cashflow",title:"La prime de No\xebl",scenario:"Tu re\xe7ois une prime de fin d'ann\xe9e de $1 500. C'est la f\xeate ?",choice_liability:{label:"Organiser un grand repas de f\xeate + cadeaux pour tout le monde",feedback:"G\xe9n\xe9reux, mais cet argent a disparu en 48h. L'exp\xe9rience est r\xe9elle, l'actif est nul."},choice_asset:{label:"Placer $1 000 et utiliser $500 pour les f\xeates",feedback:"\xc9quilibre parfait. Tu profites sans sacrifier ton futur. La r\xe8gle 80/20 appliqu\xe9e \xe0 une prime."}},{id:"cf_004",category:"cashflow",title:"Le remboursement fiscal",scenario:"Tu re\xe7ois un remboursement d'imp\xf4ts de $2 200. Premi\xe8re r\xe9action ?",choice_liability:{label:"Partir en vacances all-inclusive bien m\xe9rit\xe9es",feedback:"Des souvenirs pr\xe9cieux, mais aucun actif cr\xe9\xe9. Dans 30 jours, l'argent est parti et les dettes continuent."},choice_asset:{label:"Rembourser une dette \xe0 taux \xe9lev\xe9 ou constituer un fonds d'urgence",feedback:"Rembourser une dette co\xfbteuse, c'est un rendement garanti \xe9quivalent \xe0 son taux d'int\xe9r\xeat. Math\xe9matiquement imbattable \xe0 court terme."}},{id:"cf_005",category:"cashflow",title:"La cagnotte cadeau",scenario:"Tes amis t'offrent une cagnotte de $800 pour ton anniversaire. Que fais-tu ?",choice_liability:{label:"Sortir au restaurant avec toute la bande pour c\xe9l\xe9brer",feedback:"Belle exp\xe9rience \u2014 et l'argent est \xe9vapor\xe9. La colonne des actifs n'a pas boug\xe9."},choice_asset:{label:"Acheter des parts fractionn\xe9es d'actifs productifs",feedback:"Tu transformes un cadeau en revenu r\xe9current. Tes amis t'ont offert un actif sans le savoir."}},{id:"cf_006",category:"cashflow",title:"Le petit extra mensuel",scenario:"Ton employeur augmente ton panier repas de $150/mois. Comment l'utilises-tu ?",choice_liability:{label:"Manger dans de meilleurs restaurants chaque midi",feedback:"Tu as augment\xe9 ton niveau de vie, pas ton patrimoine. Chaque mois, $150 disparaissent en plaisir imm\xe9diat."},choice_asset:{label:"Apporter ta lunch box et investir les $150 chaque mois",feedback:"$150/mois pendant 10 ans, m\xeame avec un rendement modeste, c'est une somme significative. La constance bat l'intensit\xe9."}},{id:"cf_007",category:"cashflow",title:"Le second job freelance",scenario:"Tu d\xe9croches une mission freelance de $2 500 ce mois-ci. Premi\xe8re d\xe9cision ?",choice_liability:{label:"Te r\xe9compenser avec des achats que tu remettais \xe0 plus tard",feedback:"Tu as travaill\xe9 deux fois plus pour consommer deux fois plus. Le hamster court plus vite mais la roue ne tourne pas dans l'autre sens."},choice_asset:{label:"Investir 80% et utiliser 20% comme tu veux",feedback:"La r\xe8gle d'or du revenu exceptionnel. 80% vont construire ta libert\xe9, 20% r\xe9compensent l'effort. Le cercle vertueux commence ici."}},{id:"cf_008",category:"cashflow",title:"La vente de garage",scenario:"Tu fais une vente de tes affaires inutilis\xe9es et tu r\xe9cup\xe8res $400. Et apr\xe8s ?",choice_liability:{label:"Profiter de l'occasion pour acheter de nouvelles choses en solde",feedback:"Tu as vendu du passif pour racheter du passif. \xc9change parfait \u2014 mais ta situation n'a pas chang\xe9."},choice_asset:{label:"D\xe9poser imm\xe9diatement dans ton compte investissement",feedback:"Excellent. Tu viens de convertir du passif dormant (vieilles affaires) en capital productif. C'est exactement le type de mouvement que Kiyosaki enseigne."}},{id:"cf_009",category:"cashflow",title:"Le cashback de carte",scenario:"Tu accumules $250 de cashback sur l'ann\xe9e. Que fais-tu ?",choice_liability:{label:"Utiliser le cashback pour une sortie restaurant haut de gamme",feedback:"Un plaisir imm\xe9diat, certes m\xe9rit\xe9, mais l'argent ne travaille pas pour toi."},choice_asset:{label:"R\xe9investir le cashback dans un actif productif",feedback:"M\xeame $250 plac\xe9s r\xe9guli\xe8rement cr\xe9ent une habitude mentale plus importante que leur valeur intrins\xe8que. L'identit\xe9 d'investisseur se forge par les petits actes."}},{id:"cf_010",category:"cashflow",title:"Le loyer r\xe9duit",scenario:"Ton propri\xe9taire baisse ton loyer de $200/mois pendant 6 mois. Que fais-tu de la diff\xe9rence ?",choice_liability:{label:"Te permettre des petits extras \u2014 streaming, livraisons, sorties",feedback:"La facilit\xe9 absorbe le surplus. Dans 6 mois, tu n'auras rien de plus \xe0 montrer pour ces 6 mois de 'r\xe9duction'."},choice_asset:{label:"Automatiser un virement de $200 d\xe8s le 1er du mois vers l'\xe9pargne",feedback:"Tu n'as jamais vu cet argent. Il est parti directement construire ton avenir. La meilleure fa\xe7on de d\xe9penser moins est de ne jamais voir l'argent arriver."}},{id:"cf_011",category:"cashflow",title:"La n\xe9gociation d'assurance",scenario:"Tu ren\xe9gocies tes assurances et \xe9conomises $80/mois. Ce surplus va o\xf9 ?",choice_liability:{label:"L'int\xe9grer mentalement dans ton budget 'loisirs'",feedback:"La d\xe9pense invisible. L'argent non fl\xe9ch\xe9 finit toujours dans des d\xe9penses non planifi\xe9es."},choice_asset:{label:"Cr\xe9er un virement automatique de $80 vers un actif d\xe8s ce mois",feedback:"Chaque \xe9conomie est une opportunit\xe9 d'investissement d\xe9guis\xe9e. Tu n'as pas r\xe9duit ton budget \u2014 tu l'as r\xe9allou\xe9 intelligemment."}},{id:"cf_012",category:"cashflow",title:"Le remboursement d'un ami",scenario:"Un ami te rembourse $300 qu'il te devait depuis longtemps. R\xe9flexe ?",choice_liability:{label:"L'occasion de t'offrir quelque chose que tu voulais depuis longtemps",feedback:"L'argent inattendu part toujours en d\xe9penses non planifi\xe9es si tu n'as pas de r\xe8gle pr\xe9\xe9tablie."},choice_asset:{label:"Appliquer ta r\xe8gle : tout argent inattendu va directement dans les actifs",feedback:"La discipline sur les petites sommes forge les habitudes sur les grandes. Une r\xe8gle claire \xe9limine la tentation."}},{id:"cf_013",category:"cashflow",title:"La commission de vente",scenario:"Tu d\xe9croches une commission exceptionnelle de $1 800 ce mois. Plan d'action ?",choice_liability:{label:"F\xeater \xe7a avec des sorties et des achats coup de c\u0153ur",feedback:"La c\xe9l\xe9bration est naturelle. Mais si chaque succ\xe8s est imm\xe9diatement d\xe9pens\xe9, le succ\xe8s ne construit rien."},choice_asset:{label:"C\xe9l\xe9brer modestement et investir le reste pour cr\xe9er un revenu r\xe9current",feedback:"La commission est un \xe9v\xe9nement. Le revenu passif qu'elle g\xe9n\xe8re est permanent. Transforme l'exceptionnel en structurel."}},{id:"cf_014",category:"cashflow",title:"Le dividende de la coop\xe9rative",scenario:"Tu re\xe7ois $120 de dividendes de ta coop\xe9rative d'achat. Que fais-tu ?",choice_liability:{label:"Utiliser les dividendes pour tes courses du mois",feedback:"Les dividendes utilis\xe9s pour consommer ne grossissent jamais. Le cycle de croissance est bris\xe9 d\xe8s le premier retrait."},choice_asset:{label:"R\xe9investir automatiquement les dividendes pour acheter plus de parts",feedback:"L'int\xe9r\xeat compos\xe9 en action. Chaque dividende r\xe9investi g\xe9n\xe8re de futurs dividendes. C'est le moteur de la richesse \xe0 long terme."}},{id:"cf_015",category:"cashflow",title:"Le budget loisirs exc\xe9dentaire",scenario:"Tu r\xe9alises que tu n'as d\xe9pens\xe9 que $150 de ton budget loisirs de $300 ce mois. Que fais-tu des $150 restants ?",choice_liability:{label:"Les reporter sur le mois prochain pour 'te rattraper'",feedback:"La mentalit\xe9 'budget \xe0 d\xe9penser' transforme une \xe9conomie en permission de d\xe9penser plus tard."},choice_asset:{label:"Transf\xe9rer imm\xe9diatement les $150 non d\xe9pens\xe9s vers ton investissement",feedback:"L'\xe9conomie r\xe9alis\xe9e est un actif potentiel. Agir imm\xe9diatement emp\xeache la tentation de la d\xe9penser 'plus tard'."}},{id:"cf_016",category:"cashflow",title:"Le pr\xeat \xe0 un proche",scenario:"Un proche te demande de lui pr\xeater $500 'pour d\xe9panner'. Que fais-tu ?",choice_liability:{label:"Pr\xeater sans h\xe9siter, c'est la famille/un ami",feedback:"La g\xe9n\xe9rosit\xe9 est une valeur. Mais un pr\xeat non formalis\xe9 est souvent un don d\xe9guis\xe9 qui cr\xe9e des tensions relationnelles."},choice_asset:{label:"\xc9valuer ta situation, dire clairement si c'est un pr\xeat ou un don, documenter",feedback:"Clart\xe9 et honn\xeatet\xe9 prot\xe8gent \xe0 la fois la relation et tes finances. Un don assum\xe9 est plus sain qu'un pr\xeat sans retour."}},{id:"cf_017",category:"cashflow",title:"Le caf\xe9 quotidien",scenario:"Tu d\xe9penses $5/jour en caf\xe9. Un coll\xe8gue te dit que c'est $150/mois 'g\xe2ch\xe9s'. Il a raison ?",choice_liability:{label:"Il a raison, je coupe le caf\xe9 imm\xe9diatement pour \xe9conomiser",feedback:"La privation totale est rarement durable. La gestion financi\xe8re n'est pas une p\xe9nitence mais une optimisation intelligente."},choice_asset:{label:"Garder le caf\xe9 mais analyser mes vraies d\xe9penses non-intentionnelles",feedback:"Le caf\xe9 quotidien est souvent la seule d\xe9pense consciente. Les vraies fuites de budget sont les abonnements oubli\xe9s et les achats impulsifs en ligne."}},{id:"cf_018",category:"cashflow",title:"L'augmentation des charges",scenario:"Tes charges fixes augmentent de $100/mois. Comment r\xe9agis-tu ?",choice_liability:{label:"Accepter la hausse et continuer comme avant en coupant ailleurs al\xe9atoirement",feedback:"Sans plan pr\xe9cis, les coupures 'al\xe9atoires' tombent toujours sur les mauvaises choses \u2014 jamais sur les vraies fuites."},choice_asset:{label:"Auditer toutes tes d\xe9penses, identifier les $100 les moins utiles et les \xe9liminer",feedback:"Une augmentation de charges est une opportunit\xe9 d'audit. Tu optimises ton budget plut\xf4t que de le subir."}},{id:"cf_019",category:"cashflow",title:"Le side project rentable",scenario:"Ton projet secondaire g\xe9n\xe8re ses premiers $300 nets ce mois. Que fais-tu ?",choice_liability:{label:"Enfin te payer pour ce travail \u2014 tu le m\xe9rites bien",feedback:"Te payer sur un jeune projet ralentit sa croissance. Les entrepreneurs qui r\xe9ussissent se paient en dernier."},choice_asset:{label:"R\xe9investir $250 dans le projet et te garder $50 symbolique",feedback:"Le r\xe9investissement pr\xe9coce acc\xe9l\xe8re la croissance de fa\xe7on exponentielle. $50 de 'salaire' symbolique maintient la motivation sans freiner le projet."}},{id:"cf_020",category:"cashflow",title:"La fusion des abonnements",scenario:"Tu r\xe9alises que tu paies pour 4 services de streaming ($55/mois total). Que fais-tu ?",choice_liability:{label:"Garder tous les abonnements, tu les utilises tous 'un peu'",feedback:"$55/mois = $660/an pour du contenu consomm\xe9 passivement. Un actif comparable pourrait g\xe9n\xe9rer un revenu mensuel."},choice_asset:{label:"Garder 1-2 maximum, rediriger les $30-40 \xe9conomis\xe9s vers un investissement",feedback:"Chaque abonnement inutile est un loyer pay\xe9 pour de la distraction. L'optimisation des charges fixes lib\xe8re un capital d'investissement r\xe9el."}},{id:"cf_021",category:"cashflow",title:"Le remboursement anticip\xe9",scenario:"Tu peux rembourser $500 de cr\xe9dit consommation ce mois. Ou investir ces $500. Que fais-tu ?",choice_liability:{label:"Investir les $500 \u2014 les rendements couvriront les int\xe9r\xeats du cr\xe9dit",feedback:"Erreur math\xe9matique classique : les taux des cr\xe9dits consommation d\xe9passent presque toujours les rendements d'investissement. Rembourser est la priorit\xe9."},choice_asset:{label:"Rembourser le cr\xe9dit \u2014 c'est un rendement garanti au taux du cr\xe9dit",feedback:"Excellent raisonnement. Rembourser une dette co\xfbteuse offre un rendement garanti \xe9quivalent \xe0 son taux. C'est l'investissement le plus s\xfbr du moment."}},{id:"cf_022",category:"cashflow",title:"Le budget alimentaire",scenario:"Tu peux r\xe9duire ta facture alimentaire de $80/mois en cuisinant plus. \xc7a vaut le coup ?",choice_liability:{label:"Non, le temps que \xe7a prend n'en vaut pas la peine",feedback:"$80/mois = $960/an. \xc9valuer le temps/argent est juste, mais souvent le vrai frein est l'habitude, pas le temps."},choice_asset:{label:"Oui, cuisiner par batch le weekend et r\xe9investir les \xe9conomies",feedback:"Double b\xe9n\xe9fice : meilleure alimentation + $80/mois d'investissement suppl\xe9mentaire. Le batch cooking est un levier sous-estim\xe9."}},{id:"cf_023",category:"cashflow",title:"Le cadeau high-tech",scenario:"Un gadget technologique que tu convoites est en promotion \xe0 $400 (au lieu de $600). C'est le moment ?",choice_liability:{label:"Oui, -33% c'est une occasion \xe0 ne pas rater",feedback:"Une r\xe9duction sur quelque chose que tu n'avais pas pr\xe9vu d'acheter n'est pas une \xe9conomie \u2014 c'est une d\xe9pense d\xe9guis\xe9e en opportunit\xe9."},choice_asset:{label:"Non, ce n'\xe9tait pas dans mon plan. Je conserve les $400 pour un actif",feedback:"La vraie discipline financi\xe8re, c'est de r\xe9sister aux 'bonnes affaires' non planifi\xe9es. Ton plan d'allocation prime sur les promotions."}},{id:"cf_024",category:"cashflow",title:"La prime de d\xe9part",scenario:"Tu quittes un poste et re\xe7ois une prime de d\xe9part de $4 000. Plan d'urgence ?",choice_liability:{label:"Prendre du temps pour voyager pendant la transition professionnelle",feedback:"Les transitions sont co\xfbteuses. Utiliser une prime de d\xe9part pour voyager sans revenu entrant cr\xe9e une pression financi\xe8re inutile."},choice_asset:{label:"Constituer un fonds d'urgence de 3 mois et investir le reste",feedback:"La s\xe9curit\xe9 d'abord. Un fonds d'urgence solide permet de prendre de meilleures d\xe9cisions professionnelles sans la pression du besoin."}},{id:"cf_025",category:"cashflow",title:"Le solde cr\xe9diteur surprise",scenario:"Tu r\xe9alises que tu avais $600 oubli\xe9s sur un vieux compte bancaire. Que fais-tu ?",choice_liability:{label:"L'occasion r\xeav\xe9e pour te faire plaisir sans culpabilit\xe9",feedback:"L'argent 'trouv\xe9' est trait\xe9 diff\xe9remment de l'argent 'gagn\xe9' \u2014 c'est un biais cognitif. En r\xe9alit\xe9, il a la m\xeame valeur."},choice_asset:{label:"Le traiter exactement comme tout autre revenu et l'investir",feedback:"La coh\xe9rence de traitement de tous les flux mon\xe9taires est la marque d'un vrai plan financier. L'argent ne change pas de valeur selon son origine."}},{id:"cf_026",category:"cashflow",title:"Le d\xe9fi \xe9pargne",scenario:"Un ami te propose un d\xe9fi : \xe9conomiser $10 de plus par semaine pendant un an. Tu acceptes ?",choice_liability:{label:"C'est trop peu pour changer quoi que ce soit, \xe7a ne vaut pas la peine",feedback:"$10/semaine = $520/an. Ce n'est pas le montant qui compte \u2014 c'est l'habitude et l'identit\xe9 d'\xe9pargnant qu'elle forge."},choice_asset:{label:"Oui, et j'automatise d\xe8s aujourd'hui un virement hebdomadaire de $10",feedback:"L'automatisation transforme une intention en syst\xe8me. Les syst\xe8mes battent la volont\xe9 sur la dur\xe9e. $520 investis r\xe9guli\xe8rement cr\xe9ent une vraie dynamique."}},{id:"cf_027",category:"cashflow",title:"Le remboursement de caution",scenario:"Tu r\xe9cup\xe8res ta caution de location de $1 200 en d\xe9m\xe9nageant. R\xe9flexe imm\xe9diat ?",choice_liability:{label:"L'utiliser pour meubler et d\xe9corer ton nouvel appartement",feedback:"Naturel \u2014 mais si la caution finance le nouveau logement, tu repars de z\xe9ro financi\xe8rement, comme au d\xe9part."},choice_asset:{label:"Investir la caution et utiliser un budget s\xe9par\xe9 (moins important) pour le logement",feedback:"S\xe9parer les flux \xe9vite de 'consommer' les remboursements. La caution r\xe9cup\xe9r\xe9e est un capital \xe0 pr\xe9server, pas \xe0 red\xe9penser imm\xe9diatement."}},{id:"cf_028",category:"cashflow",title:"L'h\xe9ritage modeste",scenario:"Tu h\xe9rites de $5 000 d'un proche. Comment honores-tu cet h\xe9ritage ?",choice_liability:{label:"R\xe9aliser un r\xeave de voyage en son honneur",feedback:"Le voyage peut \xeatre symbolique et beau. Mais $5 000 d'h\xe9ritage enti\xe8rement d\xe9pens\xe9s ne cr\xe9ent pas de legs financier."},choice_asset:{label:"Investir l'essentiel, r\xe9aliser un petit geste symbolique avec une partie",feedback:"Tu transformes cet h\xe9ritage en actif durable qui continue de travailler. C'est peut-\xeatre la fa\xe7on la plus respectueuse d'honorer le travail de quelqu'un."}},{id:"cf_029",category:"cashflow",title:"Le budget de vacances",scenario:"Tu \xe9conomises pour les vacances ($150/mois pendant 8 mois). Tu as $1 200. Comment les g\xe8res-tu ?",choice_liability:{label:"D\xe9penser les $1 200 en totalit\xe9 pour des vacances m\xe9morables",feedback:"Des vacances finan\xe7ables annuellement sont saines. Mais si $1 200 c'est tout ton \xe9pargne, les vacances t'ont co\xfbt\xe9 toute ta marge de s\xe9curit\xe9."},choice_asset:{label:"Budget vacances $800, investir $400 de la somme \xe9pargn\xe9e",feedback:"Profiter tout en construisant. La discipline de ne pas tout d\xe9penser m\xeame quand c'est 'pr\xe9vu pour \xe7a' est une comp\xe9tence financi\xe8re avanc\xe9e."}},{id:"cf_030",category:"cashflow",title:"L'abonnement gym abandonn\xe9",scenario:"Tu paies $60/mois de gym mais tu n'y vas presque jamais. Que fais-tu ?",choice_liability:{label:"Garder l'abonnement, tu iras 'bient\xf4t'",feedback:"$60/mois \xd7 12 = $720/an pour une intention. Les intentions non ex\xe9cut\xe9es sont les d\xe9penses les plus co\xfbteuses."},choice_asset:{label:"Annuler imm\xe9diatement, r\xe9investir les $60/mois, trouver une alternative gratuite",feedback:"Couper une d\xe9pense inutile et la r\xe9investir imm\xe9diatement est l'un des actes les plus concrets d'optimisation financi\xe8re. Agir maintenant vaut mieux que demain."}},{id:"dt_001",category:"dette",title:"La carte de cr\xe9dit au maximum",scenario:"Ta carte de cr\xe9dit est \xe0 90% de sa limite ($4 500 de solde). Strat\xe9gie ?",choice_liability:{label:"Payer le minimum chaque mois et continuer \xe0 utiliser la carte",feedback:"Le minimum maintient le solde quasi-permanent. Les int\xe9r\xeats compos\xe9s d'une dette consommation sont l'inverse exact de l'int\xe9r\xeat compos\xe9 d'un investissement \u2014 tout aussi puissants, mais contre toi."},choice_asset:{label:"Stop toute utilisation, payer le maximum possible chaque mois jusqu'\xe0 soldation",feedback:"L'avalanche de dette : cibler la dette la plus co\xfbteuse en premier. Chaque dollar de remboursement au-dessus du minimum est un rendement garanti au taux de la carte."}},{id:"dt_002",category:"dette",title:"Le pr\xeat \xe9tudiant",scenario:"Tu dois rembourser $25 000 de pr\xeat \xe9tudiant \xe0 5%. M\xe9thode ?",choice_liability:{label:"Payer exactement la mensualit\xe9 minimale pendant toute la dur\xe9e",feedback:"\xc0 5%, tu payes correctement le co\xfbt de ton \xe9ducation. Mais si tu peux investir \xe0 un rendement sup\xe9rieur, la strat\xe9gie minimale peut \xeatre rationnelle \u2014 \xe0 condition d'investir vraiment la diff\xe9rence."},choice_asset:{label:"Payer un surplus chaque mois pour rembourser plus vite et r\xe9duire les int\xe9r\xeats totaux",feedback:"Chaque mois de remboursement anticip\xe9 r\xe9duit la dur\xe9e et les int\xe9r\xeats totaux. C'est un rendement garanti de 5% sur chaque dollar suppl\xe9mentaire rembours\xe9."}},{id:"dt_003",category:"dette",title:"La consolidation de dettes",scenario:"Tu as 3 dettes \xe0 des taux diff\xe9rents. Un organisme te propose de les regrouper en une seule mensualit\xe9 plus basse. Tu acceptes ?",choice_liability:{label:"Oui ! Une seule mensualit\xe9 plus basse, c'est plus simple",feedback:"Attention : une mensualit\xe9 plus basse sur une dur\xe9e plus longue peut signifier payer beaucoup plus d'int\xe9r\xeats au total. Calculer le co\xfbt total avant de signer."},choice_asset:{label:"Analyser le taux global, la dur\xe9e totale et le co\xfbt r\xe9el avant de d\xe9cider",feedback:"La consolidation peut \xeatre avantageuse \u2014 ou un pi\xe8ge marketing. La vraie question : quel est le co\xfbt total de la dette consolid\xe9e vs le remboursement actuel ?"}},{id:"dt_004",category:"dette",title:"Le d\xe9couvert bancaire r\xe9current",scenario:"Tu utilises syst\xe9matiquement les $500 de d\xe9couvert autoris\xe9 chaque mois. R\xe9action ?",choice_liability:{label:"C'est pratique et la banque l'autorise, donc c'est ok",feedback:"Le d\xe9couvert autoris\xe9 est parmi les cr\xe9dits les plus co\xfbteux en taux r\xe9el. Un d\xe9couvert r\xe9current signale un probl\xe8me de flux qui s'aggrave avec le temps."},choice_asset:{label:"Traiter le d\xe9couvert comme une urgence et restructurer mon budget imm\xe9diatement",feedback:"Le d\xe9couvert r\xe9current est un signal d'alarme, pas un outil de gestion. Il indique que les d\xe9penses d\xe9passent les revenus \u2014 un probl\xe8me structurel, pas ponctuel."}},{id:"dt_005",category:"dette",title:"L'offre 0% pendant 12 mois",scenario:"Un magasin offre le paiement en 12 fois sans frais pour un achat de $1 200. Tu prends ?",choice_liability:{label:"Oui, 0% c'est gratuit, autant profiter",feedback:"Le 0% est r\xe9el \u2014 mais seulement si tu rembourses AVANT la fin de la p\xe9riode. Apr\xe8s, le taux r\xe9trospectif peut \xeatre extr\xeamement \xe9lev\xe9. Et tu as quand m\xeame achet\xe9 un passif."},choice_asset:{label:"Non, si je ne peux pas payer cash, je ne peux probablement pas me le permettre",feedback:"La r\xe8gle de Kiyosaki : si tu dois emprunter pour acheter un passif (une consommation), tu ne peux pas te le permettre. Le 0% rend le passif plus accessible, pas moins passif."}},{id:"dt_006",category:"dette",title:"Le cr\xe9dit auto",scenario:"Tu as besoin d'une voiture. Le concessionnaire propose un cr\xe9dit sur 60 mois avec une mensualit\xe9 'confortable'. Tu signes ?",choice_liability:{label:"Oui, la mensualit\xe9 est dans mon budget",feedback:"Une voiture est un passif qui se d\xe9pr\xe9cie d\xe8s la sortie du garage. Financer un passif sur 60 mois signifie payer des int\xe9r\xeats sur quelque chose qui perd de la valeur chaque mois."},choice_asset:{label:"Acheter une voiture fiable d'occasion avec mes \xe9conomies ou un cr\xe9dit court",feedback:"Une voiture d'occasion pay\xe9e cash ou sur une courte dur\xe9e r\xe9duit le co\xfbt total et la pression mensuelle. Lib\xe9rer les charges fixes, c'est lib\xe9rer du capital."}},{id:"dt_007",category:"dette",title:"La m\xe9thode avalanche vs boule de neige",scenario:"Tu as plusieurs dettes. Quelle m\xe9thode de remboursement choisis-tu ?",choice_liability:{label:"Rembourser les plus petites en premier pour avoir le sentiment de progresser",feedback:"La m\xe9thode boule de neige (petites dettes d'abord) est psychologiquement motivante mais math\xe9matiquement plus co\xfbteuse. Elle co\xfbte plus d'int\xe9r\xeats au total."},choice_asset:{label:"Rembourser la dette au taux le plus \xe9lev\xe9 en premier (m\xe9thode avalanche)",feedback:"La m\xe9thode avalanche est math\xe9matiquement optimale \u2014 tu payes le moins d'int\xe9r\xeats au total. Si tu maintiens la discipline, c'est la strat\xe9gie la plus efficace."}},{id:"dt_008",category:"dette",title:"Le refinancement immobilier",scenario:"Les taux baissent et tu peux refinancer ton pr\xeat immobilier pour \xe9conomiser $150/mois. Que fais-tu de cette \xe9conomie ?",choice_liability:{label:"Augmenter ton niveau de vie avec ce surplus mensuel",feedback:"Tu as optimis\xe9 ta dette mais absorb\xe9 l'\xe9conomie dans le style de vie. L'optimisation ne cr\xe9e de richesse que si elle est r\xe9investie."},choice_asset:{label:"R\xe9investir les $150/mois \xe9conomis\xe9s dans un actif productif",feedback:"L'optimisation de dette + r\xe9investissement imm\xe9diat de l'\xe9conomie : double levier de richesse. Tu travailles moins et construis plus en parall\xe8le."}},{id:"dt_009",category:"dette",title:"Emprunter pour investir",scenario:"Tu peux emprunter $10 000 \xe0 4% pour investir dans un actif qui rapporte th\xe9oriquement 8%. Tu le fais ?",choice_liability:{label:"Oui, le spread de 4% est en ma faveur",feedback:"Le levier amplifie les gains ET les pertes. Un rendement de 8% est une hypoth\xe8se, pas une garantie. Si l'actif baisse, tu dois quand m\xeame rembourser le cr\xe9dit \xe0 4%."},choice_asset:{label:"Attendre d'avoir les fonds propres ou limiter fortement l'effet de levier",feedback:"Le levier sur investissement est un outil avanc\xe9 \xe0 manier avec pr\xe9caution. Pour un d\xe9butant, l'absence de levier est une strat\xe9gie en soi \u2014 la s\xe9curit\xe9 avant l'optimisation."}},{id:"dt_010",category:"dette",title:"Le paiement diff\xe9r\xe9 en ligne",scenario:"Un service en ligne te propose 'achetez maintenant, payez dans 6 mois'. Tu utilises cette option ?",choice_liability:{label:"Oui, \xe7a me laisse le temps de r\xe9unir les fonds",feedback:"'Payer dans 6 mois' signifie souvent reporter une d\xe9pense qu'on ne peut pas se permettre maintenant. Dans 6 mois, d'autres d\xe9penses s'accumulent \u2014 et la dette reste."},choice_asset:{label:"Non, si je ne peux pas payer maintenant, je n'ach\xe8te pas maintenant",feedback:"La discipline du paiement imm\xe9diat est un filtre puissant contre les achats impulsifs. Si tu ne peux pas payer aujourd'hui, l'achat n'est peut-\xeatre pas prioritaire."}},{id:"dt_011",category:"dette",title:"Le garant pour un proche",scenario:"Un proche te demande d'\xeatre garant de son cr\xe9dit immobilier. Tu acceptes ?",choice_liability:{label:"Oui, c'est un ami/famille, je lui fais confiance",feedback:"\xcatre garant, c'est s'engager l\xe9galement \xe0 rembourser la dette en cas de d\xe9faillance du d\xe9biteur. La confiance ne prot\xe8ge pas contre les accidents de vie."},choice_asset:{label:"Non, ou seulement apr\xe8s avoir compris toutes les implications l\xe9gales et financi\xe8res",feedback:"Le cautionnement est une responsabilit\xe9 financi\xe8re r\xe9elle qui peut affecter ta capacit\xe9 d'emprunt future. Une d\xe9cision qui m\xe9rite analyse, pas seulement de l'amour."}},{id:"dt_012",category:"dette",title:"Le rachat de cr\xe9dit",scenario:"Un organisme te propose de racheter tous tes cr\xe9dits pour r\xe9duire ta mensualit\xe9 de $300. Tu acceptes sans h\xe9siter ?",choice_liability:{label:"Oui, $300 de moins par mois c'est exactement ce dont j'ai besoin",feedback:"Une mensualit\xe9 r\xe9duite sur une dur\xe9e allong\xe9e peut co\xfbter des milliers de plus au total. Calculer le co\xfbt global, pas seulement la mensualit\xe9."},choice_asset:{label:"Calculer d'abord le co\xfbt total de la dette avant et apr\xe8s le rachat",feedback:"La mensualit\xe9 n'est qu'une donn\xe9e. Le co\xfbt total (montant \xd7 dur\xe9e \xd7 taux) est la seule m\xe9trique qui compte pour comparer des offres de cr\xe9dit."}},{id:"dt_013",category:"dette",title:"La dette familiale",scenario:"Tu dois de l'argent \xe0 un parent. Il ne te presse pas. Tu priorises ce remboursement ?",choice_liability:{label:"Non, il ne presse pas, je rembourse les autres dettes d'abord",feedback:"Logique financi\xe8rement si la dette familiale est \xe0 0%. Mais ne pas rembourser peut cr\xe9er une tension relationnelle invisible qui a un co\xfbt humain r\xe9el."},choice_asset:{label:"Oui, je rembourse avec un plan clair pour ne pas laisser la dette polluer la relation",feedback:"La clart\xe9 relationnelle et financi\xe8re sont li\xe9es. Un plan de remboursement formalis\xe9, m\xeame sans int\xe9r\xeat, respecte la confiance accord\xe9e et maintient la relation saine."}},{id:"dt_014",category:"dette",title:"Le cr\xe9dit revolving",scenario:"Ta banque t'envoie une carte de cr\xe9dit revolving avec $2 000 de limite. Tu l'actives ?",choice_liability:{label:"Oui, c'est utile pour les urgences et les impr\xe9vus",feedback:"Le cr\xe9dit revolving est l'un des produits financiers les plus co\xfbteux. Un vrai fonds d'urgence sur compte \xe9pargne remplit le m\xeame r\xf4le sans int\xe9r\xeats."},choice_asset:{label:"Non, je construis un fonds d'urgence pour ne jamais avoir besoin d'un cr\xe9dit revolving",feedback:"L'objectif ultime : ne jamais avoir besoin d'un cr\xe9dit d'urgence. Un fonds d'urgence de 3-6 mois de d\xe9penses est le meilleur produit financier qui existe."}},{id:"dt_015",category:"dette",title:"Le pr\xeat entre amis v2",scenario:"Tu as $1 000 disponibles. Un ami te propose de lui pr\xeater \xe0 5% d'int\xe9r\xeat. Tu pr\xe9f\xe8res ?",choice_liability:{label:"Pr\xeater les $1 000 \xe0 5% \xe0 mon ami",feedback:"5% d'int\xe9r\xeat garanti semble attrayant. Mais si l'ami ne rembourse pas, tu perds \xe0 la fois l'argent ET l'ami. Le risque de cr\xe9dit personnel est souvent mal \xe9valu\xe9."},choice_asset:{label:"Investir les $1 000 dans un actif diversifi\xe9 pour \xe9viter de m\xe9langer argent et amiti\xe9",feedback:"Kiyosaki conseille de ne jamais m\xe9langer argent et relations affectives sauf avec des r\xe8gles tr\xe8s claires. Un investissement dans un actif garde l'amiti\xe9 pure."}},{id:"dt_016",category:"dette",title:"L'hypoth\xe8que vs loyer",scenario:"Tu h\xe9sites entre acheter (hypoth\xe8que $1 400/mois) et louer ($1 100/mois). Crit\xe8re de d\xe9cision ?",choice_liability:{label:"Acheter co\xfbte plus cher mais c'est un investissement, c'est forc\xe9ment mieux",feedback:"L'immobilier r\xe9sidentiel est souvent pr\xe9sent\xe9 comme un actif, mais Kiyosaki nuance : ta r\xe9sidence principale ne g\xe9n\xe8re pas de revenu. Elle peut m\xeame \xeatre un passif si elle co\xfbte plus qu'elle ne rapporte."},choice_asset:{label:"Comparer le co\xfbt total de possession vs loyer + investissement de la diff\xe9rence",feedback:"La vraie question : si j'investis les $300 de diff\xe9rence mensuelle pendant 20 ans, quelle est la valeur finale vs la plus-value immobili\xe8re esp\xe9r\xe9e ? La r\xe9ponse n'est pas \xe9vidente."}},{id:"dt_017",category:"dette",title:"Le cr\xe9dit \xe0 la consommation facile",scenario:"Un vendeur te propose un cr\xe9dit 'facile' \xe0 $50/mois pour un achat de $600. Tu acceptes ?",choice_liability:{label:"$50/mois c'est rien, c'est accessible",feedback:"$50/mois peut sembler n\xe9gligeable, mais chaque cr\xe9dit consommation r\xe9duit ta capacit\xe9 d'\xe9pargne et potentiellement ta capacit\xe9 d'emprunt future pour des actifs."},choice_asset:{label:"Refuser et attendre d'avoir \xe9pargn\xe9 les $600 pour payer cash",feedback:"La discipline d'attendre : si tu \xe9pargnes $100/mois, tu as les $600 en 6 mois, sans int\xe9r\xeats. La patience est le premier capital de l'investisseur."}},{id:"dt_018",category:"dette",title:"La ren\xe9gociation de taux",scenario:"Tu peux consacrer 2h \xe0 ren\xe9gocier ton pr\xeat immobilier pour potentiellement \xe9conomiser $5 000 sur la dur\xe9e. Tu le fais ?",choice_liability:{label:"2h pour $5 000 hypoth\xe9tiques, c'est beaucoup d'effort pour rien de garanti",feedback:"$5 000 / 2h = $2 500/heure de valeur potentielle. La ren\xe9gociation est souvent l'action financi\xe8re avec le meilleur ROI qu'un particulier puisse faire."},choice_asset:{label:"Oui, imm\xe9diatement. C'est probablement la meilleure heure de ma vie financi\xe8re",feedback:"La ren\xe9gociation de cr\xe9dit est le levier financier le plus accessible et souvent le plus ignor\xe9. Une heure peut valoir des milliers \u2014 et elle n'est jamais trop tard."}},{id:"dt_019",category:"dette",title:"Le solde carte en fin de mois",scenario:"Tu ne peux pas solder ta carte de cr\xe9dit int\xe9gralement ce mois. Tu payes combien ?",choice_liability:{label:"Le minimum requis, et je compenserai le mois prochain",feedback:"Payer le minimum active les int\xe9r\xeats compos\xe9s contre toi. 'Le mois prochain' n'arrive presque jamais pour les petits soldes \u2014 qui grossissent silencieusement."},choice_asset:{label:"Le maximum possible, et je bloque la carte pour ne pas aggraver la situation",feedback:"Payer le maximum possible + bloquer l'utilisation = double action. On arr\xeate l'h\xe9morragie ET on acc\xe9l\xe8re la gu\xe9rison. Le minimum est une illusion de contr\xf4le."}},{id:"dt_020",category:"dette",title:"Le cr\xe9dit formation",scenario:"Une formation co\xfbte $3 000. Tu peux payer cash ou utiliser un cr\xe9dit \xe0 6%. Que fais-tu ?",choice_liability:{label:"Utiliser le cr\xe9dit pour garder mon cash disponible pour autre chose",feedback:"Si 'autre chose' signifie le d\xe9penser, le cr\xe9dit \xe0 6% est la mauvaise d\xe9cision. Si 'autre chose' signifie investir \xe0 plus de 6%, le calcul peut \xeatre favorable."},choice_asset:{label:"Payer cash si la formation a un ROI clair et mesurable sur mes revenus",feedback:"Une formation est un actif si elle augmente ta capacit\xe9 de revenus de fa\xe7on mesurable. Cash ou cr\xe9dit d\xe9pend du ROI attendu et de ton taux d'int\xe9r\xeat alternatif."}},{id:"dt_021",category:"dette",title:"La dette vs l'\xe9pargne d'urgence",scenario:"Tu as $2 000 d'\xe9pargne et $1 500 de dette \xe0 18%. Tu utilises l'\xe9pargne pour rembourser ?",choice_liability:{label:"Non, garder l'\xe9pargne pour les urgences, c'est la s\xe9curit\xe9",feedback:"Garder $2 000 \xe0 ~1% d'int\xe9r\xeat tout en payant 18% sur $1 500 vous co\xfbte ~$250/an net. La 's\xe9curit\xe9' a un prix r\xe9el."},choice_asset:{label:"Oui, rembourser $1 500 et conserver $500 comme fonds d'urgence minimal",feedback:"Rembourser une dette \xe0 18% avec une \xe9pargne \xe0 1% est un gain net de 17%. Garde un minimum d'urgence ($500), rembourse le reste."}},{id:"dt_022",category:"dette",title:"L'assurance cr\xe9dit",scenario:"La banque te propose une assurance cr\xe9dit \xe0 $40/mois pour couvrir tes remboursements en cas d'accident. Tu prends ?",choice_liability:{label:"Oui, c'est rassurant et la banque le recommande",feedback:"Les assurances cr\xe9dit vendues par les banques sont souvent sur\xe9valu\xe9es et peu adapt\xe9es. Comparer avec une assurance individuelle ou un fonds d'urgence construit soi-m\xeame."},choice_asset:{label:"\xc9valuer la n\xe9cessit\xe9 r\xe9elle et comparer avec des alternatives ind\xe9pendantes",feedback:"Une assurance peut \xeatre utile \u2014 mais le prix et les conditions varient \xe9norm\xe9ment. L'alternative souvent moins ch\xe8re : un fonds d'urgence \xe9quivalent \xe0 3-6 mois de charges."}},{id:"dt_023",category:"dette",title:"Le cr\xe9dit 'investissement'",scenario:"Un ami te dit qu'il a emprunt\xe9 pour acheter des actifs sp\xe9culatifs. Il gagne beaucoup. Tu fais pareil ?",choice_liability:{label:"Si lui peut le faire, moi aussi \u2014 les gains semblent r\xe9els",feedback:"Le biais de confirmation : tu vois les gains, pas les pertes. Les gens ne racontent pas les investissements \xe0 cr\xe9dit qui ont mal tourn\xe9. Le survivorship bias est dangereux."},choice_asset:{label:"F\xe9liciter l'ami, mais analyser le risque r\xe9el du levier avant de copier",feedback:"Le levier amplifie les deux sens. Ton ami a peut-\xeatre eu raison par chance autant que par strat\xe9gie. Analyse ton propre profil de risque avant tout."}},{id:"dt_024",category:"dette",title:"La dette hypoth\xe9caire vs investissement",scenario:"Tu peux rembourser $500/mois suppl\xe9mentaire sur ton hypoth\xe8que (\xe0 3%) OU investir ces $500. Que fais-tu ?",choice_liability:{label:"Rembourser l'hypoth\xe8que plus vite pour \xeatre 'libre de dettes' plus t\xf4t",feedback:"\xc0 3% d'hypoth\xe8que, rembourser par anticipation offre un rendement garanti de 3%. C'est excellent en p\xe9riode de faibles rendements, moins optimal si tu peux investir \xe0 7%+."},choice_asset:{label:"Investir les $500 si le rendement attendu d\xe9passe largement 3%",feedback:"Math\xe9matiquement, si tu peux investir \xe0 long terme avec un rendement esp\xe9r\xe9 de 6-8% et que ton hypoth\xe8que est \xe0 3%, l'investissement gagne. Mais c'est risqu\xe9 \u2014 le 3% est garanti, le 7% ne l'est pas."}},{id:"dt_025",category:"dette",title:"Le rachat de cr\xe9ances",scenario:"Un organisme te propose de racheter ta dette \xe0 50 cents pour un dollar. Tu acceptes ?",choice_liability:{label:"Oui ! Payer 50% de ma dette, c'est la meilleure affaire possible",feedback:"Un r\xe8glement \xe0 50% peut impacter ton historique de cr\xe9dit et tes relations avec les cr\xe9anciers. Il faut aussi v\xe9rifier les implications fiscales \xe9ventuelles selon le pays."},choice_asset:{label:"Analyser les implications l\xe9gales, fiscales et sur le score de cr\xe9dit avant de d\xe9cider",feedback:"Le rachat de cr\xe9ances peut \xeatre une solution viable mais complexe. Comprendre toutes les cons\xe9quences \u2014 notamment sur la capacit\xe9 d'emprunt future \u2014 est essentiel."}},{id:"dt_026",category:"dette",title:"Le cr\xe9dit gratuit du vendeur",scenario:"Un vendeur immobilier te propose un cr\xe9dit vendeur \xe0 0% pendant 2 ans. Trop beau pour \xeatre vrai ?",choice_liability:{label:"0% c'est g\xe9nial, je signe sans trop analyser les d\xe9tails",feedback:"Un cr\xe9dit \xe0 0% du vendeur compense souvent par un prix de vente plus \xe9lev\xe9. Le co\xfbt du financement est inclus dans le prix, pas dans le taux. N\xe9gocier le prix d'abord."},choice_asset:{label:"Analyser si le prix int\xe8gre le co\xfbt du financement et n\xe9gocier sur les deux variables",feedback:"Un vendeur qui offre du financement int\xe8gre g\xe9n\xe9ralement ce co\xfbt dans le prix. La vraie question : quel serait le prix avec un paiement cash ?"}},{id:"dt_027",category:"dette",title:"La cessation de paiement",scenario:"Tu ne peux plus honorer tes dettes. Quelle premi\xe8re action ?",choice_liability:{label:"Attendre et esp\xe9rer que la situation se r\xe9tablisse d'elle-m\xeame",feedback:"L'attente aggrave presque toujours la situation. Les int\xe9r\xeats s'accumulent, les p\xe9nalit\xe9s s'ajoutent, les options de n\xe9gociation se r\xe9duisent."},choice_asset:{label:"Contacter proactivement les cr\xe9anciers et chercher un conseiller financier imm\xe9diatement",feedback:"L'action proactive en situation de crise financi\xe8re est contre-intuitive mais essentielle. Les cr\xe9anciers pr\xe9f\xe8rent g\xe9n\xe9ralement n\xe9gocier plut\xf4t que poursuivre."}},{id:"dt_028",category:"dette",title:"L'endettement \xe9tudiant pr\xe9coce",scenario:"Tu peux choisir une universit\xe9 moins ch\xe8re avec des aides financi\xe8res ou une grande \xe9cole avec $60 000 de pr\xeats. Crit\xe8re de choix ?",choice_liability:{label:"La grande \xe9cole, le r\xe9seau et le prestige justifient la dette",feedback:"Le prestige a une valeur r\xe9elle dans certains domaines. Mais $60 000 de dettes \xe9tudiantes repr\xe9sentent des ann\xe9es de remboursement qui retardent la construction de patrimoine."},choice_asset:{label:"Calculer le ROI r\xe9el de chaque option : diff\xe9rentiel de salaire vs co\xfbt de la dette",feedback:"L'\xe9ducation est un investissement \u2014 comme tout investissement, il faut calculer le rendement. Le diff\xe9rentiel de salaire attendu doit couvrir le surco\xfbt de la dette dans un d\xe9lai raisonnable."}},{id:"dt_029",category:"dette",title:"Le micro-cr\xe9dit professionnel",scenario:"Tu peux emprunter $5 000 pour lancer ton activit\xe9 secondaire. Le projet est solide mais incertain. Tu empruntes ?",choice_liability:{label:"Oui, sans risque pas de gain, l'entrepreneuriat n\xe9cessite d'investir",feedback:"Le risque calcul\xe9 est sain. Mais emprunter pour un projet incertain signifie que si le projet \xe9choue, tu dois quand m\xeame rembourser. Le risque est asym\xe9trique."},choice_asset:{label:"Bootstrapper jusqu'\xe0 valider le concept, puis financer la croissance avec les revenus",feedback:"Le bootstrapping force la validation du mod\xe8le \xe9conomique avant d'engager du capital. Un projet qui peut cro\xeetre lentement avec ses propres revenus est plus robuste qu'un projet financ\xe9 \xe0 cr\xe9dit."}},{id:"dt_030",category:"dette",title:"La dette good vs bad",scenario:"Tu as deux opportunit\xe9s d'emprunt : $10 000 pour acheter une voiture de luxe OU $10 000 pour acheter un bien qui g\xe9n\xe8re un revenu locatif. Quelle diff\xe9rence ?",choice_liability:{label:"Les deux sont des dettes, c'est pareil dans les deux cas",feedback:"Non, Kiyosaki fait une distinction fondamentale : la bonne dette finance un actif qui g\xe9n\xe8re un revenu sup\xe9rieur au co\xfbt de la dette. La mauvaise dette finance un passif."},choice_asset:{label:"La dette locative est potentiellement 'bonne' si le loyer couvre les int\xe9r\xeats et g\xe9n\xe8re un surplus",feedback:"C'est la distinction cl\xe9 de Kiyosaki entre bonne et mauvaise dette. Emprunter pour acqu\xe9rir un actif productif dont le rendement d\xe9passe le taux d'int\xe9r\xeat est un levier l\xe9gitime."}},{id:"inv_001",category:"investissement",title:"Les 1 000 premiers dollars",scenario:"Tu as \xe9conomis\xe9 $1 000 pour investir pour la premi\xe8re fois. O\xf9 vas-tu ?",choice_liability:{label:"Acheter une action d'une entreprise dont tu entends parler partout",feedback:"Suivre la hype m\xe9diatique est le moyen le plus efficace de surpayer un actif au sommet et de le revendre en panique au fond. La popularit\xe9 pr\xe9c\xe8de souvent la bulle."},choice_asset:{label:"Investir dans un fonds indiciel diversifi\xe9 pour commencer sans biais de s\xe9lection",feedback:"Pour un premier investissement, la diversification maximale \xe0 faibles frais est statistiquement la strat\xe9gie la plus solide. Elle \xe9limine le risque de s\xe9lection et le biais \xe9motionnel."}},{id:"inv_002",category:"investissement",title:"La chute des march\xe9s",scenario:"Les march\xe9s chutent de 20%. Ton portefeuille perd $2 000 en 48h. Tu fais quoi ?",choice_liability:{label:"Vendre avant que \xe7a empire \u2014 mieux vaut pr\xe9server ce qu'il reste",feedback:"Vendre pendant une chute transforme une perte latente en perte r\xe9elle. Historiquement, les investisseurs qui vendent pendant les crises ratent presque toujours la reprise."},choice_asset:{label:"Ne rien faire \u2014 ou acheter davantage si tu as des liquidit\xe9s disponibles",feedback:"Les crises sont des soldes pour les investisseurs \xe0 long terme. Buffett dit d'\xeatre avide quand les autres ont peur. Tenir le cap (et id\xe9alement acheter plus) est contre-intuitif mais historiquement gagnant."}},{id:"inv_003",category:"investissement",title:"L'action 'tuyau'",scenario:"Un coll\xe8gue te dit tenir un 'tuyau' sur une action qui va exploser. Tu investis ?",choice_liability:{label:"Oui, si lui est s\xfbr, c'est une opportunit\xe9 \xe0 ne pas rater",feedback:"Investir sur des 'tuyaux' expose \xe0 deux risques : le tuyau est faux (fr\xe9quent) ou le tuyau constitue un d\xe9lit d'initi\xe9 (risque l\xe9gal r\xe9el). La confiance n'est pas une strat\xe9gie d'investissement."},choice_asset:{label:"Non, analyser l'actif soi-m\xeame ou passer \u2014 jamais sur une rumeur",feedback:"Un bon investissement doit r\xe9sister \xe0 une analyse personnelle. Si tu ne comprends pas pourquoi l'actif devrait monter par toi-m\xeame, tu ne comprendras pas non plus quand vendre."}},{id:"inv_004",category:"investissement",title:"La diversification",scenario:"Tu as tout investi dans 2 actions qui se portent bien depuis un an. Strat\xe9gie ?",choice_liability:{label:"Garder la concentration, \xe7a marche bien et diversifier diluerait les gains",feedback:"La concentration amplifie les gains ET les pertes. 2 actions repr\xe9sentent un risque de portefeuille extr\xeame. Les gagnants d'hier ne sont pas garantis de l'\xeatre demain."},choice_asset:{label:"Progressivement diversifier vers un portefeuille de 15+ actifs non-corr\xe9l\xe9s",feedback:"La diversification r\xe9duit le risque sans n\xe9cessairement r\xe9duire le rendement esp\xe9r\xe9. Passer de 2 \xe0 20 actifs r\xe9duit la volatilit\xe9 significativement sans frais suppl\xe9mentaires majeurs."}},{id:"inv_005",category:"investissement",title:"L'immobilier vs bourse",scenario:"Tu as $30 000 d'\xe9pargne. Immobilier locatif ou bourse ? Crit\xe8re principal ?",choice_liability:{label:"L'immobilier, c'est concret et 'on ne perd jamais en immobilier'",feedback:"L'immobilier peut perdre de la valeur. Et 'concret' n'est pas une strat\xe9gie \u2014 c'est un biais \xe9motionnel. Les deux classes d'actifs ont des rendements et des risques diff\xe9rents selon les march\xe9s."},choice_asset:{label:"Analyser le rendement net, la liquidit\xe9 et le niveau de gestion requis pour chaque option",feedback:"Ni l'un ni l'autre n'est universellement sup\xe9rieur. Le rendement net de l'immobilier locatif (loyer - charges - fiscalit\xe9 - temps) est souvent plus faible qu'il n'y para\xeet."}},{id:"inv_006",category:"investissement",title:"Le market timing",scenario:"Un analyste pr\xe9dit que les march\xe9s vont baisser dans 3 mois. Tu attends avant d'investir ?",choice_liability:{label:"Attendre la baisse pour investir \xe0 meilleur prix",feedback:"Personne ne peut pr\xe9dire le march\xe9 de fa\xe7on fiable sur le court terme \u2014 ni les analystes, ni les algorithmes. L'attente fait souvent rater des hausses qui compensent les baisses anticip\xe9es."},choice_asset:{label:"Investir maintenant avec ton plan habituel \u2014 le temps dans le march\xe9 bat le timing du march\xe9",feedback:"'Time in the market beats timing the market' est l'une des conclusions les plus robustes de la finance comportementale. Chaque mois hors du march\xe9 est une opportunit\xe9 perdue."}},{id:"inv_007",category:"investissement",title:"Les frais de gestion",scenario:"Tu h\xe9sites entre un fonds avec 0,2% de frais annuels et un autre avec 2% de frais mais 'g\xe9r\xe9 activement'. Lequel choisir ?",choice_liability:{label:"Les 2% sont justifi\xe9s si le g\xe9rant est expert",feedback:"Statistiquement, la majorit\xe9 des fonds g\xe9r\xe9s activement sous-performent leur indice de r\xe9f\xe9rence sur 10 ans, surtout apr\xe8s frais. 1,8% de diff\xe9rence de frais est \xe9norme sur 20 ans."},choice_asset:{label:"Le fonds \xe0 0,2% \u2014 les \xe9tudes montrent que les frais bas sont le meilleur pr\xe9dicteur de performance nette",feedback:"1,8% de frais annuels suppl\xe9mentaires sur $10 000 pendant 20 ans repr\xe9sente une diff\xe9rence de milliers de dollars. Les frais bas sont l'un des rares avantages que l'investisseur individuel peut contr\xf4ler."}},{id:"inv_008",category:"investissement",title:"L'investissement socialement responsable",scenario:"Tu peux choisir entre un fonds ISR (moins diversifi\xe9, frais l\xe9g\xe8rement plus \xe9lev\xe9s) ou un fonds indiciel large. Que priorisez-tu ?",choice_liability:{label:"L'ISR sans h\xe9siter \u2014 les valeurs avant les rendements",feedback:"Les valeurs sont importantes. Mais 'ISR' n'est pas une garantie de meilleur rendement ou d'impact r\xe9el. V\xe9rifier la m\xe9thodologie de l'ISR et ses frais r\xe9els avant de choisir."},choice_asset:{label:"Analyser l'impact r\xe9el, les frais et le rendement historique avant de trancher",feedback:"L'investissement \xe9thique est l\xe9gitime \u2014 mais m\xe9rite autant de rigueur que tout autre investissement. Certains fonds ISR sont excellents, d'autres sont du 'greenwashing' avec des frais \xe9lev\xe9s."}},{id:"inv_009",category:"investissement",title:"Le DCA vs lump sum",scenario:"Tu as $5 000 \xe0 investir. Tu le places tout d'un coup ou r\xe9partis sur 12 mois ?",choice_liability:{label:"R\xe9partir sur 12 mois pour 'r\xe9duire le risque de mauvais timing'",feedback:"Math\xe9matiquement, le lump sum (tout d'un coup) surperforme le DCA (r\xe9partition) 2/3 du temps historiquement, car les march\xe9s montent plus qu'ils ne descendent. Mais le DCA est meilleur psychologiquement."},choice_asset:{label:"Tout d'un coup si les march\xe9s sont 'normaux', DCA si tr\xe8s hauts ou tr\xe8s volatils",feedback:"Les deux ont leur place. Le lump sum gagne statistiquement mais le DCA r\xe9duit le stress \xe9motionnel. Si l'\xe9motion risque de te faire vendre au mauvais moment, le DCA peut \xeatre meilleur en pratique."}},{id:"inv_010",category:"investissement",title:"Les cryptomonnaies",scenario:"Un ami a multipli\xe9 son investissement par 5 en crypto. Tu veux participer ?",choice_liability:{label:"Investir massivement \u2014 les gains potentiels sont \xe9normes",feedback:"Les actifs qui peuvent multiplier par 5 peuvent aussi diviser par 5. La crypto est une classe d'actif \xe0 haute volatilit\xe9 qui convient \xe0 une fraction du portefeuille (5-10% maximum pour la plupart)."},choice_asset:{label:"Si int\xe9ress\xe9, allouer une fraction limit\xe9e que tu es pr\xeat \xe0 perdre totalement",feedback:"La r\xe8gle de la crypto responsable : n'investir que ce que tu es pr\xeat \xe0 perdre enti\xe8rement. La volatilit\xe9 est r\xe9elle et les cycles peuvent \xeatre tr\xe8s longs."}},{id:"inv_011",category:"investissement",title:"Les obligations vs actions",scenario:"Tu approches de la retraite. Tu gardes 100% en actions ou tu r\xe9\xe9quilibres ?",choice_liability:{label:"Garder 100% actions pour maximiser les gains jusqu'\xe0 la fin",feedback:"La s\xe9quence de rendements est cruciale en approche de retraite : une forte baisse au mauvais moment peut r\xe9duire dramatiquement la dur\xe9e de vie du portefeuille."},choice_asset:{label:"R\xe9\xe9quilibrer progressivement vers des actifs moins volatils au fur et \xe0 mesure",feedback:"La r\xe8gle classique : (100 - \xe2ge) % en actions. En approche de retraite, r\xe9duire la volatilit\xe9 est aussi important que maximiser les rendements. Le risque de timing devient critique."}},{id:"inv_012",category:"investissement",title:"Investir dans ce que tu connais",scenario:"Tu travailles dans le secteur technologique. Tu investis principalement dans des entreprises tech ?",choice_liability:{label:"Oui, j'investis l\xe0 o\xf9 j'ai un avantage informationnel r\xe9el",feedback:"Peter Lynch recommande 'd'investir dans ce qu'on conna\xeet' \u2014 mais le biais de familiarit\xe9 peut aussi conduire \xe0 sur-concentrer dans un secteur et sous-diversifier."},choice_asset:{label:"Utiliser la connaissance sectorielle pour s\xe9lectionner, mais maintenir une diversification globale",feedback:"La connaissance sectorielle est un avantage r\xe9el \u2014 \xe0 condition qu'elle serve la s\xe9lection, pas la sur-concentration. Ton emploi d\xe9pend d\xe9j\xe0 du tech : ton portefeuille ne devrait pas lui \xeatre corr\xe9l\xe9 \xe0 100%."}},{id:"inv_013",category:"investissement",title:"La r\xe9allocation annuelle",scenario:"Apr\xe8s une ann\xe9e de hausse, tes actions repr\xe9sentent 80% du portefeuille au lieu de 60%. Tu r\xe9\xe9quilibres ?",choice_liability:{label:"Non, les actions performent bien, autant laisser cro\xeetre",feedback:"L'absence de r\xe9\xe9quilibrage laisse d\xe9river le profil de risque vers plus de volatilit\xe9 que pr\xe9vu. Un portefeuille 80/20 n'est pas le m\xeame risque qu'un 60/40."},choice_asset:{label:"Oui, vendre une partie des actions pour revenir \xe0 l'allocation cible",feedback:"Le r\xe9\xe9quilibrage discipline 'vendre haut, acheter bas' de fa\xe7on syst\xe9matique. C'est une des rares actions o\xf9 la m\xe9canique seule produit une meilleure performance ajust\xe9e au risque."}},{id:"inv_014",category:"investissement",title:"L'immobilier locatif",scenario:"Tu peux acheter un appartement pour $150 000 et le louer $700/mois. C'est une bonne affaire ?",choice_liability:{label:"$700/mois c'est un revenu garanti, c'est excellent",feedback:"$700/mois brut \u2260 $700 de revenu net. Charges de copropri\xe9t\xe9, taxe fonci\xe8re, vacance locative, travaux, gestion : le rendement net peut tomber \xe0 2-3%. Calculer le rendement NET."},choice_asset:{label:"Calculer le rendement net (loyer - toutes charges - fiscalit\xe9) et comparer aux alternatives",feedback:"Le vrai rendement locatif : (loyers annuels - charges - taxes - vacance - gestion) / prix d'achat. Un bien \xe0 3% net n'est pas forc\xe9ment meilleur qu'un fonds indiciel \xe0 frais r\xe9duits."}},{id:"inv_015",category:"investissement",title:"L'investissement dans sa propre formation",scenario:"Une formation avanc\xe9e co\xfbte $2 500 et peut potentiellement augmenter tes revenus de $300/mois. Tu fais le calcul ?",choice_liability:{label:"C'est trop cher pour des r\xe9sultats incertains",feedback:"$2 500 / $300 = 8,3 mois de payback. Si la formation livre vraiment $300/mois suppl\xe9mentaires, c'est un des meilleurs retours sur investissement qui existe."},choice_asset:{label:"Oui, un ROI de ~8 mois est excellent \u2014 mais v\xe9rifier les preuves de r\xe9sultats de la formation",feedback:"L'investissement en soi-m\xeame est souvent le plus rentable. Mais 'potentiellement' n'est pas une garantie. Chercher des t\xe9moignages v\xe9rifiables et des r\xe9sultats concrets avant d'investir."}},{id:"inv_016",category:"investissement",title:"Le portefeuille concentr\xe9 vs dilu\xe9",scenario:"Investir dans 5 actifs que tu comprends parfaitement OU dans 50 actifs via un fonds. Que pr\xe9f\xe8res-tu ?",choice_liability:{label:"5 actifs que je comprends bien, la concentration maximise les gains",feedback:"La concentration peut maximiser les gains \u2014 et les pertes. Warren Buffett peut le faire parce qu'il consacre 12h/jour \xe0 l'analyse. Pour la plupart des investisseurs, la concentration est un risque excessif."},choice_asset:{label:"50 actifs diversifi\xe9s pour r\xe9duire le risque idiosyncratique de chaque actif",feedback:"La diversification est la seule chose gratuite en finance. 50 actifs non-corr\xe9l\xe9s r\xe9duisent drastiquement la volatilit\xe9 sans r\xe9duire n\xe9cessairement le rendement esp\xe9r\xe9 \xe0 long terme."}},{id:"inv_017",category:"investissement",title:"Timing de march\xe9: vendre avant la chute",scenario:"Les experts pr\xe9disent une r\xe9cession. Tu vends tout pour attendre ?",choice_liability:{label:"Oui, mieux vaut prot\xe9ger ses gains en attendant la certitude",feedback:"La certitude n'existe pas en finance. Vendre tout cr\xe9e deux probl\xe8mes : quand revenir ? Et si la chute n'a pas lieu, tu as rat\xe9 la hausse en attendant."},choice_asset:{label:"Rester investi selon mon allocation cible et peut-\xeatre augmenter mon \xe9pargne pour racheter en baisse",feedback:"\xcatre pr\xeat \xe0 acheter en baisse sans vendre en panique est la strat\xe9gie de l'investisseur mature. La r\xe9cession, si elle arrive, est une opportunit\xe9 pour celui qui a des liquidit\xe9s."}},{id:"inv_018",category:"investissement",title:"L'investissement en start-up",scenario:"Un ami lance une start-up et cherche des investisseurs. Il te propose une participation pour $5 000. Tu entres ?",choice_liability:{label:"Oui, les start-ups peuvent rapporter 10x si on entre t\xf4t",feedback:"Les statistiques : 90% des start-ups \xe9chouent. Un investissement de $5 000 dans une start-up d'ami a une probabilit\xe9 \xe9lev\xe9e d'aller \xe0 z\xe9ro ET de cr\xe9er une tension relationnelle."},choice_asset:{label:"\xc9valuer comme tout investissement : plan d'affaires, traction, \xe9quipe, et risque de perte totale",feedback:"Un investissement en start-up m\xe9rite autant de rigueur qu'un investissement boursier. Investir uniquement si tu acceptes la perte totale probable et comprends r\xe9ellement le mod\xe8le \xe9conomique."}},{id:"inv_019",category:"investissement",title:"La liquidit\xe9",scenario:"Tu as tous tes actifs investis \xe0 long terme et une urgence de $1 500 survient. Que fais-tu ?",choice_liability:{label:"Vendre rapidement une partie de mes investissements",feedback:"Vendre des actifs long terme pour une urgence court terme, c'est le sc\xe9nario que le fonds d'urgence est cens\xe9 \xe9viter. La vente forc\xe9e au mauvais moment cristallise les pertes."},choice_asset:{label:"Utiliser mon fonds d'urgence liquide \u2014 c'est exactement pour \xe7a qu'il existe",feedback:"Le fonds d'urgence est le tampon qui permet de ne jamais toucher aux investissements long terme. Son existence prot\xe8ge les actifs productifs des impr\xe9vus de la vie."}},{id:"inv_020",category:"investissement",title:"L'investissement socialement responsable 2",scenario:"Tu d\xe9couvres que l'une de tes entreprises en portefeuille a un comportement environnemental contestable. Que fais-tu ?",choice_liability:{label:"Ne rien faire \u2014 c'est leur probl\xe8me, pas le mien",feedback:"En tant qu'actionnaire, tu es partiellement propri\xe9taire de l'entreprise et de ses pratiques. Ton investissement la finance indirectement."},choice_asset:{label:"\xc9valuer si vendre ou garder selon tes valeurs ET les perspectives financi\xe8res",feedback:"Les deux crit\xe8res peuvent s'aligner : des pratiques contestables cr\xe9ent souvent des risques r\xe9glementaires et r\xe9putationnels \xe0 long terme. \xc9thique et performance ne sont pas toujours oppos\xe9es."}},{id:"inv_021",category:"investissement",title:"Les dividendes vs plus-values",scenario:"Tu pr\xe9f\xe8res des actions \xe0 dividendes (4%/an) ou des actions de croissance (0% dividende mais croissance esp\xe9r\xe9e de 12%) ?",choice_liability:{label:"Les dividendes, c'est du revenu r\xe9el et r\xe9gulier",feedback:"Les dividendes sont attrayants mais fiscalement moins efficaces dans certains pays. Une action qui cro\xeet de 12% cr\xe9e autant de valeur que 4% de dividende + 8% de croissance du cours."},choice_asset:{label:"Analyser le rendement total (dividende + appr\xe9ciation) et la fiscalit\xe9 dans mon pays",feedback:"Le rendement total (dividende + croissance) est la vraie m\xe9trique. La pr\xe9f\xe9rence dividendes vs croissance d\xe9pend aussi de ta tranche fiscale et de tes besoins de revenus actuels."}},{id:"inv_022",category:"investissement",title:"L'investissement dans l'or",scenario:"En p\xe9riode d'incertitude \xe9conomique, un conseiller te recommande 'tout mettre en or'. Tu acceptes ?",choice_liability:{label:"Oui, l'or est une valeur refuge universelle",feedback:"L'or est une r\xe9serve de valeur, pas un actif productif. Il ne g\xe9n\xe8re ni dividende ni loyer ni int\xe9r\xeat. Sur tr\xe8s long terme, son rendement r\xe9el est proche de z\xe9ro apr\xe8s inflation."},choice_asset:{label:"Allouer une fraction limit\xe9e en or comme diversification, pas comme strat\xe9gie principale",feedback:"L'or a sa place dans un portefeuille diversifi\xe9 comme protection contre l'inflation et la corr\xe9lation inverse en crise. Mais 'tout' dans l'or, c'est remplacer un risque par un autre."}},{id:"inv_023",category:"investissement",title:"Les ETF vs fonds actifs",scenario:"Tu dois choisir entre un ETF \xe0 0,15%/an et un fonds actif qui pr\xe9tend battre le march\xe9 \xe0 1,5%/an. Crit\xe8re ?",choice_liability:{label:"Le fonds actif si son g\xe9rant a une bonne r\xe9putation",feedback:"La r\xe9putation pass\xe9e ne pr\xe9dit pas les performances futures. 90% des g\xe9rants actifs sous-performent leur indice sur 15 ans apr\xe8s frais. 1,35% d'\xe9cart de frais est un handicap majeur."},choice_asset:{label:"L'ETF dans la grande majorit\xe9 des cas \u2014 les donn\xe9es montrent la sup\xe9riorit\xe9 des indices \xe0 long terme",feedback:"Les \xe9tudes acad\xe9miques sont unanimes : sur 15+ ans, plus de 90% des fonds actifs sous-performent leur indice de r\xe9f\xe9rence apr\xe8s frais. L'ETF \xe0 bas co\xfbts gagne statistiquement."}},{id:"inv_024",category:"investissement",title:"L'allocation d'actifs en d\xe9but de carri\xe8re",scenario:"Tu as 25 ans et commences \xe0 investir. Quelle allocation choisir ?",choice_liability:{label:"50% actions, 50% obligations pour '\xe9quilibrer le risque'",feedback:"\xc0 25 ans, tu as 40 ans d'horizon d'investissement. Les obligations sur-diversifient \xe0 la baisse. \xc0 cet \xe2ge, la capacit\xe9 de r\xe9sistance aux cycles favorise une allocation plus agressive en actifs productifs."},choice_asset:{label:"Allocation majoritairement en actifs productifs \u2014 l'horizon long terme compense la volatilit\xe9",feedback:"\xc0 25 ans, le temps est ton meilleur actif. La volatilit\xe9 \xe0 court terme est absorb\xe9e par les d\xe9cennies devant toi. Une allocation adapt\xe9e \xe0 un long horizon maximise le potentiel de croissance."}},{id:"inv_025",category:"investissement",title:"Les news financi\xe8res",scenario:"Les nouvelles financi\xe8res annoncent une crise imminente. Tu regardes tes investissements ?",choice_liability:{label:"Oui, surveiller quotidiennement pour r\xe9agir vite si \xe7a tourne mal",feedback:"Les \xe9tudes montrent que plus un investisseur regarde son portefeuille, plus il trade (souvent au mauvais moment). La surveillance quotidienne augmente l'anxi\xe9t\xe9 sans am\xe9liorer les r\xe9sultats."},choice_asset:{label:"Non, ma strat\xe9gie est d\xe9finie. Je la r\xe9\xe9value trimestriellement au maximum",feedback:"L'investisseur passionn\xe9 qui surveille quotidiennement sous-performe g\xe9n\xe9ralement celui qui d\xe9finit sa strat\xe9gie et l'ex\xe9cute sans regarder les news. Moins de bruit = meilleures d\xe9cisions."}},{id:"inv_026",category:"investissement",title:"Investir via une structure d\xe9di\xe9e",scenario:"Tu peux investir via une soci\xe9t\xe9 ou holding d'investissement pour optimiser ta situation. \xc7a vaut le co\xfbt de la structure ?",choice_liability:{label:"Non, trop complexe et co\xfbteux \xe0 g\xe9rer",feedback:"Pour des montants importants, une structure d\xe9di\xe9e peut repr\xe9senter des avantages significatifs qui d\xe9passent largement les co\xfbts de gestion. \xc0 \xe9valuer selon les montants en jeu et la r\xe9glementation locale."},choice_asset:{label:"Analyser le break-even entre co\xfbts de structure et avantages r\xe9els selon les montants et ta juridiction",feedback:"Une structure d'investissement d\xe9di\xe9e devient pertinente \xe0 partir d'un certain niveau de patrimoine. En dessous, les co\xfbts de cr\xe9ation et de gestion d\xe9passent les b\xe9n\xe9fices \u2014 et les r\xe8gles varient fortement selon le pays."}},{id:"inv_027",category:"investissement",title:"L'investissement dans sa propre entreprise",scenario:"Tu peux investir $10 000 en bourse ou dans ton propre business. Que choisis-tu ?",choice_liability:{label:"En bourse, c'est plus s\xfbr et plus liquide",feedback:"La bourse est liquide mais tu n'as aucun contr\xf4le sur les entreprises. Ton propre business offre un contr\xf4le total et potentiellement les meilleurs rendements \u2014 mais aussi le risque le plus \xe9lev\xe9."},choice_asset:{label:"Selon le stade du business : early stage va dans le business, business mature \u2192 diversification",feedback:"Les meilleures opportunit\xe9s de rendement sont souvent dans son propre business \xe0 un stade pr\xe9coce. \xc0 mesure que le business mature, diversifier progressivement r\xe9duit le risque de concentration."}},{id:"inv_028",category:"investissement",title:"Le portefeuille h\xe9rit\xe9",scenario:"Tu h\xe9rites d'un portefeuille investi dans des titres que tu ne comprends pas. Tu gardes ou tu restructures ?",choice_liability:{label:"Garder sans changer \u2014 \xe7a a march\xe9 pour le d\xe9funt",feedback:"Un portefeuille adapt\xe9 \xe0 quelqu'un d'autre (\xe2ge, objectifs, fiscalit\xe9 diff\xe9rents) n't est pas forc\xe9ment adapt\xe9 \xe0 ta situation. Comprendre ce qu'on poss\xe8de est un minimum."},choice_asset:{label:"Comprendre chaque ligne, \xe9valuer si \xe7a correspond \xe0 mes objectifs, restructurer si n\xe9cessaire",feedback:"H\xe9riter d'un portefeuille m\xe9rite autant d'analyse que construire le sien. Aligner les investissements h\xe9rit\xe9s avec ses propres objectifs et horizon de temps est une responsabilit\xe9 fiduciaire envers soi-m\xeame."}},{id:"inv_029",category:"investissement",title:"L'investissement climatique",scenario:"Tu penses que la transition \xe9nerg\xe9tique va cr\xe9er les plus grandes opportunit\xe9s de la d\xe9cennie. Comment investir ?",choice_liability:{label:"Tout sur les entreprises vertes et les \xe9nergies renouvelables",feedback:"La conviction th\xe9matique peut \xeatre juste mais le timing et la s\xe9lection restent cruciaux. Un secteur peut avoir un bel avenir et des valorisations d\xe9j\xe0 excessives \u2014 ce qui r\xe9duit les rendements futurs."},choice_asset:{label:"Allouer une fraction de mon portefeuille sur ce th\xe8me tout en maintenant une base diversifi\xe9e",feedback:"Une conviction th\xe9matique justifie une surpond\xe9ration, pas une concentration totale. Garder une base diversifi\xe9e prot\xe8ge contre la possibilit\xe9 que le th\xe8me soit juste mais le timing mauvais."}},{id:"inv_030",category:"investissement",title:"L'investissement locatif vs REITs",scenario:"Tu veux t'exposer \xe0 l'immobilier. Immeuble direct ou fonds immobilier cot\xe9 ?",choice_liability:{label:"Immobilier direct \u2014 c'est concret et tu contr\xf4les tout",feedback:"L'immobilier direct offre un contr\xf4le total mais aussi une gestion active, une faible liquidit\xe9 et une concentration g\xe9ographique. Ce n'est pas un actif passif."},choice_asset:{label:"\xc9valuer les deux selon liquidit\xe9, diversification, rendement net et temps de gestion",feedback:"Les fonds immobiliers cot\xe9s offrent diversification, liquidit\xe9 et z\xe9ro gestion. L'immobilier direct offre levier, contr\xf4le et avantages fiscaux potentiels. Les deux ont leur place selon le profil."}},{id:"mn_001",category:"mentalite",title:"Le r\xe9flexe E vs B",scenario:"Tu as une id\xe9e de business mais ton emploi actuel est stable et bien pay\xe9. Que fais-tu ?",choice_liability:{label:"Garder l'emploi stable \u2014 la s\xe9curit\xe9 avant tout",feedback:"La mentalit\xe9 E (Employ\xe9) valorise la s\xe9curit\xe9 du salaire. La stabilit\xe9 a une valeur r\xe9elle \u2014 mais elle peut aussi devenir un plafond qui emp\xeache de construire la vraie libert\xe9 financi\xe8re."},choice_asset:{label:"Tester l'id\xe9e en parall\xe8le pendant les soir\xe9es/weekends avant de sauter le pas",feedback:"Le quadrant B (Business Owner) commence souvent en dehors des heures de travail. Tester \xe0 faible risque avant de sauter est la strat\xe9gie de la plupart des entrepreneurs qui r\xe9ussissent."}},{id:"mn_002",category:"mentalite",title:"La d\xe9finition du risque",scenario:"Ton entourage te dit que 'investir c'est risqu\xe9'. Comment r\xe9agis-tu ?",choice_liability:{label:"Ils ont raison \u2014 mieux vaut garder son argent sur un livret s\xfbr",feedback:"Ne pas investir a aussi un risque : le risque d'inflation qui \xe9rode le pouvoir d'achat de l'\xe9pargne, et le risque de ne pas atteindre ses objectifs financiers \xe0 long terme."},choice_asset:{label:"Ne pas investir est aussi un risque \u2014 celui de perdre du pouvoir d'achat et des d\xe9cennies de croissance",feedback:"Kiyosaki dit que l'\xe9ducation financi\xe8re r\xe9duit le risque. Ce qui est risqu\xe9 pour quelqu'un sans formation ne l'est pas pour quelqu'un qui comprend ce qu'il fait."}},{id:"mn_003",category:"mentalite",title:"L'argent et les \xe9motions",scenario:"Tu fais une mauvaise d\xe9cision financi\xe8re et perds $500. Comment g\xe8res-tu \xe7a ?",choice_liability:{label:"Te punir mentalement et \xe9viter de prendre des risques pendant des mois",feedback:"La peur des pertes (loss aversion) est le biais comportemental le plus document\xe9. Un investisseur qui se punit apr\xe8s une erreur prend de moins bonnes d\xe9cisions futures par exc\xe8s de prudence."},choice_asset:{label:"Analyser l'erreur objectivement, en tirer une le\xe7on et passer \xe0 autre chose",feedback:"Les meilleurs investisseurs font des erreurs \u2014 et en tirent des le\xe7ons sans s'y noyer \xe9motionnellement. L'objectivit\xe9 post-erreur est une comp\xe9tence qui se cultive."}},{id:"mn_004",category:"mentalite",title:"La richesse visible",scenario:"Ton voisin ach\xe8te une voiture de luxe. Quelle est ta r\xe9action int\xe9rieure ?",choice_liability:{label:"Il a r\xe9ussi \u2014 lui aussi peut se le permettre, je devrais travailler plus dur",feedback:"Le syndrome du voisin riche. Les \xe9tudes sur les millionnaires montrent que la richesse r\xe9elle est souvent invisible : voitures modestes, maisons mod\xe9r\xe9es, richesse en actifs non-affich\xe9s."},choice_asset:{label:"La voiture ne prouve rien \u2014 la richesse r\xe9elle est dans les actifs invisibles",feedback:"'The Millionaire Next Door' documente que la plupart des personnes vraiment riches ne l'affichent pas. Une voiture de luxe peut \xeatre le signe d'une richesse r\xe9elle ou d'une dette bien cach\xe9e."}},{id:"mn_005",category:"mentalite",title:"L'\xe9ducation financi\xe8re",scenario:"Tu as 2h libres ce weekend. Que fais-tu ?",choice_liability:{label:"Regarder une s\xe9rie ou te reposer \u2014 tu as bien travaill\xe9 cette semaine",feedback:"Le repos est l\xe9gitime et n\xe9cessaire. Mais 2h de contenu financier \xe9ducatif par semaine peuvent transformer ton rapport \xe0 l'argent sur 1 an."},choice_asset:{label:"Lire un livre ou \xe9couter un podcast sur la finance et les investissements",feedback:"Kiyosaki dit que la diff\xe9rence entre les riches et les autres est ce qu'ils font de leur temps libre. L'\xe9ducation financi\xe8re est un investissement en soi qui rapporte \xe0 vie."}},{id:"mn_006",category:"mentalite",title:"Le conseil du riche",scenario:"Tu as l'occasion de d\xe9jeuner avec quelqu'un de tr\xe8s riche. Quelle question poses-tu ?",choice_liability:{label:"Comment as-tu fait pour te lancer ? Quelle a \xe9t\xe9 ta grande chance ?",feedback:"La question du 'coup de chance' cherche la shortcut. Mais la plupart des fortunes durables r\xe9sultent d'une construction m\xe9thodique, pas d'un coup de d\xe9 unique."},choice_asset:{label:"Quelle erreur m'\xe9viterais-tu de faire ? Quelle habitude a le plus chang\xe9 ta trajectoire ?",feedback:"Les questions sur les erreurs et les habitudes donnent des informations actionnables. Les riches qui r\xe9ussissent sur la dur\xe9e ont g\xe9n\xe9ralement des syst\xe8mes et des habitudes plus que des coups de chance."}},{id:"mn_007",category:"mentalite",title:"La peur de commencer",scenario:"Tu veux investir mais tu penses 'pas encore, je dois en savoir plus d'abord'. Depuis 2 ans. Que fais-tu ?",choice_liability:{label:"Continuer \xe0 apprendre \u2014 mieux vaut \xeatre s\xfbr avant de se lancer",feedback:"L'attente parfaite est l'ennemi de la r\xe9alit\xe9 imparfaite. 2 ans de non-investissement ont un co\xfbt d'opportunit\xe9 r\xe9el. La perfection de la connaissance n'existe pas \u2014 l'action avec incertitude, si."},choice_asset:{label:"Commencer petit avec ce que tu sais, et apprendre en faisant",feedback:"Les comp\xe9tences financi\xe8res r\xe9elles se d\xe9veloppent en pratique, pas seulement en th\xe9orie. Un petit investissement r\xe9el enseigne plus qu'une centaine d'heures de lecture."}},{id:"mn_008",category:"mentalite",title:"La critique de l'entourage",scenario:"Tu d\xe9cides d'investir et ta famille te dit 'tu vas tout perdre'. Comment r\xe9agis-tu ?",choice_liability:{label:"Renoncer ou garder tes projets secrets pour \xe9viter le conflit",feedback:"Cacher ses projets financiers \xe0 l'entourage ou renoncer sous la pression sociale sont deux r\xe9ponses qui permettent \xe0 l'entourage de contr\xf4ler ta trajectoire financi\xe8re."},choice_asset:{label:"\xc9couter la pr\xe9occupation, l'analyser rationnellement, puis d\xe9cider selon tes propres recherches",feedback:"La critique familiale vient souvent de la peur et non de l'expertise. \xc9couter sans ob\xe9ir automatiquement. Analyser le fond de l'argument, pas la forme \xe9motionnelle."}},{id:"mn_009",category:"mentalite",title:"Le temps vs l'argent",scenario:"Tu peux accepter une mission suppl\xe9mentaire pour $500 de plus ce mois. Mais elle prendrait 20h de ton temps libre. Tu acceptes ?",choice_liability:{label:"Oui, $500 c'est $500 \u2014 on ne refuse pas de l'argent",feedback:"$500 / 20h = $25/h. La vraie question : combien vaut ton temps libre ? Et ces 20h pourraient-elles \xeatre utilis\xe9es pour construire quelque chose qui rapporte plus \xe0 terme ?"},choice_asset:{label:"D\xe9pend de l'\xe9tat de mes finances, de ce que je ferais avec ce temps autrement",feedback:"Le temps est l'actif non-renouvelable. \xc0 $25/h, la mission peut valoir le coup \u2014 ou pas. La d\xe9cision devrait int\xe9grer ce que 20h de temps libre pourraient cr\xe9er en alternative."}},{id:"mn_010",category:"mentalite",title:"La honte de parler d'argent",scenario:"Tu ne parles jamais d'argent avec tes amis par crainte de para\xeetre 'obs\xe9d\xe9'. Est-ce sain ?",choice_liability:{label:"Oui, l'argent c'est un sujet priv\xe9 qu'on ne doit pas aborder",feedback:"Le tabou de l'argent est culturellement construit \u2014 et tr\xe8s co\xfbteux. Il emp\xeache de partager les bonnes pratiques, de d\xe9couvrir les erreurs communes et de s'entraider financi\xe8rement."},choice_asset:{label:"Non, parler d'argent avec bienveillance est une source d'apprentissage collective",feedback:"Les personnes qui parlent ouvertement d'argent avec leur entourage apprennent plus vite et font moins d'erreurs. Le tabou financier prot\xe8ge ceux qui vendent des produits co\xfbteux et peu adapt\xe9s."}},{id:"mn_011",category:"mentalite",title:"L'identit\xe9 financi\xe8re",scenario:"Tu te d\xe9cris comme 'quelqu'un qui n'est pas bon avec l'argent'. Est-ce vrai ?",choice_liability:{label:"Oui, certaines personnes ont juste ce don et pas d'autres",feedback:"L'identit\xe9 financi\xe8re n\xe9gative est une proph\xe9tie auto-r\xe9alisatrice. Croire qu'on 'n'est pas bon avec l'argent' emp\xeache d'apprendre et de changer ses comportements."},choice_asset:{label:"Non, c'est une comp\xe9tence qui s'apprend \u2014 pas un trait de caract\xe8re inn\xe9",feedback:"La litt\xe9ratie financi\xe8re est une comp\xe9tence, pas un talent inn\xe9. Kiyosaki a \xe9t\xe9 pauvre avant d'\xeatre riche. Les bonnes habitudes financi\xe8res s'apprennent \xe0 tout \xe2ge."}},{id:"mn_012",category:"mentalite",title:"La jalousie de la richesse",scenario:"Tu vois le succ\xe8s financier d'un pair et tu ressens de la jalousie. Comment transformer \xe7a ?",choice_liability:{label:"\xc9viter de les voir \u2014 leur succ\xe8s te met mal \xe0 l'aise",feedback:"La jalousie \xe9vit\xe9e stagne. Elle ne se transforme pas en motivation sans une r\xe9flexion consciente sur ce qu'elle r\xe9v\xe8le de tes propres d\xe9sirs et blocages."},choice_asset:{label:"Utiliser la jalousie comme signal pour identifier ce que tu veux vraiment et comment l'obtenir",feedback:"La jalousie est une boussole \xe9motionnelle. Elle pointe vers quelque chose que tu valorises mais n'as pas. Utilis\xe9e consciemment, elle devient motivation et clarification des priorit\xe9s."}},{id:"mn_013",category:"mentalite",title:"La g\xe9n\xe9rosit\xe9 et la richesse",scenario:"Tu penses qu'\xeatre riche signifie \xeatre avare. Kiyosaki est-il d'accord ?",choice_liability:{label:"Oui, les riches gardent tout pour eux, c'est pour \xe7a qu'ils s'enrichissent",feedback:"La corr\xe9lation richesse-avarice est un mythe. Les \xe9tudes sur les millionnaires montrent que la g\xe9n\xe9rosit\xe9 est plus r\xe9pandue chez les riches que chez ceux qui cherchent \xe0 para\xeetre riches."},choice_asset:{label:"Non, la g\xe9n\xe9rosit\xe9 et la richesse sont compatibles \u2014 la vraie richesse vient d'un surplus, pas d'une privation",feedback:"Kiyosaki souligne que la vraie richesse cr\xe9e de l'abondance \xe0 partager. La g\xe9n\xe9rosit\xe9 d'un riche qui a des actifs productifs co\xfbte moins en proportion qu'une g\xe9n\xe9rosit\xe9 forc\xe9e par culpabilit\xe9."}},{id:"mn_014",category:"mentalite",title:"La discipline financi\xe8re quotidienne",scenario:"Tu as un budget mensuel que tu ne respectes pas souvent. Pourquoi ?",choice_liability:{label:"Parce que la vie est impr\xe9visible et les budgets sont trop rigides",feedback:"Un budget peut \xeatre flexible sans \xeatre ignor\xe9. L'impr\xe9visible peut \xeatre budg\xe9t\xe9 (fonds d'urgence, budget impr\xe9vus). Le vrai probl\xe8me est souvent l'absence de suivi, pas la rigidit\xe9 du budget."},choice_asset:{label:"Parce que le budget n'est pas automatis\xe9 et que la volont\xe9 seule ne suffit pas",feedback:"La volont\xe9 est un muscle qui s'\xe9puise. Les syst\xe8mes automatiques (virements automatiques, budgets categoris\xe9s par application) remplacent la volont\xe9 par des m\xe9canismes fiables."}},{id:"mn_015",category:"mentalite",title:"L'argent et le bonheur",scenario:"Un ami dit : 'L'argent ne fait pas le bonheur'. Tu r\xe9ponds quoi ?",choice_liability:{label:"Il a raison, le bonheur vient des relations et des exp\xe9riences, pas de l'argent",feedback:"Partiellement vrai. Mais en dessous d'un certain seuil de s\xe9curit\xe9 financi\xe8re, l'absence d'argent cause un stress r\xe9el et chronique qui affecte directement le bonheur."},choice_asset:{label:"L'argent ne fait pas le bonheur, mais son absence peut cr\xe9er beaucoup de souffrance",feedback:"Les recherches en psychologie montrent que l'argent augmente le bonheur jusqu'\xe0 un seuil de s\xe9curit\xe9. En dessous de ce seuil, les probl\xe8mes financiers sont la premi\xe8re source de stress chronique."}},{id:"mn_016",category:"mentalite",title:"La libert\xe9 financi\xe8re comme objectif",scenario:"Ton objectif \xe0 10 ans : libert\xe9 financi\xe8re ou promotion professionnelle ?",choice_liability:{label:"Promotion \u2014 c'est concret, mesurable et valoris\xe9 socialement",feedback:"La promotion augmente le salaire \u2014 un revenu actif. La libert\xe9 financi\xe8re vise le revenu passif. Les deux peuvent coexister, mais la promotion seule ne m\xe8ne pas automatiquement \xe0 la libert\xe9."},choice_asset:{label:"Les deux ne sont pas oppos\xe9s \u2014 utiliser la promotion pour acc\xe9l\xe9rer la libert\xe9 financi\xe8re",feedback:"La promotion peut financer l'investissement qui m\xe8ne \xe0 la libert\xe9. L'erreur est de d\xe9penser l'augmentation plut\xf4t que de l'investir. La promotion est un acc\xe9l\xe9rateur, pas une destination."}},{id:"mn_017",category:"mentalite",title:"La patience et la richesse",scenario:"Tu veux des r\xe9sultats financiers rapides. Est-ce r\xe9aliste ?",choice_liability:{label:"Oui, avec les bons investissements on peut s'enrichir vite",feedback:"La recherche de richesse rapide est la source de la plupart des arnaques financi\xe8res. Les rendements exceptionnels \xe0 court terme impliquent un risque exceptionnel \u2014 souvent mal compris."},choice_asset:{label:"La vraie richesse est lente et pr\xe9visible \u2014 les raccourcis co\xfbtent presque toujours plus cher",feedback:"La richesse durable se construit sur des d\xe9cennies, pas des mois. Les personnes les plus riches du monde ont massivement profit\xe9 de d\xe9cennies d'int\xe9r\xeat compos\xe9, pas de coups de g\xe9nie."}},{id:"mn_018",category:"mentalite",title:"L'erreur financi\xe8re",scenario:"Tu r\xe9alises que tu as pay\xe9 trop cher pour un actif. Tu vends \xe0 perte ou tu gardes ?",choice_liability:{label:"Garder pour ne pas 'mat\xe9rialiser la perte'",feedback:"C'est le biais de l'aversion aux pertes. Une perte latente est une vraie perte \xe9conomique, quelle que soit la colonne comptable. Garder un mauvais actif esp\xe9rant un retour est irrationnel si l'analyse change."},choice_asset:{label:"Analyser objectivement si les perspectives justifient de garder \u2014 ind\xe9pendamment du prix pay\xe9",feedback:"L'analyse du 'que ferais-je si je n'avais pas encore cet actif ? L'ach\xe8terais-je aujourd'hui ?' \xe9limine le biais du prix pay\xe9. La d\xe9cision doit se baser sur les perspectives futures, pas le co\xfbt pass\xe9."}},{id:"mn_019",category:"mentalite",title:"Le travail acharn\xe9 vs le syst\xe8me",scenario:"Tu crois que travailler plus dur que tout le monde est la cl\xe9 du succ\xe8s financier. Kiyosaki est d'accord ?",choice_liability:{label:"Oui, l'effort et la pers\xe9v\xe9rance sont la cl\xe9 absolue",feedback:"Le travail acharn\xe9 est n\xe9cessaire mais insuffisant. Kiyosaki note que les employ\xe9s qui travaillent le plus dur sont souvent les moins riches, parce que leur effort enrichit l'entreprise, pas leur propre colonne d'actifs."},choice_asset:{label:"Non, Kiyosaki insiste : le bon syst\xe8me > le travail acharn\xe9 seul",feedback:"'Travailler dur pour soi, pas pour l'autre' est le message central de Rich Dad Poor Dad. Construire des syst\xe8mes (business, actifs) qui travaillent sans toi est la vraie libert\xe9."}},{id:"mn_020",category:"mentalite",title:"La comparaison sociale",scenario:"Tes amis semblent tous 'r\xe9ussir' sur les r\xe9seaux sociaux. \xc7a t'affecte financi\xe8rement ?",choice_liability:{label:"Oui, leurs publications me poussent \xe0 d\xe9penser pour para\xeetre au m\xeame niveau",feedback:"La comparaison sociale aliment\xe9e par les r\xe9seaux sociaux est un moteur puissant de consommation impulsive. Tu payes des d\xe9penses r\xe9elles pour une image virtuelle."},choice_asset:{label:"Non, je sais que les r\xe9seaux montrent le meilleur de chacun \u2014 je me compare uniquement \xe0 ma version pass\xe9e",feedback:"Comparer sa r\xe9alit\xe9 \xe0 la vitrine des autres est une illusion. La seule comparaison pertinente : es-tu en meilleure situation qu'il y a un an ? La progression personnelle est la vraie m\xe9trique."}},{id:"mn_021",category:"mentalite",title:"La d\xe9l\xe9gation",scenario:"Tu g\xe8res tout toi-m\xeame pour '\xe9viter les arnaques'. Est-ce optimal ?",choice_liability:{label:"Oui, personne ne g\xe8re mon argent aussi bien que moi",feedback:"La sur-centralisation est un goulot d'\xe9tranglement. Les personnes tr\xe8s riches d\xe9l\xe8guent l'ex\xe9cution tout en maintenant la supervision strat\xe9gique."},choice_asset:{label:"D\xe9l\xe9guer l'ex\xe9cution de certaines t\xe2ches financi\xe8res en gardant la supervision strat\xe9gique",feedback:"La richesse scalable implique la d\xe9l\xe9gation. Comptable, conseiller, gestionnaire de biens : d\xe9l\xe9guer l'ex\xe9cution lib\xe8re ton temps pour les d\xe9cisions \xe0 haute valeur ajout\xe9e."}},{id:"mn_022",category:"mentalite",title:"L'apprentissage des erreurs des autres",scenario:"Tu connais quelqu'un qui a fait faillite. Comment utiliser cette exp\xe9rience ?",choice_liability:{label:"\xc9viter tout ce qu'il a fait, m\xeame si les contextes sont diff\xe9rents",feedback:"Copier la peur de quelqu'un d'autre sans analyser le contexte est aussi irrationnel que copier ses actions sans r\xe9flexion. Chaque situation financi\xe8re est unique."},choice_asset:{label:"Analyser les causes structurelles de l'\xe9chec pour en tirer des principes applicables",feedback:"Les \xe9checs des autres sont des enseignements gratuits. Comprendre les m\xe9canismes (levier excessif, manque de liquidit\xe9, concentration) plus que les anecdotes sp\xe9cifiques permet d'extraire des principes."}},{id:"mn_023",category:"mentalite",title:"Le luxe et la valeur",scenario:"Tu h\xe9sites \xe0 acheter un article de luxe \xe0 $800. Comment d\xe9cider ?",choice_liability:{label:"Le luxe r\xe9compense le travail \u2014 tu le m\xe9rites si tu te l'es fix\xe9",feedback:"La r\xe9compense mat\xe9rielle n'est pas probl\xe9matique en soi \u2014 si elle est budg\xe9t\xe9e et proportionn\xe9e aux actifs construits. Le probl\xe8me est quand le luxe pr\xe9c\xe8de les actifs."},choice_asset:{label:"Acheter si mes actifs le couvrent ais\xe9ment \u2014 pas si \xe7a compromet mon investissement mensuel",feedback:"La r\xe8gle de Kiyosaki : les riches ach\xe8tent le luxe en dernier, avec les revenus de leurs actifs. Les pauvres et la classe moyenne ach\xe8tent le luxe d'abord, avec leur revenu actif."}},{id:"mn_024",category:"mentalite",title:"La libert\xe9 du salari\xe9",scenario:"Ton patron te propose une belle promotion avec plus de responsabilit\xe9s mais plus de contraintes. Tu acceptes ?",choice_liability:{label:"Oui, la promotion c'est la progression naturelle de la carri\xe8re",feedback:"Une promotion qui encha\xeene davantage dans l'\xe9change temps-contre-argent n'est pas une progression vers la libert\xe9. C'est une progression dans le quadrant E/S."},choice_asset:{label:"Accepter si la promotion finance un projet d'actifs \u2014 refuser si elle consomme plus de temps sans cr\xe9er d'ind\xe9pendance",feedback:"La promotion n'est ni bonne ni mauvaise \u2014 c'est ce qu'on en fait. Si elle finance un investissement qui r\xe9duit la d\xe9pendance au salaire, elle est un levier. Sinon, c'est une cha\xeene dor\xe9e."}},{id:"mn_025",category:"mentalite",title:"La mentalit\xe9 d'abondance",scenario:"Un concurrent reproduit ton id\xe9e de business. Premi\xe8re r\xe9action ?",choice_liability:{label:"C'est une trahison \u2014 tu vas tout faire pour le bloquer",feedback:"La mentalit\xe9 de raret\xe9 voit la concurrence comme une menace existentielle. La mentalit\xe9 d'abondance la voit comme une validation du march\xe9 et une opportunit\xe9 de se diff\xe9rencier."},choice_asset:{label:"La concurrence valide le march\xe9 \u2014 se concentrer sur ce qui te diff\xe9rencie",feedback:"Un concurrent qui copie ton id\xe9e prouve que le march\xe9 existe. Kiyosaki parle d'abondance : il y a assez de succ\xe8s pour tout le monde. La course \xe0 la diff\xe9renciation est plus productive que la bataille l\xe9gale."}},{id:"mn_026",category:"mentalite",title:"Le premier emploi et l'argent",scenario:"Tu obtiens ton premier emploi \xe0 22 ans. Premi\xe8re d\xe9cision financi\xe8re ?",choice_liability:{label:"S'installer confortablement : appartement sympa, voiture, sorties",feedback:"Le pi\xe8ge du premier salaire : la lifestyle inflation d\xe8s le d\xe9part. Les habitudes \xe9tablies \xe0 22 ans seront difficiles \xe0 changer \xe0 30. Commencer petit et investir la diff\xe9rence est une strat\xe9gie bien document\xe9e."},choice_asset:{label:"Automatiser 20% du salaire en investissement d\xe8s le premier mois, avant de s'habituer au montant",feedback:"Se payer en premier est le principe de Kiyosaki. Avant de s'habituer au salaire complet, allouer automatiquement une partie \xe0 l'investissement cr\xe9e une habitude fondatrice."}},{id:"mn_027",category:"mentalite",title:"Le respect de l'argent",scenario:"Tu re\xe7ois $20 en trop dans ta monnaie au supermarch\xe9. Que fais-tu ?",choice_liability:{label:"Tu gardes \u2014 ce n'est pas ta faute si le caissier s'est tromp\xe9",feedback:"La question de valeurs et pas seulement financi\xe8re. Mais au-del\xe0 de l'\xe9thique, comment tu traites l'argent des petites sommes refl\xe8te ta relation \xe0 l'argent en g\xe9n\xe9ral."},choice_asset:{label:"Tu le signales et rends la monnaie \u2014 l'int\xe9grit\xe9 s'applique aussi aux petits montants",feedback:"Kiyosaki parle de respecter l'argent dans toutes ses formes. L'int\xe9grit\xe9 financi\xe8re dans les petites choses est le fondement de la confiance en soi sur les grandes d\xe9cisions."}},{id:"mn_028",category:"mentalite",title:"La mentalit\xe9 E\u2192S\u2192B\u2192I",scenario:"Tu es salari\xe9 et veux devenir 'propri\xe9taire d'actifs'. Par o\xf9 commences-tu ?",choice_liability:{label:"Quitter imm\xe9diatement son emploi pour lancer quelque chose",feedback:"Le saut imm\xe9diat du E au B sans filet est risqu\xe9. La plupart des entrepreneurs qui r\xe9ussissent ont pr\xe9par\xe9 leur transition en parall\xe8le de leur emploi, pas en quittant brusquement."},choice_asset:{label:"Construire progressivement : E \u2192 side project S \u2192 business B \u2192 actifs passifs I en parall\xe8le",feedback:"Le quadrant de Kiyosaki n'est pas un saut \u2014 c'est une progression. Chaque \xe9tape construit sur la pr\xe9c\xe9dente. La transition se pr\xe9pare pendant qu'on est encore en s\xe9curit\xe9."}},{id:"mn_029",category:"mentalite",title:"Le refus de la m\xe9diocrit\xe9",scenario:"Tu te demandes si viser la libert\xe9 financi\xe8re n'est pas arrogant ou irr\xe9aliste. Est-ce que \xe7a t'arr\xeate ?",choice_liability:{label:"Un peu, oui \u2014 qui suis-je pour vouloir plus que la moyenne ?",feedback:"La normalisation de la m\xe9diocrit\xe9 financi\xe8re est culturellement construite. Se demander 'qui suis-je pour vouloir plus ?' est une limite mentale qui a un co\xfbt financier r\xe9el sur des d\xe9cennies."},choice_asset:{label:"Non \u2014 viser la libert\xe9 financi\xe8re n'est pas arrogant, c'est responsable",feedback:"La libert\xe9 financi\xe8re n'est pas un luxe \u2014 c'est la capacit\xe9 de choisir son temps, ses projets et ses contributions. Y aspirer est un acte de responsabilit\xe9 envers soi-m\xeame et ses proches."}},{id:"mn_030",category:"mentalite",title:"La d\xe9finition du succ\xe8s",scenario:"Comment d\xe9finis-tu le succ\xe8s financier ? Salaire \xe9lev\xe9 ou libert\xe9 de temps ?",choice_liability:{label:"Salaire \xe9lev\xe9 \u2014 la reconnaissance et la r\xe9mun\xe9ration prouvent la valeur",feedback:"Un salaire \xe9lev\xe9 est un succ\xe8s dans le quadrant E. Mais Kiyosaki questionne : si tu arr\xeates de travailler demain, ton niveau de vie change-t-il ? Si oui, tu n'es pas encore financi\xe8rement libre."},choice_asset:{label:"Libert\xe9 de temps \u2014 avoir des actifs qui couvrent mes d\xe9penses sans que je travaille",feedback:"C'est la d\xe9finition de Kiyosaki : la libert\xe9 financi\xe8re, c'est quand tes actifs g\xe9n\xe8rent plus que tes d\xe9penses. Le salaire est un moyen, pas une fin. La libert\xe9 de temps est la destination."}},{id:"cf_031",category:"cashflow",title:"Le budget alimentaire inattendu",scenario:"Tu r\xe9alises que tu d\xe9penses $400/mois en nourriture et livraisons, soit $200 de plus que pr\xe9vu. Que fais-tu ?",choice_liability:{label:"C'est normal, la vie co\xfbte cher \u2014 j'ajuste mon budget \xe0 la hausse",feedback:"Ajuster le budget \xe0 la hausse pour justifier une d\xe9pense non optimis\xe9e est le mouvement inverse de la gestion financi\xe8re. C'est le budget qui guide les d\xe9penses, pas l'inverse."},choice_asset:{label:"Identifier les $200 de fuites (livraisons impulsives, gaspillage) et les rediriger",feedback:"$200/mois = $2 400/an = un investissement significatif. Analyser les fuites et les r\xe9orienter vers un actif est une d\xe9cision de quelques minutes pour un impact annuel majeur."}}],en:[{id:"cf_001",category:"cashflow",title:"The Unexpected Bonus",scenario:"You receive a $3,000 work bonus. What do you do?",choice_liability:{label:"Buy the latest smartphone + AirPods",feedback:"You just turned $3,000 into something worth $1,800 tomorrow. Kiyosaki calls this feeding the liability column."},choice_asset:{label:"Invest in an index fund generating monthly income",feedback:"Your bonus now works for you every month. That's the asset reflex Philia Vault trains you to build."}},{id:"cf_002",category:"cashflow",title:"The Raise",scenario:"You get a $400/month raise. How do you handle the surplus?",choice_liability:{label:"Upgrade your apartment and get a new car",feedback:"Lifestyle inflation: your expenses absorbed the raise before it created anything. Net cashflow stays at zero."},choice_asset:{label:"Automate a $350 transfer to an investment account",feedback:"Automation is the wealthy person's secret. You never see the money, it never gets spent \u2014 it compounds."}},{id:"cf_003",category:"cashflow",title:"The Christmas Bonus",scenario:"You receive a $1,500 year-end bonus. Party time?",choice_liability:{label:"Organize a big holiday dinner and gifts for everyone",feedback:"Generous, but that money vanished in 48 hours. The experience is real, the asset is zero."},choice_asset:{label:"Invest $1,000 and use $500 for the holidays",feedback:"Perfect balance. Enjoy without sacrificing your future. The 80/20 rule applied to a bonus."}},{id:"cf_004",category:"cashflow",title:"The Tax Refund",scenario:"You receive a $2,200 tax refund. First reaction?",choice_liability:{label:"Book an all-inclusive vacation \u2014 you deserve it",feedback:"Precious memories, but no asset created. In 30 days the money is gone and the debts continue."},choice_asset:{label:"Pay off a high-interest debt or build an emergency fund",feedback:"Paying off costly debt is a guaranteed return equal to its interest rate. Mathematically unbeatable short-term."}},{id:"cf_005",category:"cashflow",title:"The Birthday Fund",scenario:"Friends pool $800 for your birthday. What do you do?",choice_liability:{label:"Take everyone out to a nice restaurant to celebrate",feedback:"Great experience \u2014 and the money evaporated. The asset column didn't move."},choice_asset:{label:"Buy fractional shares of productive assets",feedback:"You transform a gift into recurring income. Your friends gave you an asset without knowing it."}},{id:"cf_006",category:"cashflow",title:"The Monthly Extra",scenario:"Your employer increases your meal allowance by $150/month. How do you use the difference?",choice_liability:{label:"Eat at better restaurants every day",feedback:"You raised your lifestyle, not your net worth. Every month, $150 disappears into immediate pleasure."},choice_asset:{label:"Bring your lunch box and invest the $150 each month",feedback:"$150/month for 10 years, even at a modest return, is significant. Consistency beats intensity."}},{id:"cf_007",category:"cashflow",title:"The Freelance Gig",scenario:"You land a freelance project worth $2,500 this month. First decision?",choice_liability:{label:"Reward yourself with purchases you've been putting off",feedback:"You worked twice as hard to consume twice as much. The hamster runs faster but the wheel spins the same way."},choice_asset:{label:"Invest 80% and use 20% however you want",feedback:"The golden rule for extra income. 80% builds your freedom, 20% rewards the effort. The virtuous cycle starts here."}},{id:"cf_008",category:"cashflow",title:"The Garage Sale",scenario:"You sell unused stuff and pocket $400. What next?",choice_liability:{label:"Seize the opportunity to buy new things on sale",feedback:"You sold liabilities to buy liabilities. A perfect swap \u2014 but your situation hasn't changed."},choice_asset:{label:"Deposit it immediately into your investment account",feedback:"You just converted dormant liabilities (old stuff) into productive capital. This is exactly the move Kiyosaki teaches."}},{id:"cf_009",category:"cashflow",title:"The Card Cashback",scenario:"You accumulate $250 in cashback over the year. What do you do?",choice_liability:{label:"Use the cashback for a fancy dinner out",feedback:"A deserved pleasure, but the money doesn't work for you."},choice_asset:{label:"Reinvest the cashback into a productive asset",feedback:"Even $250 invested regularly builds a mental habit more valuable than the dollar amount. The investor identity is forged by small acts."}},{id:"cf_010",category:"cashflow",title:"The Reduced Rent",scenario:"Your landlord drops your rent by $200/month for 6 months. What do you do with the difference?",choice_liability:{label:"Treat yourself to small extras \u2014 streaming, delivery, outings",feedback:"The ease absorbs the surplus. In 6 months, you'll have nothing to show for those 6 months of 'savings'."},choice_asset:{label:"Automate a $200 transfer on the 1st of every month",feedback:"You never saw this money. It went directly to build your future. The best way to spend less is to never see the money arrive."}},{id:"cf_011",category:"cashflow",title:"The Insurance Negotiation",scenario:"You renegotiate your insurance and save $80/month. Where does the surplus go?",choice_liability:{label:"Mentally fold it into your 'leisure' budget",feedback:"The invisible expense. Unallocated money always ends up in unplanned spending."},choice_asset:{label:"Create an automatic $80 transfer to an asset this month",feedback:"Every saving is a disguised investment opportunity. You didn't cut your budget \u2014 you reallocated it smartly."}},{id:"cf_012",category:"cashflow",title:"The Friend's Repayment",scenario:"A friend pays back $300 they owed you. Reflex?",choice_liability:{label:"The perfect occasion to buy something you've wanted for a while",feedback:"Unexpected money always goes to unplanned expenses without a preset rule."},choice_asset:{label:"Apply your rule: all unexpected money goes straight into assets",feedback:"Discipline on small amounts forges habits for large ones. A clear rule eliminates temptation."}},{id:"cf_013",category:"cashflow",title:"The Sales Commission",scenario:"You land an exceptional $1,800 commission this month. Action plan?",choice_liability:{label:"Celebrate with outings and impulse purchases",feedback:"Celebration is natural. But if every success is immediately spent, success builds nothing."},choice_asset:{label:"Celebrate modestly and invest the rest for recurring income",feedback:"The commission is an event. The passive income it generates is permanent. Turn the exceptional into structural."}},{id:"cf_014",category:"cashflow",title:"The Coop Dividend",scenario:"You receive $120 in dividends from your buying coop. What do you do?",choice_liability:{label:"Use the dividends for this month's groceries",feedback:"Dividends spent on consumption never grow. The growth cycle is broken at the first withdrawal."},choice_asset:{label:"Automatically reinvest dividends to buy more shares",feedback:"Compound interest in action. Each reinvested dividend generates future dividends. This is the wealth engine."}},{id:"cf_015",category:"cashflow",title:"Leftover Leisure Budget",scenario:"You realize you only spent $150 of your $300 leisure budget this month. What do you do with the $150?",choice_liability:{label:"Roll it over to next month to 'catch up'",feedback:"The 'budget to spend' mentality turns savings into permission to spend more later."},choice_asset:{label:"Immediately transfer the unspent $150 to your investment",feedback:"The saving made is a potential asset. Acting immediately prevents the temptation to spend it 'later'."}},{id:"cf_016",category:"cashflow",title:"Lending to a Friend",scenario:"You have $500 available. A friend asks to borrow it 'to get through the month'. What do you do?",choice_liability:{label:"Lend without hesitation, they're family/a friend",feedback:"Generosity is a value. But an informal loan is often a disguised gift that creates relationship tension."},choice_asset:{label:"Assess your situation, be clear whether it's a loan or a gift, document it",feedback:"Clarity and honesty protect both the relationship and your finances. An acknowledged gift is healthier than a loan with no return."}},{id:"cf_017",category:"cashflow",title:"The Daily Coffee",scenario:"You spend $5/day on coffee. A colleague says that's $150/month 'wasted'. Are they right?",choice_liability:{label:"They're right, I'll cut coffee immediately to save",feedback:"Total deprivation is rarely sustainable. Financial management is optimization, not punishment."},choice_asset:{label:"Keep the coffee but audit my real unintentional expenses",feedback:"The daily coffee is often the only conscious expense. The real budget leaks are forgotten subscriptions and online impulse buys."}},{id:"cf_018",category:"cashflow",title:"Rising Fixed Costs",scenario:"Your fixed costs increase by $100/month. How do you react?",choice_liability:{label:"Accept the increase and randomly cut elsewhere",feedback:"Without a specific plan, 'random' cuts always fall on the wrong things \u2014 never on the real leaks."},choice_asset:{label:"Audit all expenses, identify the least useful $100 and eliminate it",feedback:"A cost increase is an audit opportunity. You optimize your budget rather than suffering it."}},{id:"cf_019",category:"cashflow",title:"The Profitable Side Project",scenario:"Your side project generates its first $300 net this month. What do you do?",choice_liability:{label:"Finally pay yourself \u2014 you deserve it",feedback:"Paying yourself from a young project slows its growth. Successful entrepreneurs pay themselves last."},choice_asset:{label:"Reinvest $250 into the project and keep $50 symbolically",feedback:"Early reinvestment accelerates exponential growth. $50 symbolic 'salary' maintains motivation without slowing the project."}},{id:"cf_020",category:"cashflow",title:"The Subscription Audit",scenario:"You realize you're paying for 4 streaming services ($55/month total). What do you do?",choice_liability:{label:"Keep all subscriptions, you use them all 'a bit'",feedback:"$55/month = $660/year for passively consumed content. A comparable asset could generate monthly income."},choice_asset:{label:"Keep 1-2 max, redirect the $30-40 saved to an investment",feedback:"Every useless subscription is rent paid for distraction. Optimizing fixed costs frees real investment capital."}},{id:"cf_021",category:"cashflow",title:"Early Repayment vs Investing",scenario:"You can pay off $500 of consumer credit this month. Or invest those $500. What do you do?",choice_liability:{label:"Invest the $500 \u2014 returns will cover the credit interest",feedback:"Classic math error: consumer credit rates almost always exceed investment returns. Repaying is the priority."},choice_asset:{label:"Pay off the credit \u2014 it's a guaranteed return at the credit rate",feedback:"Excellent reasoning. Paying off costly debt offers a guaranteed return equal to its rate. The safest investment right now."}},{id:"cf_022",category:"cashflow",title:"The Food Budget",scenario:"You can cut your food bill by $80/month by cooking more. Is it worth it?",choice_liability:{label:"No, the time it takes isn't worth it",feedback:"$80/month = $960/year. Evaluating time/money is fair, but the real barrier is usually habit, not time."},choice_asset:{label:"Yes, batch cook on weekends and reinvest the savings",feedback:"Double benefit: better nutrition + $80/month extra to invest. Batch cooking is an underrated lever."}},{id:"cf_023",category:"cashflow",title:"The Tech Gadget on Sale",scenario:"A gadget you've been eyeing is on sale at $400 (down from $600). Is now the time?",choice_liability:{label:"Yes, -33% is an opportunity not to miss",feedback:"A discount on something you hadn't planned to buy isn't a saving \u2014 it's a spending disguised as opportunity."},choice_asset:{label:"No, it wasn't in my plan. I keep the $400 for an asset",feedback:"Real financial discipline is resisting unplanned 'good deals'. Your allocation plan overrides promotions."}},{id:"cf_024",category:"cashflow",title:"The Severance Pay",scenario:"You leave a job and receive $4,000 in severance. Emergency plan?",choice_liability:{label:"Travel during the career transition",feedback:"Transitions are costly. Using severance to travel without incoming revenue creates unnecessary financial pressure."},choice_asset:{label:"Build a 3-month emergency fund and invest the rest",feedback:"Safety first. A solid emergency fund allows better professional decisions without the pressure of need."}},{id:"cf_025",category:"cashflow",title:"The Forgotten Balance",scenario:"You realize you had $600 forgotten in an old bank account. What do you do?",choice_liability:{label:"The perfect guilt-free treat",feedback:"'Found' money is treated differently than 'earned' money \u2014 it's a cognitive bias. In reality, it has the same value."},choice_asset:{label:"Treat it exactly like any other income and invest it",feedback:"Consistent treatment of all money flows is the mark of a real financial plan. Money doesn't change value based on its origin."}},{id:"cf_026",category:"cashflow",title:"The Savings Challenge",scenario:"A friend proposes a challenge: save $10 more per week for a year. Do you accept?",choice_liability:{label:"Too little to change anything, not worth the effort",feedback:"$10/week = $520/year. It's not the amount \u2014 it's the saver's habit and identity being built."},choice_asset:{label:"Yes, and I automate a weekly transfer of $10 today",feedback:"Automation turns intention into system. Systems beat willpower over time. $520 invested regularly creates real momentum."}},{id:"cf_027",category:"cashflow",title:"The Security Deposit Refund",scenario:"You get your $1,200 deposit back when moving. Immediate reflex?",choice_liability:{label:"Use it to furnish and decorate the new apartment",feedback:"Natural \u2014 but if the deposit funds the new place, you start from zero financially, same as before."},choice_asset:{label:"Invest the deposit and use a separate (smaller) budget for the move",feedback:"Separating flows prevents 'consuming' refunds. The deposit recovered is capital to preserve, not immediately respend."}},{id:"cf_028",category:"cashflow",title:"The Modest Inheritance",scenario:"You inherit $5,000 from a relative. How do you honor that inheritance?",choice_liability:{label:"Make a travel dream happen in their honor",feedback:"The trip can be meaningful and beautiful. But $5,000 entirely spent creates no financial legacy."},choice_asset:{label:"Invest most of it, make a small symbolic gesture with a portion",feedback:"You transform this inheritance into a lasting asset that keeps working. That may be the most respectful way to honor someone's work."}},{id:"cf_029",category:"cashflow",title:"The Vacation Budget",scenario:"You save for vacation ($150/month for 8 months). You have $1,200. How do you manage it?",choice_liability:{label:"Spend all $1,200 for a memorable vacation",feedback:"Annual affordable vacations are healthy. But if $1,200 is all your savings, the vacation cost you your entire safety margin."},choice_asset:{label:"$800 vacation budget, invest $400 of the saved amount",feedback:"Enjoy while building. The discipline of not spending everything even when it's 'planned for that' is advanced financial skill."}},{id:"cf_030",category:"cashflow",title:"The Abandoned Gym",scenario:"You pay $60/month for gym but barely go. What do you do?",choice_liability:{label:"Keep the membership, you'll go 'soon'",feedback:"$60/month \xd7 12 = $720/year for an intention. Unexecuted intentions are the most expensive expenses."},choice_asset:{label:"Cancel immediately, reinvest the $60/month, find a free alternative",feedback:"Cutting a useless expense and reinvesting it immediately is one of the most concrete financial optimization acts. Act now, not tomorrow."}},{id:"dt_001",category:"debt",title:"Maxed-Out Credit Card",scenario:"Your credit card is at 90% of its limit ($4,500 balance). Strategy?",choice_liability:{label:"Pay the minimum each month and keep using the card",feedback:"The minimum keeps the balance nearly permanent. Compound interest on consumer debt is the exact inverse of compound investment \u2014 just as powerful, but against you."},choice_asset:{label:"Stop all use, pay the maximum possible each month until paid off",feedback:"The debt avalanche: target the most expensive debt first. Every dollar above the minimum is a guaranteed return at the card's rate."}},{id:"dt_002",category:"debt",title:"The Student Loan",scenario:"You owe $25,000 in student loans at 5%. Method?",choice_liability:{label:"Pay exactly the minimum installment for the entire term",feedback:"At 5%, you're correctly paying the cost of your education. But if you can invest at higher returns, the minimum strategy can be rational \u2014 as long as you actually invest the difference."},choice_asset:{label:"Pay a surplus each month to repay faster and reduce total interest",feedback:"Every month of early repayment reduces the term and total interest. It's a guaranteed 5% return on each extra dollar repaid."}},{id:"dt_003",category:"debt",title:"Debt Consolidation",scenario:"You have 3 debts at different rates. A company offers to merge them into one lower monthly payment. Do you accept?",choice_liability:{label:"Yes! One lower payment, it's simpler",feedback:"Warning: a lower payment over a longer term may mean paying much more in total interest. Calculate the total cost before signing."},choice_asset:{label:"Analyze the overall rate, total duration and real cost before deciding",feedback:"Consolidation can be advantageous \u2014 or a marketing trap. The real question: what is the total cost of the consolidated debt vs current repayment?"}},{id:"dt_004",category:"debt",title:"Recurring Overdraft",scenario:"You systematically use your $500 authorized overdraft every month. Reaction?",choice_liability:{label:"The bank allows it, so it's fine",feedback:"Authorized overdrafts are among the most expensive credit in real rate terms. A recurring overdraft signals a worsening cash flow problem."},choice_asset:{label:"Treat the overdraft as an emergency and restructure my budget immediately",feedback:"Recurring overdraft is an alarm signal, not a management tool. It indicates spending exceeds income \u2014 a structural problem, not temporary."}},{id:"dt_005",category:"debt",title:"The 0% for 12 Months Offer",scenario:"A store offers 12-month interest-free payments on a $1,200 purchase. Do you take it?",choice_liability:{label:"Yes, 0% is free, might as well benefit",feedback:"The 0% is real \u2014 but only if you repay BEFORE the period ends. After that, the retroactive rate can be extremely high. And you still bought a liability."},choice_asset:{label:"No, if I can't pay cash, I probably can't afford it",feedback:"Kiyosaki's rule: if you have to borrow to buy a liability (consumption), you can't afford it. 0% makes the liability more accessible, not less of a liability."}},{id:"dt_006",category:"debt",title:"The Car Loan",scenario:"You need a car. The dealer offers a 60-month loan with a 'comfortable' monthly payment. Do you sign?",choice_liability:{label:"Yes, the payment fits my budget",feedback:"A car is a liability that depreciates the moment it leaves the lot. Financing a liability over 60 months means paying interest on something losing value every month."},choice_asset:{label:"Buy a reliable used car with savings or a short-term loan",feedback:"A used car paid in cash or over a short term reduces total cost and monthly pressure. Freeing fixed costs frees capital."}},{id:"dt_007",category:"debt",title:"Avalanche vs Snowball",scenario:"You have several debts. Which repayment method do you choose?",choice_liability:{label:"Pay off the smallest ones first to feel progress",feedback:"The snowball method (smallest first) is psychologically motivating but mathematically more costly. It pays more total interest."},choice_asset:{label:"Pay off the highest-rate debt first (avalanche method)",feedback:"The avalanche method is mathematically optimal \u2014 you pay the least total interest. If you maintain discipline, it's the most efficient strategy."}},{id:"dt_008",category:"debt",title:"The Mortgage Refinance",scenario:"Rates drop and you can refinance your mortgage to save $150/month. What do you do with the savings?",choice_liability:{label:"Raise your standard of living with this monthly surplus",feedback:"You optimized your debt but absorbed the savings into lifestyle. Optimization only creates wealth if it's reinvested."},choice_asset:{label:"Reinvest the $150/month saved into a productive asset",feedback:"Debt optimization + immediate reinvestment of savings: double wealth lever. You work less and build more in parallel."}},{id:"dt_009",category:"debt",title:"Borrowing to Invest",scenario:"You can borrow $10,000 at 4% to invest in an asset theoretically returning 8%. Do you do it?",choice_liability:{label:"Yes, the 4% spread is in my favor",feedback:"Leverage amplifies gains AND losses. An 8% return is a hypothesis, not a guarantee. If the asset falls, you still owe the 4% loan."},choice_asset:{label:"Wait until you have your own funds, or strictly limit leverage",feedback:"Investment leverage is an advanced tool to handle with caution. For a beginner, zero leverage is a strategy in itself \u2014 safety before optimization."}},{id:"dt_010",category:"debt",title:"Buy Now Pay Later",scenario:"An online service offers 'buy now, pay in 6 months'. Do you use this option?",choice_liability:{label:"Yes, it gives me time to gather the funds",feedback:"'Pay in 6 months' often means delaying a purchase you can't afford now. In 6 months, other expenses pile up \u2014 and the debt remains."},choice_asset:{label:"No, if I can't pay now, I don't buy now",feedback:"The discipline of immediate payment is a powerful filter against impulse buys. If you can't pay today, the purchase may not be a priority."}},{id:"dt_011",category:"debt",title:"Being a Guarantor",scenario:"A close friend asks you to co-sign their mortgage. Do you accept?",choice_liability:{label:"Yes, it's family/a friend, I trust them",feedback:"Being a guarantor means legally committing to repay the debt if the borrower defaults. Trust doesn't protect against life's accidents."},choice_asset:{label:"No, or only after understanding all the legal and financial implications",feedback:"Co-signing is a real financial commitment that can affect your future borrowing capacity. A decision deserving analysis, not just love."}},{id:"dt_012",category:"debt",title:"The Debt Buyout",scenario:"A company offers to buy out all your loans to reduce your payment by $300. Do you accept without hesitation?",choice_liability:{label:"Yes, $300 less per month is exactly what I need",feedback:"A lower payment over a longer term can cost thousands more in total. Calculate the total cost, not just the payment."},choice_asset:{label:"First calculate the total cost before and after the buyout",feedback:"The monthly payment is just one data point. Total cost (amount \xd7 duration \xd7 rate) is the only metric that matters for comparing loan offers."}},{id:"dt_013",category:"debt",title:"The Family Debt",scenario:"You owe money to a relative. They're not pressuring you. Do you prioritize repaying them?",choice_liability:{label:"No, they're not pressing, I'll pay other debts first",feedback:"Financially logical if the family debt is at 0%. But not repaying can create an invisible relational tension with a real human cost."},choice_asset:{label:"Yes, I repay with a clear plan to not let the debt pollute the relationship",feedback:"Relational and financial clarity are linked. A formalized repayment plan, even interest-free, respects the trust given and keeps the relationship healthy."}},{id:"dt_014",category:"debt",title:"The Revolving Credit Card",scenario:"Your bank sends you a revolving credit card with a $2,000 limit. Do you activate it?",choice_liability:{label:"Yes, it's useful for emergencies and unexpected expenses",feedback:"Revolving credit is one of the most expensive financial products. A real emergency fund in a savings account fills the same role with zero interest."},choice_asset:{label:"No, I build an emergency fund so I never need revolving credit",feedback:"The ultimate goal: never need emergency credit. A 3-6 month expense emergency fund is the best financial product that exists."}},{id:"dt_015",category:"debt",title:"Lending to a Friend at Interest",scenario:"You have $1,000 available. A friend proposes borrowing it at 5% interest. Do you prefer...",choice_liability:{label:"Lend the $1,000 at 5% to my friend",feedback:"5% guaranteed interest seems attractive. But if the friend doesn't repay, you lose both the money AND the friend. Personal credit risk is often underestimated."},choice_asset:{label:"Invest the $1,000 in a diversified asset to avoid mixing money and friendship",feedback:"Kiyosaki advises never mixing money and emotional relationships without very clear rules. An investment in an asset keeps the friendship pure."}},{id:"dt_016",category:"debt",title:"Mortgage vs Rent",scenario:"You're torn between buying (mortgage $1,400/month) and renting ($1,100/month). Decision criterion?",choice_liability:{label:"Buy \u2014 it costs more but it's an investment, always better",feedback:"Real estate is often presented as an asset, but Kiyosaki nuances: your primary residence generates no income. It can even be a liability if it costs more than it produces."},choice_asset:{label:"Compare total cost of ownership vs rent + investing the difference",feedback:"The real question: if I invest the $300 monthly difference over 20 years, what's the final value vs expected real estate appreciation? The answer isn't obvious."}},{id:"dt_017",category:"debt",title:"The Easy Consumer Credit",scenario:"A salesperson offers 'easy' credit at $50/month for a $600 purchase. Do you accept?",choice_liability:{label:"$50/month is nothing, it's affordable",feedback:"$50/month may seem negligible, but every consumer credit reduces your savings capacity and potentially your future borrowing capacity for assets."},choice_asset:{label:"Refuse and wait until you've saved the $600 to pay cash",feedback:"The discipline of waiting: if you save $100/month, you have the $600 in 6 months with no interest. Patience is the investor's first capital."}},{id:"dt_018",category:"debt",title:"Rate Renegotiation",scenario:"You can spend 2 hours renegotiating your mortgage to potentially save $5,000 over the term. Do you do it?",choice_liability:{label:"2 hours for hypothetical $5,000 is too much effort",feedback:"$5,000 / 2h = $2,500/hour of potential value. Renegotiation is often the financial action with the best ROI available to an individual."},choice_asset:{label:"Yes, immediately. It's probably the best hour of my financial life",feedback:"Mortgage renegotiation is the most accessible and often most ignored financial lever. One hour can be worth thousands \u2014 and it's never too late."}},{id:"dt_019",category:"debt",title:"Month-End Card Balance",scenario:"You can't fully pay your credit card balance this month. How much do you pay?",choice_liability:{label:"The required minimum, I'll make up for it next month",feedback:"Paying the minimum activates compound interest against you. 'Next month' almost never comes for small balances \u2014 which silently grow."},choice_asset:{label:"The maximum possible, and I block the card to not make things worse",feedback:"Pay the maximum possible + block usage = double action. Stop the bleeding AND accelerate recovery. The minimum is an illusion of control."}},{id:"dt_020",category:"debt",title:"Training Credit",scenario:"A course costs $3,000. You can pay cash or use credit at 6%. What do you do?",choice_liability:{label:"Use credit to keep my cash available for something else",feedback:"If 'something else' means spending it, the 6% credit is the wrong decision. If 'something else' means investing at more than 6%, the math may favor credit."},choice_asset:{label:"Pay cash if the training has a clear and measurable ROI on my income",feedback:"Training is an asset if it measurably increases your earning capacity. Cash or credit depends on expected ROI and your alternative interest rate."}},{id:"dt_021",category:"debt",title:"Debt vs Emergency Savings",scenario:"You have $2,000 saved and $1,500 in debt at 18%. Do you use the savings to repay?",choice_liability:{label:"No, keep the savings for emergencies, it's safety",feedback:"Keeping $2,000 at ~1% while paying 18% on $1,500 costs you ~$250/year net. The 'safety' has a real price."},choice_asset:{label:"Yes, repay $1,500 and keep $500 as a minimal emergency fund",feedback:"Repaying 18% debt with 1% savings is a net gain of 17%. Keep a minimum emergency buffer ($500), repay the rest."}},{id:"dt_022",category:"debt",title:"Credit Insurance",scenario:"The bank offers credit insurance at $40/month to cover your repayments in case of accident. Do you take it?",choice_liability:{label:"Yes, it's reassuring and the bank recommends it",feedback:"Bank-sold credit insurance is often overpriced and poorly suited. Compare with independent insurance or a self-built emergency fund."},choice_asset:{label:"Evaluate the real need and compare with independent alternatives",feedback:"Insurance can be useful \u2014 but the price and conditions vary enormously. The often cheaper alternative: an emergency fund equivalent to 3-6 months of charges."}},{id:"dt_023",category:"debt",title:"Borrowed to Invest",scenario:"A friend tells you he borrowed to buy speculative assets. He's making a lot. Do you do the same?",choice_liability:{label:"If he can do it, so can I \u2014 the gains look real",feedback:"Confirmation bias: you see the gains, not the losses. People don't tell you about leveraged investments that went wrong. Survivorship bias is dangerous."},choice_asset:{label:"Congratulate the friend, but analyze the real risk of leverage before copying",feedback:"Leverage amplifies both directions. Your friend may have been right by luck as much as by strategy. Analyze your own risk profile first."}},{id:"dt_024",category:"debt",title:"Extra Mortgage Payment vs Investing",scenario:"You can pay $500/month extra on your mortgage (at 3%) OR invest that $500. What do you do?",choice_liability:{label:"Pay the mortgage off faster to be 'debt-free' sooner",feedback:"At 3% mortgage, early repayment offers a guaranteed 3% return. Excellent in low-yield environments, less optimal if you can invest at 7%+."},choice_asset:{label:"Invest the $500 if expected returns significantly exceed 3%",feedback:"Mathematically, if you can invest long-term with an expected return of 6-8% and your mortgage is at 3%, investment wins. But it's risky \u2014 the 3% is guaranteed, the 7% isn't."}},{id:"dt_025",category:"debt",title:"Debt Settlement",scenario:"A company offers to buy your debt for 50 cents on the dollar. Do you accept?",choice_liability:{label:"Yes! Paying 50% of my debt is the best deal possible",feedback:"A 50% settlement may impact your credit history and relationship with creditors. Also check the possible tax implications."},choice_asset:{label:"Analyze legal, tax and credit score implications before deciding",feedback:"Debt settlement can be a viable but complex solution. Understanding all consequences \u2014 particularly on future borrowing capacity \u2014 is essential."}},{id:"dt_026",category:"debt",title:"The Seller's Free Credit",scenario:"A real estate seller offers 0% financing for 2 years. Too good to be true?",choice_liability:{label:"0% is great, I sign without analyzing the details",feedback:"0% seller credit often compensates with a higher sale price. The financing cost is embedded in the price, not the rate. Negotiate the price first."},choice_asset:{label:"Analyze whether the price includes the financing cost and negotiate both variables",feedback:"A seller offering financing generally embeds that cost in the price. The real question: what would the price be with a cash payment?"}},{id:"dt_027",category:"debt",title:"Unable to Pay",scenario:"You can no longer meet your debt obligations. First action?",choice_liability:{label:"Wait and hope the situation resolves itself",feedback:"Waiting almost always worsens the situation. Interest accumulates, penalties add up, negotiation options shrink."},choice_asset:{label:"Proactively contact creditors and seek a financial advisor immediately",feedback:"Proactive action in a financial crisis is counterintuitive but essential. Creditors generally prefer to negotiate rather than pursue."}},{id:"dt_028",category:"debt",title:"Early Student Debt",scenario:"You can choose a cheaper university with financial aid or a top school with $60,000 in loans. Decision criterion?",choice_liability:{label:"Top school \u2014 the network and prestige justify the debt",feedback:"Prestige has real value in some fields. But $60,000 in student debt represents years of repayment that delay wealth building."},choice_asset:{label:"Calculate the real ROI of each option: salary differential vs cost of debt",feedback:"Education is an investment \u2014 like any investment, calculate the return. The expected salary differential should cover the extra debt cost in a reasonable timeframe."}},{id:"dt_029",category:"debt",title:"The Micro Business Loan",scenario:"You can borrow $5,000 to launch your side business. The project is solid but uncertain. Do you borrow?",choice_liability:{label:"Yes, no risk no reward, entrepreneurship requires investment",feedback:"Calculated risk is healthy. But borrowing for an uncertain project means if it fails, you still owe the repayment. The risk is asymmetric."},choice_asset:{label:"Bootstrap until you validate the concept, then fund growth with revenues",feedback:"Bootstrapping forces business model validation before committing capital. A project that can grow slowly with its own revenues is more robust than a credit-funded one."}},{id:"dt_030",category:"debt",title:"Good Debt vs Bad Debt",scenario:"Two borrowing opportunities: $10,000 for a luxury car OR $10,000 for a rental property generating income. What's the difference?",choice_liability:{label:"Both are debts, it's the same either way",feedback:"No, Kiyosaki makes a fundamental distinction: good debt finances an asset that generates income greater than the cost of the debt. Bad debt finances a liability."},choice_asset:{label:"Rental debt is potentially 'good' if rent covers interest and generates surplus",feedback:"This is Kiyosaki's key distinction between good and bad debt. Borrowing to acquire a productive asset whose return exceeds the interest rate is a legitimate lever."}},{id:"inv_001",category:"investment",title:"The First $1,000",scenario:"You've saved $1,000 to invest for the first time. Where do you go?",choice_liability:{label:"Buy a stock from a company you hear about everywhere",feedback:"Following media hype is the most effective way to overpay at the top and panic-sell at the bottom. Popularity often precedes the bubble."},choice_asset:{label:"Invest in a diversified index fund to start without selection bias",feedback:"For a first investment, maximum diversification at low cost is statistically the most solid strategy. It eliminates selection risk and emotional bias."}},{id:"inv_002",category:"investment",title:"The Market Crash",scenario:"Markets fall 20%. Your portfolio loses $2,000 in 48 hours. What do you do?",choice_liability:{label:"Sell before it gets worse \u2014 better to protect what's left",feedback:"Selling during a crash turns a paper loss into a real loss. Historically, investors who sell during crises almost always miss the recovery."},choice_asset:{label:"Do nothing \u2014 or buy more if you have available cash",feedback:"Crises are sales for long-term investors. Buffett says to be greedy when others are fearful. Staying the course (and ideally buying more) is counterintuitive but historically winning."}},{id:"inv_003",category:"investment",title:"The Hot Tip",scenario:"A colleague says they have a 'tip' on a stock that's about to explode. Do you invest?",choice_liability:{label:"Yes, if they're sure, it's an opportunity not to miss",feedback:"Investing on 'tips' exposes you to two risks: the tip is wrong (frequent) or it constitutes insider trading (real legal risk). Trust is not an investment strategy."},choice_asset:{label:"No, analyze the asset yourself or pass \u2014 never on a rumor",feedback:"A good investment must withstand personal analysis. If you don't understand why the asset should rise yourself, you won't understand when to sell either."}},{id:"inv_004",category:"investment",title:"Diversification",scenario:"You've put everything in 2 stocks that have performed well for a year. Strategy?",choice_liability:{label:"Keep the concentration, it's working and diversifying would dilute gains",feedback:"Concentration amplifies gains AND losses. 2 stocks represent extreme portfolio risk. Yesterday's winners aren't guaranteed to be tomorrow's."},choice_asset:{label:"Progressively diversify toward a portfolio of 15+ uncorrelated assets",feedback:"Diversification reduces risk without necessarily reducing expected return. Going from 2 to 20 assets significantly reduces volatility with no major additional cost."}},{id:"inv_005",category:"investment",title:"Real Estate vs Stock Market",scenario:"You have $30,000 saved. Rental real estate or stock market? Main criterion?",choice_liability:{label:"Real estate, it's tangible and 'you never lose in real estate'",feedback:"Real estate can lose value. And 'tangible' isn't a strategy \u2014 it's an emotional bias. Both asset classes have different returns and risks depending on markets."},choice_asset:{label:"Analyze net return, liquidity and required management level for each option",feedback:"Neither is universally superior. The net return of rental real estate (rent - charges - taxes - time) is often lower than it appears."}},{id:"inv_006",category:"investment",title:"Market Timing",scenario:"An analyst predicts markets will fall in 3 months. Do you wait to invest?",choice_liability:{label:"Wait for the dip to invest at a better price",feedback:"Nobody can reliably predict short-term markets \u2014 not analysts, not algorithms. Waiting often means missing gains that offset the anticipated drops."},choice_asset:{label:"Invest now with your regular plan \u2014 time in the market beats timing the market",feedback:"'Time in the market beats timing the market' is one of the most robust conclusions in behavioral finance. Every month out of the market is a lost opportunity."}},{id:"inv_007",category:"investment",title:"Management Fees",scenario:"You're choosing between a fund with 0.2% annual fees and one with 2% fees but 'actively managed'. Which to choose?",choice_liability:{label:"The 2% is justified if the manager is expert",feedback:"Statistically, the majority of actively managed funds underperform their benchmark index over 10 years, especially after fees. A 1.8% fee difference is enormous over 20 years."},choice_asset:{label:"The 0.2% fund \u2014 studies show low fees are the best predictor of net performance",feedback:"1.8% extra annual fees on $10,000 over 20 years represents a difference of thousands of dollars. Low fees are one of the few advantages an individual investor can control."}},{id:"inv_008",category:"investment",title:"Socially Responsible Investing",scenario:"You can choose between an ESG fund (less diversified, slightly higher fees) or a broad index fund. What do you prioritize?",choice_liability:{label:"ESG without hesitation \u2014 values before returns",feedback:"Values matter. But 'ESG' doesn't guarantee better returns or real impact. Check the ESG methodology and actual fees before choosing."},choice_asset:{label:"Analyze real impact, fees and historical return before deciding",feedback:"Ethical investing is legitimate \u2014 but deserves as much rigor as any other investment. Some ESG funds are excellent, others are 'greenwashing' with high fees."}},{id:"inv_009",category:"investment",title:"DCA vs Lump Sum",scenario:"You have $5,000 to invest. Put it all in at once or spread it over 12 months?",choice_liability:{label:"Spread over 12 months to 'reduce bad timing risk'",feedback:"Mathematically, lump sum (all at once) outperforms DCA (spreading) 2/3 of the time historically, as markets rise more than they fall. But DCA is psychologically better."},choice_asset:{label:"All at once if markets are 'normal', DCA if very high or very volatile",feedback:"Both have their place. Lump sum wins statistically but DCA reduces emotional stress. If emotion might make you sell at the wrong time, DCA may be better in practice."}},{id:"inv_010",category:"investment",title:"Cryptocurrencies",scenario:"A friend multiplied their crypto investment by 5. Do you want in?",choice_liability:{label:"Invest heavily \u2014 the potential gains are enormous",feedback:"Assets that can multiply by 5 can also divide by 5. Crypto is a high-volatility asset class suited for a fraction of a portfolio (5-10% maximum for most)."},choice_asset:{label:"If interested, allocate a limited fraction you're prepared to lose entirely",feedback:"The responsible crypto rule: only invest what you're prepared to lose completely. The volatility is real and cycles can be very long."}},{id:"inv_011",category:"investment",title:"Bonds vs Stocks",scenario:"You're approaching retirement. Do you keep 100% in stocks or rebalance?",choice_liability:{label:"Keep 100% stocks to maximize gains until the end",feedback:"Sequence of returns risk is crucial near retirement: a sharp drop at the wrong moment can dramatically reduce portfolio longevity."},choice_asset:{label:"Progressively rebalance toward less volatile assets as you approach",feedback:"The classic rule: (100 - age)% in stocks. Near retirement, reducing volatility is as important as maximizing returns. Timing risk becomes critical."}},{id:"inv_012",category:"investment",title:"Invest in What You Know",scenario:"You work in tech. Do you mainly invest in tech companies?",choice_liability:{label:"Yes, I invest where I have a real informational advantage",feedback:"Peter Lynch recommends 'investing in what you know' \u2014 but familiarity bias can also lead to over-concentrating in one sector and under-diversifying."},choice_asset:{label:"Use sector knowledge for selection, but maintain global diversification",feedback:"Sector knowledge is a real edge \u2014 as long as it serves selection, not over-concentration. Your job already depends on tech: your portfolio shouldn't be 100% correlated with it."}},{id:"inv_013",category:"investment",title:"Annual Rebalancing",scenario:"After a year of gains, stocks represent 80% of your portfolio instead of 60%. Do you rebalance?",choice_liability:{label:"No, stocks are performing well, let them grow",feedback:"Not rebalancing lets the risk profile drift to more volatility than intended. An 80/20 portfolio is not the same risk as a 60/40."},choice_asset:{label:"Yes, sell some stocks to return to the target allocation",feedback:"Rebalancing systematically enforces 'sell high, buy low'. It's one of the few mechanical actions that produces better risk-adjusted performance."}},{id:"inv_014",category:"investment",title:"Rental Real Estate",scenario:"You can buy an apartment for $150,000 and rent it for $700/month. Is it a good deal?",choice_liability:{label:"$700/month is guaranteed income, it's excellent",feedback:"$700/month gross \u2260 $700 net income. Condo fees, property taxes, vacancy, repairs, management: net return may drop to 2-3%. Calculate NET return."},choice_asset:{label:"Calculate the net return (rent - all charges - taxes) and compare alternatives",feedback:"True rental yield: (annual rent - charges - taxes - vacancy - management) / purchase price. A property at 3% net isn't necessarily better than a low-cost index fund."}},{id:"inv_015",category:"investment",title:"Investing in Your Own Training",scenario:"An advanced course costs $2,500 and could potentially increase your income by $300/month. Do the math?",choice_liability:{label:"Too expensive for uncertain results",feedback:"$2,500 / $300 = 8.3 months payback. If the training really delivers $300/month extra, it's one of the best returns on investment available."},choice_asset:{label:"Yes, a ~8-month ROI is excellent \u2014 but verify the training's proven results",feedback:"Investment in yourself is often the most profitable. But 'potentially' isn't a guarantee. Seek verifiable testimonials and concrete results before investing."}},{id:"inv_016",category:"investment",title:"Concentrated vs Diversified Portfolio",scenario:"Invest in 5 assets you understand perfectly OR in 50 assets via a fund. What do you prefer?",choice_liability:{label:"5 assets I understand well, concentration maximizes gains",feedback:"Concentration can maximize gains \u2014 and losses. Warren Buffett can do it because he spends 12 hours/day on analysis. For most investors, concentration is excessive risk."},choice_asset:{label:"50 diversified assets to reduce the idiosyncratic risk of each",feedback:"Diversification is the only free lunch in finance. 50 uncorrelated assets dramatically reduce volatility without necessarily reducing expected long-term return."}},{id:"inv_017",category:"investment",title:"Selling Before the Crash",scenario:"Experts predict a recession. Do you sell everything to wait it out?",choice_liability:{label:"Yes, better to protect gains while waiting for certainty",feedback:"Certainty doesn't exist in finance. Selling everything creates two problems: when to re-enter? And if the crash doesn't happen, you missed the gain while waiting."},choice_asset:{label:"Stay invested per my target allocation and maybe increase savings to buy the dip",feedback:"Being ready to buy during a dip without panic-selling is the mature investor's strategy. The recession, if it comes, is an opportunity for those with liquidity."}},{id:"inv_018",category:"investment",title:"Start-up Investment",scenario:"A friend is launching a start-up and looking for investors. He offers you equity for $5,000. Do you join?",choice_liability:{label:"Yes, start-ups can return 10x if you get in early",feedback:"The statistics: 90% of start-ups fail. A $5,000 investment in a friend's start-up has a high probability of going to zero AND creating relationship tension."},choice_asset:{label:"Evaluate like any investment: business plan, traction, team, and risk of total loss",feedback:"A start-up investment deserves as much rigor as a stock market investment. Only invest if you accept the likely total loss and truly understand the business model."}},{id:"inv_019",category:"investment",title:"Liquidity",scenario:"All your assets are invested long-term and a $1,500 emergency arises. What do you do?",choice_liability:{label:"Quickly sell part of my investments",feedback:"Selling long-term assets for a short-term emergency is exactly what the emergency fund is supposed to prevent. Forced selling at the wrong time crystallizes losses."},choice_asset:{label:"Use my liquid emergency fund \u2014 that's exactly what it's for",feedback:"The emergency fund is the buffer that allows you to never touch long-term investments. Its existence protects productive assets from life's surprises."}},{id:"inv_020",category:"investment",title:"ESG in Portfolio",scenario:"You discover one of your portfolio companies has contested environmental behavior. What do you do?",choice_liability:{label:"Do nothing \u2014 it's their problem, not mine",feedback:"As a shareholder, you are a partial owner of the company and its practices. Your investment indirectly finances them."},choice_asset:{label:"Evaluate whether to sell or hold based on both your values AND financial prospects",feedback:"Both criteria can align: contested practices often create regulatory and reputational risks long-term. Ethics and performance aren't always opposed."}},{id:"inv_021",category:"investment",title:"Dividends vs Capital Gains",scenario:"You prefer dividend stocks (4%/year) or growth stocks (0% dividend but 12% expected growth)?",choice_liability:{label:"Dividends \u2014 it's real regular income",feedback:"Dividends are attractive but fiscally less efficient in some countries. A stock growing 12% creates as much value as 4% dividend + 8% price growth."},choice_asset:{label:"Analyze total return (dividend + appreciation) and tax treatment in your country",feedback:"Total return (dividend + growth) is the true metric. Dividend vs growth preference also depends on your tax bracket and current income needs."}},{id:"inv_022",category:"investment",title:"Investing in Gold",scenario:"During economic uncertainty, an advisor recommends 'putting everything in gold'. Do you agree?",choice_liability:{label:"Yes, gold is a universal safe haven",feedback:"Gold is a store of value, not a productive asset. It generates neither dividend, rent, nor interest. Over the very long term, its real return is close to zero after inflation."},choice_asset:{label:"Allocate a limited fraction to gold as diversification, not as a main strategy",feedback:"Gold has its place in a diversified portfolio as protection against inflation and inverse correlation in crises. But 'everything' in gold replaces one risk with another."}},{id:"inv_023",category:"investment",title:"ETFs vs Active Funds",scenario:"You must choose between an ETF at 0.15%/year and an active fund claiming to beat the market at 1.5%/year. Criterion?",choice_liability:{label:"The active fund if its manager has a good reputation",feedback:"Past reputation doesn't predict future performance. 90% of active managers underperform their index over 15 years after fees. A 1.35% fee gap is a major handicap."},choice_asset:{label:"The ETF in the vast majority of cases \u2014 data shows the superiority of indices long-term",feedback:"Academic studies are unanimous: over 15+ years, more than 90% of active funds underperform their benchmark index after fees. The low-cost ETF wins statistically."}},{id:"inv_024",category:"investment",title:"Asset Allocation at Career Start",scenario:"You're 25 and starting to invest. What allocation to choose?",choice_liability:{label:"50% stocks, 50% bonds for 'balanced risk'",feedback:"At 25, you have a 40-year investment horizon. Bonds over-diversify to the downside. At this age, cycle resilience favors a more aggressive allocation in productive assets."},choice_asset:{label:"Majority allocation in productive assets \u2014 the long horizon compensates for volatility",feedback:"At 25, time is your best asset. Short-term volatility is absorbed by the decades ahead. An allocation suited to a long horizon maximizes growth potential."}},{id:"inv_025",category:"investment",title:"Financial News",scenario:"Financial news announces an imminent crisis. Do you check your investments?",choice_liability:{label:"Yes, monitor daily to react fast if things go wrong",feedback:"Studies show the more an investor checks their portfolio, the more they trade (often at the wrong time). Daily monitoring increases anxiety without improving results."},choice_asset:{label:"No, my strategy is defined. I reassess at most quarterly",feedback:"The passionate investor who monitors daily generally underperforms the one who defines their strategy and executes without watching the news. Less noise = better decisions."}},{id:"inv_026",category:"investment",title:"Investing Through a Dedicated Structure",scenario:"You can invest through a dedicated investment company or holding to optimize your situation. Is it worth the cost of the structure?",choice_liability:{label:"No, too complex and costly to manage",feedback:"For significant amounts, a dedicated structure can represent advantages that greatly exceed management costs. Evaluate based on amounts involved and local regulations."},choice_asset:{label:"Analyze the break-even between structure costs and real advantages based on amounts and your jurisdiction",feedback:"A dedicated investment structure becomes relevant above a certain wealth level. Below that, creation and management costs exceed the benefits \u2014 and rules vary greatly by country."}},{id:"inv_027",category:"investment",title:"Investing in Your Own Business",scenario:"You can invest $10,000 in the stock market or in your own business. What do you choose?",choice_liability:{label:"Stock market \u2014 it's safer and more liquid",feedback:"The stock market is liquid but you have no control over companies. Your own business offers total control and potentially the best returns \u2014 but also the highest risk."},choice_asset:{label:"Depends on business stage: early stage goes into the business, mature business \u2192 diversify",feedback:"The best return opportunities are often in your own early-stage business. As the business matures, progressively diversifying reduces concentration risk."}},{id:"inv_028",category:"investment",title:"The Inherited Portfolio",scenario:"You inherit a portfolio invested in securities you don't understand. Do you keep or restructure?",choice_liability:{label:"Keep without changing \u2014 it worked for the deceased",feedback:"A portfolio suited to someone else (different age, goals, tax situation) isn't necessarily suited to yours. Understanding what you own is a minimum."},choice_asset:{label:"Understand each position, evaluate if it matches my objectives, restructure if necessary",feedback:"Inheriting a portfolio deserves as much analysis as building your own. Aligning inherited investments with your own goals and time horizon is a fiduciary responsibility to yourself."}},{id:"inv_029",category:"investment",title:"The Climate Investment",scenario:"You believe the energy transition will create the decade's greatest opportunities. How do you invest?",choice_liability:{label:"All-in on green companies and renewables",feedback:"Thematic conviction can be right but timing and selection remain crucial. A sector can have a bright future but already excessive valuations \u2014 which reduces future returns."},choice_asset:{label:"Allocate a portfolio fraction to this theme while maintaining a diversified base",feedback:"A thematic conviction justifies overweighting, not total concentration. Keeping a diversified base protects against the possibility that the theme is right but the timing is wrong."}},{id:"inv_030",category:"investment",title:"Direct Real Estate vs REITs",scenario:"You want real estate exposure. Direct property or listed real estate fund?",choice_liability:{label:"Direct real estate \u2014 it's tangible and you control everything",feedback:"Direct real estate offers total control but also active management, low liquidity and geographic concentration. It's not a passive asset."},choice_asset:{label:"Evaluate both by liquidity, diversification, net return and management time",feedback:"Listed real estate funds offer diversification, liquidity and zero management. Direct property offers leverage, control and potential tax advantages. Both have their place by profile."}},{id:"mn_001",category:"mindset",title:"The E vs B Reflex",scenario:"You have a business idea but your current job is stable and well paid. What do you do?",choice_liability:{label:"Keep the stable job \u2014 safety first",feedback:"The Employee (E) mentality values the paycheck's security. Stability has real value \u2014 but it can also become a ceiling preventing real financial freedom."},choice_asset:{label:"Test the idea in parallel evenings/weekends before making the leap",feedback:"The B (Business Owner) quadrant often starts outside work hours. Testing at low risk before jumping is the strategy of most successful entrepreneurs."}},{id:"mn_002",category:"mindset",title:"The Definition of Risk",scenario:"Your circle says 'investing is risky'. How do you react?",choice_liability:{label:"They're right \u2014 better to keep money in a safe savings account",feedback:"Not investing also has a risk: the inflation risk that erodes purchasing power, and the risk of not reaching long-term financial goals."},choice_asset:{label:"Not investing is also a risk \u2014 losing purchasing power and decades of growth",feedback:"Kiyosaki says financial education reduces risk. What's risky for someone without training isn't risky for someone who understands what they're doing."}},{id:"mn_003",category:"mindset",title:"Money and Emotions",scenario:"You make a bad financial decision and lose $500. How do you handle it?",choice_liability:{label:"Punish yourself mentally and avoid taking risks for months",feedback:"Loss aversion is the most documented behavioral bias. An investor who self-punishes after a mistake makes worse future decisions through over-caution."},choice_asset:{label:"Objectively analyze the mistake, draw a lesson from it and move on",feedback:"The best investors make mistakes \u2014 and draw lessons without drowning in them emotionally. Post-mistake objectivity is a skill that's cultivated."}},{id:"mn_004",category:"mindset",title:"Visible Wealth",scenario:"Your neighbor buys a luxury car. What's your inner reaction?",choice_liability:{label:"They've made it \u2014 they can afford it, I should work harder",feedback:"The wealthy neighbor syndrome. Studies on millionaires show real wealth is often invisible: modest cars, moderate homes, wealth in non-displayed assets."},choice_asset:{label:"The car proves nothing \u2014 real wealth is in invisible assets",feedback:"'The Millionaire Next Door' documents that most truly rich people don't display it. A luxury car can signal real wealth or well-hidden debt."}},{id:"mn_005",category:"mindset",title:"Financial Education",scenario:"You have 2 free hours this weekend. What do you do?",choice_liability:{label:"Watch a series or rest \u2014 you worked hard this week",feedback:"Rest is legitimate and necessary. But 2 hours of financial educational content per week can transform your relationship with money over 1 year."},choice_asset:{label:"Read a book or listen to a podcast on finance and investing",feedback:"Kiyosaki says the difference between the rich and others is what they do with their free time. Financial education is an investment in yourself that pays for life."}},{id:"mn_006",category:"mindset",title:"Advice from the Wealthy",scenario:"You have the opportunity to have lunch with a very wealthy person. What question do you ask?",choice_liability:{label:"How did you get started? What was your big break?",feedback:"The 'lucky break' question looks for the shortcut. But most lasting fortunes result from methodical construction, not a single dice roll."},choice_asset:{label:"What mistake would you spare me? What habit most changed your trajectory?",feedback:"Questions about mistakes and habits give actionable information. Those who succeed long-term generally have systems and habits more than lucky breaks."}},{id:"mn_007",category:"mindset",title:"The Fear of Starting",scenario:"You want to invest but think 'not yet, I need to know more first'. Since 2 years. What do you do?",choice_liability:{label:"Keep learning \u2014 better to be sure before starting",feedback:"Perfect waiting is the enemy of imperfect reality. 2 years of non-investing has a real opportunity cost. Perfect knowledge doesn't exist \u2014 action with uncertainty does."},choice_asset:{label:"Start small with what you know, and learn by doing",feedback:"Real financial skills develop in practice, not just theory. A small real investment teaches more than a hundred hours of reading."}},{id:"mn_008",category:"mindset",title:"Criticism from Those Around You",scenario:"You decide to invest and your family says 'you'll lose everything'. How do you react?",choice_liability:{label:"Give up or keep your plans secret to avoid conflict",feedback:"Hiding your financial projects from those around you or giving in to social pressure both allow your environment to control your financial trajectory."},choice_asset:{label:"Listen to the concern, analyze it rationally, then decide based on your own research",feedback:"Family criticism often comes from fear, not expertise. Listen without automatically obeying. Analyze the substance of the argument, not the emotional form."}},{id:"mn_009",category:"mindset",title:"Time vs Money",scenario:"You can accept an extra assignment for $500 more this month. But it would take 20 hours of your free time. Do you accept?",choice_liability:{label:"Yes, $500 is $500 \u2014 you don't refuse money",feedback:"$500 / 20h = $25/h. The real question: how much is your free time worth? And could those 20 hours be used to build something that pays more long-term?"},choice_asset:{label:"Depends on my finances, and what I'd do with that time otherwise",feedback:"Time is the non-renewable asset. At $25/h, the assignment may be worth it \u2014 or not. The decision should factor in what 20 hours of free time could create alternatively."}},{id:"mn_010",category:"mindset",title:"The Shame of Talking About Money",scenario:"You never talk about money with friends for fear of seeming 'obsessed'. Is that healthy?",choice_liability:{label:"Yes, money is a private subject you shouldn't bring up",feedback:"The money taboo is culturally constructed \u2014 and very costly. It prevents sharing good practices, discovering common mistakes and helping each other financially."},choice_asset:{label:"No, talking about money with kindness is a source of collective learning",feedback:"People who openly discuss money with their circle learn faster and make fewer mistakes. The financial taboo protects those who sell expensive and poorly-suited products."}},{id:"mn_011",category:"mindset",title:"Financial Identity",scenario:"You describe yourself as 'someone who isn't good with money'. Is that true?",choice_liability:{label:"Yes, some people just have that gift and others don't",feedback:"Negative financial identity is a self-fulfilling prophecy. Believing you 'aren't good with money' prevents learning and changing your behaviors."},choice_asset:{label:"No, it's a learnable skill \u2014 not an innate character trait",feedback:"Financial literacy is a skill, not an innate talent. Kiyosaki was poor before he was rich. Good financial habits can be learned at any age."}},{id:"mn_012",category:"mindset",title:"Jealousy of Wealth",scenario:"You see a peer's financial success and feel jealousy. How do you transform it?",choice_liability:{label:"Avoid seeing them \u2014 their success makes you uncomfortable",feedback:"Avoided jealousy stagnates. It doesn't transform into motivation without conscious reflection on what it reveals about your own desires and blocks."},choice_asset:{label:"Use jealousy as a signal to identify what you truly want and how to get it",feedback:"Jealousy is an emotional compass. It points toward something you value but don't have. Used consciously, it becomes motivation and clarification of priorities."}},{id:"mn_013",category:"mindset",title:"Generosity and Wealth",scenario:"You think being rich means being greedy. Would Kiyosaki agree?",choice_liability:{label:"Yes, the rich keep everything for themselves, that's why they get rich",feedback:"The wealth-greed correlation is a myth. Studies on millionaires show generosity is more prevalent among the wealthy than among those seeking to appear wealthy."},choice_asset:{label:"No, generosity and wealth are compatible \u2014 real wealth comes from surplus, not deprivation",feedback:"Kiyosaki emphasizes that real wealth creates abundance to share. The generosity of a wealthy person with productive assets costs less proportionally than generosity forced by guilt."}},{id:"mn_014",category:"mindset",title:"Daily Financial Discipline",scenario:"You have a monthly budget that you often don't stick to. Why?",choice_liability:{label:"Because life is unpredictable and budgets are too rigid",feedback:"A budget can be flexible without being ignored. The unpredictable can be budgeted (emergency fund, miscellaneous budget). The real problem is often lack of tracking, not rigidity."},choice_asset:{label:"Because the budget isn't automated and willpower alone isn't enough",feedback:"Willpower is a muscle that exhausts. Automatic systems (automatic transfers, categorized budgets through apps) replace willpower with reliable mechanisms."}},{id:"mn_015",category:"mindset",title:"Money and Happiness",scenario:"A friend says: 'Money doesn't buy happiness'. What do you say?",choice_liability:{label:"They're right, happiness comes from relationships and experiences, not money",feedback:"Partially true. But below a certain threshold of financial security, lack of money causes real chronic stress that directly affects happiness."},choice_asset:{label:"Money doesn't buy happiness, but its absence can create a lot of suffering",feedback:"Psychology research shows money increases happiness up to a security threshold. Below that threshold, financial problems are the number one source of chronic stress."}},{id:"mn_016",category:"mindset",title:"Financial Freedom as a Goal",scenario:"Your 10-year goal: financial freedom or career promotion?",choice_liability:{label:"Promotion \u2014 it's concrete, measurable and socially valued",feedback:"Promotion increases salary \u2014 an active income. Financial freedom aims for passive income. Both can coexist, but promotion alone doesn't automatically lead to freedom."},choice_asset:{label:"The two aren't opposed \u2014 use the promotion to accelerate financial freedom",feedback:"Promotion can fund the investment that leads to freedom. The mistake is spending the raise rather than investing it. Promotion is an accelerator, not a destination."}},{id:"mn_017",category:"mindset",title:"Patience and Wealth",scenario:"You want quick financial results. Is it realistic?",choice_liability:{label:"Yes, with the right investments you can get rich fast",feedback:"The quest for quick wealth is the source of most financial scams. Exceptional short-term returns imply exceptional risk \u2014 often poorly understood."},choice_asset:{label:"Real wealth is slow and predictable \u2014 shortcuts almost always cost more",feedback:"Lasting wealth is built over decades, not months. The world's wealthiest people have massively benefited from decades of compound interest, not strokes of genius."}},{id:"mn_018",category:"mindset",title:"The Financial Mistake",scenario:"You realize you overpaid for an asset. Do you sell at a loss or hold?",choice_liability:{label:"Hold to not 'realize the loss'",feedback:"This is the loss aversion bias. A paper loss is a real economic loss regardless of the accounting column. Holding a bad asset hoping for a return is irrational if the analysis changes."},choice_asset:{label:"Objectively analyze if the prospects justify holding \u2014 independent of the price paid",feedback:"The analysis of 'what would I do if I didn't already have this asset? Would I buy it today?' eliminates the paid price bias. The decision must be based on future prospects, not past cost."}},{id:"mn_019",category:"mindset",title:"Hard Work vs System",scenario:"You believe working harder than everyone is the key to financial success. Would Kiyosaki agree?",choice_liability:{label:"Yes, effort and perseverance are the absolute key",feedback:"Hard work is necessary but insufficient. Kiyosaki notes that the hardest-working employees are often the least wealthy, because their effort enriches the company, not their own asset column."},choice_asset:{label:"No, Kiyosaki insists: the right system > hard work alone",feedback:"'Work hard for yourself, not for someone else' is the central message of Rich Dad Poor Dad. Building systems (business, assets) that work without you is true freedom."}},{id:"mn_020",category:"mindset",title:"Social Comparison",scenario:"Your friends all seem to be 'succeeding' on social media. Does it affect you financially?",choice_liability:{label:"Yes, their posts push me to spend to appear at the same level",feedback:"Social media-fueled comparison is a powerful driver of impulsive spending. You pay real expenses for a virtual image."},choice_asset:{label:"No, I know social media shows everyone's best \u2014 I only compare myself to my past self",feedback:"Comparing your reality to others' highlight reel is an illusion. The only relevant comparison: are you in better shape than a year ago? Personal progress is the true metric."}},{id:"mn_021",category:"mindset",title:"Delegation",scenario:"You manage everything yourself to 'avoid scams'. Is it optimal?",choice_liability:{label:"Yes, nobody manages my money better than me",feedback:"Over-centralization is a bottleneck. Very wealthy people delegate execution while maintaining strategic oversight."},choice_asset:{label:"Delegate the execution of certain financial tasks while keeping strategic oversight",feedback:"Scalable wealth involves delegation. Accountant, advisor, property manager: delegating execution frees your time for high-value decisions."}},{id:"mn_022",category:"mindset",title:"Learning from Others' Mistakes",scenario:"You know someone who went bankrupt. How do you use that experience?",choice_liability:{label:"Avoid everything they did, even if contexts are different",feedback:"Copying someone else's fear without analyzing the context is as irrational as copying their actions without reflection. Each financial situation is unique."},choice_asset:{label:"Analyze the structural causes of the failure to extract applicable principles",feedback:"Others' failures are free lessons. Understanding the mechanisms (excessive leverage, lack of liquidity, concentration) more than the specific anecdotes extracts transferable principles."}},{id:"mn_023",category:"mindset",title:"Luxury and Value",scenario:"You're hesitating about a $800 luxury item. How do you decide?",choice_liability:{label:"Luxury rewards hard work \u2014 you deserve it if you set the goal",feedback:"Material reward isn't problematic in itself \u2014 if budgeted and proportional to built assets. The problem is when luxury precedes assets."},choice_asset:{label:"Buy if my assets cover it easily \u2014 not if it compromises my monthly investment",feedback:"Kiyosaki's rule: the rich buy luxury last, with income from their assets. The poor and middle class buy luxury first, with their active income."}},{id:"mn_024",category:"mindset",title:"The Employee's Freedom",scenario:"Your boss offers a great promotion with more responsibility but more constraints. Do you accept?",choice_liability:{label:"Yes, promotion is the natural career progression",feedback:"A promotion that further chains you in the time-for-money exchange isn't progress toward freedom. It's progress within the E/S quadrant."},choice_asset:{label:"Accept if the promotion funds an asset project \u2014 decline if it consumes more time without creating independence",feedback:"Promotion is neither good nor bad \u2014 it's what you do with it. If it funds an investment that reduces salary dependence, it's leverage. Otherwise, it's a golden chain."}},{id:"mn_025",category:"mindset",title:"Abundance Mentality",scenario:"A competitor copies your business idea. First reaction?",choice_liability:{label:"It's a betrayal \u2014 you'll do everything to block them",feedback:"The scarcity mentality sees competition as an existential threat. The abundance mentality sees it as market validation and an opportunity to differentiate."},choice_asset:{label:"Competition validates the market \u2014 focus on what differentiates you",feedback:"A competitor copying your idea proves the market exists. Kiyosaki talks about abundance: there's enough success for everyone. The race to differentiation is more productive than legal battle."}},{id:"mn_026",category:"mindset",title:"First Job and Money",scenario:"You get your first job at 22. First financial decision?",choice_liability:{label:"Set up comfortably: nice apartment, car, outings",feedback:"The first paycheck trap: lifestyle inflation from the start. Habits established at 22 will be hard to change at 30. Starting small and investing the difference is a well-documented strategy."},choice_asset:{label:"Automate 20% of salary to investment from the first month, before getting used to the amount",feedback:"Pay yourself first is Kiyosaki's principle. Before getting used to the full salary, automatically allocating a portion to investment creates a foundational habit."}},{id:"mn_027",category:"mindset",title:"Respect for Money",scenario:"You receive $20 too much in change at the supermarket. What do you do?",choice_liability:{label:"Keep it \u2014 it's not your fault the cashier made a mistake",feedback:"A values question beyond finance. But how you treat money in small amounts reflects your relationship with money in general."},choice_asset:{label:"Point it out and return the change \u2014 integrity applies to small amounts too",feedback:"Kiyosaki talks about respecting money in all its forms. Financial integrity in small things is the foundation of self-trust in big decisions."}},{id:"mn_028",category:"mindset",title:"The E\u2192S\u2192B\u2192I Mindset",scenario:"You're an employee and want to become an 'asset owner'. Where do you start?",choice_liability:{label:"Immediately quit your job to launch something",feedback:"The immediate jump from E to B without a safety net is risky. Most successful entrepreneurs prepared their transition alongside their job, not by quitting abruptly."},choice_asset:{label:"Build progressively: E \u2192 side project S \u2192 business B \u2192 passive assets I in parallel",feedback:"Kiyosaki's quadrant isn't a jump \u2014 it's a progression. Each step builds on the previous. The transition is prepared while still in security."}},{id:"mn_029",category:"mindset",title:"Refusing Mediocrity",scenario:"You wonder if aiming for financial freedom is arrogant or unrealistic. Does that stop you?",choice_liability:{label:"A little yes \u2014 who am I to want more than average?",feedback:"The normalization of financial mediocrity is culturally constructed. Asking 'who am I to want more?' is a mental limit with a real financial cost over decades."},choice_asset:{label:"No \u2014 aiming for financial freedom isn't arrogant, it's responsible",feedback:"Financial freedom isn't a luxury \u2014 it's the ability to choose your time, your projects and your contributions. Aspiring to it is an act of responsibility to yourself and your loved ones."}},{id:"mn_030",category:"mindset",title:"The Definition of Success",scenario:"How do you define financial success? High salary or time freedom?",choice_liability:{label:"High salary \u2014 recognition and compensation prove value",feedback:"A high salary is success in the E quadrant. But Kiyosaki questions: if you stopped working tomorrow, would your lifestyle change? If yes, you're not yet financially free."},choice_asset:{label:"Time freedom \u2014 having assets that cover my expenses without me working",feedback:"This is Kiyosaki's definition: financial freedom is when your assets generate more than your expenses. Salary is a means, not an end. Time freedom is the destination."}},{id:"cf_031",category:"cashflow",title:"The Unexpected Food Budget",scenario:"You realize you spend $400/month on food and delivery, $200 more than planned. What do you do?",choice_liability:{label:"That's normal, life is expensive \u2014 I adjust my budget upward",feedback:"Adjusting the budget upward to justify an unoptimized expense is the reverse of financial management. The budget guides expenses, not the other way around."},choice_asset:{label:"Identify the $200 in leaks (impulse deliveries, waste) and redirect them",feedback:"$200/month = $2,400/year = a significant investment. Analyzing leaks and redirecting to an asset is a few-minutes decision for a major annual impact."}}],es:[{id:"cf_001",category:"cashflow",title:"El Bono Inesperado",scenario:"Recibes un bono de $3,000 en el trabajo. \xbfQu\xe9 haces?",choice_liability:{label:"Comprar el \xfaltimo smartphone + auriculares",feedback:"Acabas de convertir $3,000 en algo que vale $1,800 ma\xf1ana. Kiyosaki llama a esto alimentar la columna de pasivos."},choice_asset:{label:"Invertir en un fondo \xedndice que genera ingresos mensuales",feedback:"Tu bono ahora trabaja para ti cada mes. Ese es el reflejo de activo que Philia Vault te entrena a construir."}},{id:"cf_002",category:"cashflow",title:"El Aumento",scenario:"Recibes un aumento de $400/mes. \xbfC\xf3mo manejas el excedente?",choice_liability:{label:"Mejorar el apartamento y comprar un auto nuevo",feedback:"Inflaci\xf3n de estilo de vida: tus gastos absorbieron el aumento antes de crear algo. El flujo de caja neto sigue en cero."},choice_asset:{label:"Automatizar una transferencia de $350 a una cuenta de inversi\xf3n",feedback:"La automatizaci\xf3n es el secreto de los ricos. Nunca ves el dinero, nunca se gasta \u2014 se compone."}},{id:"cf_003",category:"cashflow",title:"El Bono Navide\xf1o",scenario:"Recibes un bono de fin de a\xf1o de $1,500. \xbfEs hora de celebrar?",choice_liability:{label:"Organizar una gran cena navide\xf1a y regalos para todos",feedback:"Generoso, pero ese dinero desapareci\xf3 en 48 horas. La experiencia es real, el activo es cero."},choice_asset:{label:"Invertir $1,000 y usar $500 para las fiestas",feedback:"Balance perfecto. Disfruta sin sacrificar tu futuro. La regla 80/20 aplicada a un bono."}},{id:"cf_004",category:"cashflow",title:"La Devoluci\xf3n de Impuestos",scenario:"Recibes una devoluci\xf3n de impuestos de $2,200. \xbfPrimera reacci\xf3n?",choice_liability:{label:"Reservar unas vacaciones todo incluido \u2014 te lo mereces",feedback:"Recuerdos preciados, pero ning\xfan activo creado. En 30 d\xedas el dinero se fue y las deudas contin\xfaan."},choice_asset:{label:"Pagar una deuda de alto inter\xe9s o construir un fondo de emergencia",feedback:"Pagar deuda costosa es un retorno garantizado igual a su tasa de inter\xe9s. Matem\xe1ticamente imbatible a corto plazo."}},{id:"cf_005",category:"cashflow",title:"El Fondo de Cumplea\xf1os",scenario:"Tus amigos juntan $800 para tu cumplea\xf1os. \xbfQu\xe9 haces?",choice_liability:{label:"Llevar a todos a un buen restaurante a celebrar",feedback:"Gran experiencia \u2014 y el dinero evaporado. La columna de activos no se movi\xf3."},choice_asset:{label:"Comprar acciones fraccionadas de activos productivos",feedback:"Transformas un regalo en ingresos recurrentes. Tus amigos te dieron un activo sin saberlo."}},{id:"cf_006",category:"cashflow",title:"El Extra Mensual",scenario:"Tu empleador aumenta tu subsidio de comida en $150/mes. \xbfC\xf3mo usas la diferencia?",choice_liability:{label:"Comer en mejores restaurantes todos los d\xedas",feedback:"Elevaste tu estilo de vida, no tu patrimonio. Cada mes, $150 desaparecen en placer inmediato."},choice_asset:{label:"Llevar tu propia comida e invertir los $150 cada mes",feedback:"$150/mes durante 10 a\xf1os, incluso con un retorno modesto, es significativo. La consistencia supera la intensidad."}},{id:"cf_007",category:"cashflow",title:"El Proyecto Freelance",scenario:"Consigues un proyecto freelance por $2,500 este mes. \xbfPrimera decisi\xf3n?",choice_liability:{label:"Recompensarte con compras que ven\xedas postergando",feedback:"Trabajaste el doble para consumir el doble. El h\xe1mster corre m\xe1s r\xe1pido pero la rueda gira igual."},choice_asset:{label:"Invertir el 80% y usar el 20% como quieras",feedback:"La regla de oro para ingresos extra. 80% construye tu libertad, 20% recompensa el esfuerzo. El ciclo virtuoso empieza aqu\xed."}},{id:"cf_008",category:"cashflow",title:"La Venta de Garage",scenario:"Vendes cosas sin usar y obtienes $400. \xbfQu\xe9 sigue?",choice_liability:{label:"Aprovechar para comprar cosas nuevas en oferta",feedback:"Vendiste pasivos para comprar pasivos. Un intercambio perfecto \u2014 pero tu situaci\xf3n no cambi\xf3."},choice_asset:{label:"Depositarlo inmediatamente en tu cuenta de inversi\xf3n",feedback:"Acabas de convertir pasivos dormidos (cosas viejas) en capital productivo. Esto es exactamente lo que ense\xf1a Kiyosaki."}},{id:"cf_009",category:"cashflow",title:"El Cashback de la Tarjeta",scenario:"Acumulas $250 en cashback durante el a\xf1o. \xbfQu\xe9 haces?",choice_liability:{label:"Usar el cashback para una cena elegante",feedback:"Un placer merecido, pero el dinero no trabaja para ti."},choice_asset:{label:"Reinvertir autom\xe1ticamente el cashback en un activo productivo",feedback:"Incluso $250 invertidos regularmente construyen un h\xe1bito mental m\xe1s valioso que la cantidad en d\xf3lares."}},{id:"cf_010",category:"cashflow",title:"El Alquiler Reducido",scenario:"Tu arrendador baja el alquiler $200/mes durante 6 meses. \xbfQu\xe9 haces con la diferencia?",choice_liability:{label:"Darte peque\xf1os extras \u2014 streaming, delivery, salidas",feedback:"La facilidad absorbe el excedente. En 6 meses, no tendr\xe1s nada que mostrar de esos 6 meses de 'ahorro'."},choice_asset:{label:"Automatizar una transferencia de $200 el 1\xb0 de cada mes",feedback:"Nunca viste este dinero. Fue directamente a construir tu futuro. La mejor forma de gastar menos es nunca ver llegar el dinero."}},{id:"cf_011",category:"cashflow",title:"La Negociaci\xf3n del Seguro",scenario:"Renegocias tu seguro y ahorras $80/mes. \xbfAd\xf3nde va el excedente?",choice_liability:{label:"Incorporarlo mentalmente a tu presupuesto de 'ocio'",feedback:"El gasto invisible. El dinero no asignado siempre termina en gastos no planificados."},choice_asset:{label:"Crear una transferencia autom\xe1tica de $80 a un activo este mes",feedback:"Cada ahorro es una oportunidad de inversi\xf3n disfrazada. No recortaste tu presupuesto \u2014 lo reasignaste inteligentemente."}},{id:"cf_012",category:"cashflow",title:"El Reembolso del Amigo",scenario:"Un amigo te devuelve $300 que te deb\xeda. \xbfReflejo?",choice_liability:{label:"La ocasi\xf3n perfecta para comprar algo que quer\xedas",feedback:"El dinero inesperado siempre va a gastos no planificados sin una regla preestablecida."},choice_asset:{label:"Aplicar mi regla: todo dinero inesperado va directo a activos",feedback:"La disciplina en cantidades peque\xf1as forja h\xe1bitos para las grandes. Una regla clara elimina la tentaci\xf3n."}},{id:"cf_013",category:"cashflow",title:"La Comisi\xf3n de Ventas",scenario:"Consigues una comisi\xf3n excepcional de $1,800 este mes. \xbfPlan de acci\xf3n?",choice_liability:{label:"Celebrar con salidas y compras impulsivas",feedback:"La celebraci\xf3n es natural. Pero si cada \xe9xito se gasta inmediatamente, el \xe9xito no construye nada."},choice_asset:{label:"Celebrar modestamente e invertir el resto para ingresos recurrentes",feedback:"La comisi\xf3n es un evento. Los ingresos pasivos que genera son permanentes. Convierte lo excepcional en estructural."}},{id:"cf_014",category:"cashflow",title:"El Dividendo de la Cooperativa",scenario:"Recibes $120 en dividendos de tu cooperativa de compras. \xbfQu\xe9 haces?",choice_liability:{label:"Usar los dividendos para las compras del mes",feedback:"Los dividendos gastados en consumo nunca crecen. El ciclo de crecimiento se rompe en el primer retiro."},choice_asset:{label:"Reinvertir autom\xe1ticamente los dividendos para comprar m\xe1s acciones",feedback:"El inter\xe9s compuesto en acci\xf3n. Cada dividendo reinvertido genera dividendos futuros. Este es el motor de la riqueza."}},{id:"cf_015",category:"cashflow",title:"Presupuesto de Ocio Sobrante",scenario:"Te das cuenta de que solo gastaste $150 de tu presupuesto de ocio de $300 este mes. \xbfQu\xe9 haces con los $150?",choice_liability:{label:"Trasladarlo al mes siguiente para 'recuperar'",feedback:"La mentalidad de 'presupuesto para gastar' convierte los ahorros en permiso para gastar m\xe1s despu\xe9s."},choice_asset:{label:"Transferir inmediatamente los $150 no gastados a tu inversi\xf3n",feedback:"El ahorro realizado es un activo potencial. Actuar de inmediato previene la tentaci\xf3n de gastarlo 'despu\xe9s'."}},{id:"cf_016",category:"cashflow",title:"Pr\xe9stamo a un Amigo",scenario:"Tienes $500 disponibles. Un amigo pide prestarlo 'para pasar el mes'. \xbfQu\xe9 haces?",choice_liability:{label:"Prestar sin dudar, son familia/amigo",feedback:"La generosidad es un valor. Pero un pr\xe9stamo informal es a menudo un regalo disfrazado que crea tensi\xf3n en la relaci\xf3n."},choice_asset:{label:"Eval\xfaa tu situaci\xf3n, s\xe9 claro si es pr\xe9stamo o regalo, docum\xe9ntalo",feedback:"La claridad y honestidad protegen tanto la relaci\xf3n como tus finanzas. Un regalo reconocido es m\xe1s sano que un pr\xe9stamo sin retorno."}},{id:"cf_017",category:"cashflow",title:"El Caf\xe9 Diario",scenario:"Gastas $5/d\xeda en caf\xe9. Un colega dice que son $150/mes 'desperdiciados'. \xbfTiene raz\xf3n?",choice_liability:{label:"Tiene raz\xf3n, voy a cortar el caf\xe9 inmediatamente para ahorrar",feedback:"La privaci\xf3n total rara vez es sostenible. La gesti\xf3n financiera es optimizaci\xf3n, no castigo."},choice_asset:{label:"Mantener el caf\xe9 pero auditar mis gastos reales no intencionales",feedback:"El caf\xe9 diario es a menudo el \xfanico gasto consciente. Las verdaderas fugas del presupuesto son suscripciones olvidadas y compras impulsivas online."}},{id:"cf_018",category:"cashflow",title:"Costos Fijos en Alza",scenario:"Tus costos fijos aumentan $100/mes. \xbfC\xf3mo reaccionas?",choice_liability:{label:"Aceptar el aumento y recortar aleatoriamente en otro lado",feedback:"Sin un plan espec\xedfico, los recortes 'aleatorios' siempre caen en las cosas equivocadas \u2014 nunca en las verdaderas fugas."},choice_asset:{label:"Auditar todos los gastos, identificar los $100 menos \xfatiles y eliminarlos",feedback:"Un aumento de costos es una oportunidad de auditor\xeda. Optimizas tu presupuesto en vez de sufrirlo."}},{id:"cf_019",category:"cashflow",title:"El Proyecto Paralelo Rentable",scenario:"Tu proyecto paralelo genera sus primeros $300 netos este mes. \xbfQu\xe9 haces?",choice_liability:{label:"Finalmente pagarte \u2014 te lo mereces",feedback:"Pagarse desde un proyecto joven ralentiza su crecimiento. Los emprendedores exitosos se pagan a s\xed mismos al \xfaltimo."},choice_asset:{label:"Reinvertir $250 en el proyecto y guardar $50 simb\xf3licamente",feedback:"La reinversi\xf3n temprana acelera el crecimiento exponencial. $50 de 'salario' simb\xf3lico mantiene la motivaci\xf3n sin frenar el proyecto."}},{id:"cf_020",category:"cashflow",title:"La Auditor\xeda de Suscripciones",scenario:"Te das cuenta de que pagas 4 servicios de streaming ($55/mes en total). \xbfQu\xe9 haces?",choice_liability:{label:"Mantener todas las suscripciones, las usas todas 'un poco'",feedback:"$55/mes = $660/a\xf1o por contenido consumido pasivamente. Un activo comparable podr\xeda generar ingresos mensuales."},choice_asset:{label:"Mantener 1-2 m\xe1ximo, redirigir los $30-40 ahorrados a una inversi\xf3n",feedback:"Cada suscripci\xf3n in\xfatil es alquiler pagado por distracci\xf3n. Optimizar costos fijos libera capital de inversi\xf3n real."}},{id:"cf_021",category:"cashflow",title:"Prepago vs Inversi\xf3n",scenario:"Puedes pagar $500 de cr\xe9dito al consumo este mes. O invertir esos $500. \xbfQu\xe9 haces?",choice_liability:{label:"Invertir los $500 \u2014 los retornos cubrir\xe1n los intereses del cr\xe9dito",feedback:"Error matem\xe1tico cl\xe1sico: las tasas de cr\xe9dito al consumo casi siempre superan los retornos de inversi\xf3n. El pago es la prioridad."},choice_asset:{label:"Pagar el cr\xe9dito \u2014 es un retorno garantizado a la tasa del cr\xe9dito",feedback:"Excelente razonamiento. Pagar deuda costosa ofrece un retorno garantizado igual a su tasa. La inversi\xf3n m\xe1s segura en este momento."}},{id:"cf_022",category:"cashflow",title:"El Presupuesto de Comida",scenario:"Puedes reducir tu factura de comida en $80/mes cocinando m\xe1s. \xbfVale la pena?",choice_liability:{label:"No, el tiempo que toma no vale la pena",feedback:"$80/mes = $960/a\xf1o. Evaluar tiempo/dinero es v\xe1lido, pero la barrera real suele ser el h\xe1bito, no el tiempo."},choice_asset:{label:"S\xed, cocinar en lote los fines de semana y reinvertir los ahorros",feedback:"Doble beneficio: mejor nutrici\xf3n + $80/mes extra para invertir. Cocinar en lote es una palanca subestimada."}},{id:"cf_023",category:"cashflow",title:"El Gadget Tecnol\xf3gico en Oferta",scenario:"Un gadget que quer\xedas est\xe1 en oferta a $400 (de $600). \xbfEs el momento?",choice_liability:{label:"S\xed, -33% es una oportunidad que no se puede perder",feedback:"Un descuento en algo que no hab\xedas planeado comprar no es un ahorro \u2014 es un gasto disfrazado de oportunidad."},choice_asset:{label:"No, no estaba en mi plan. Guardo los $400 para un activo",feedback:"La disciplina financiera real es resistir las 'buenas ofertas' no planificadas. Tu plan de asignaci\xf3n supera las promociones."}},{id:"cf_024",category:"cashflow",title:"La Indemnizaci\xf3n",scenario:"Dejas un trabajo y recibes $4,000 de indemnizaci\xf3n. \xbfPlan de emergencia?",choice_liability:{label:"Viajar durante la transici\xf3n de carrera",feedback:"Las transiciones son costosas. Usar la indemnizaci\xf3n para viajar sin ingresos crea presi\xf3n financiera innecesaria."},choice_asset:{label:"Construir un fondo de emergencia de 3 meses e invertir el resto",feedback:"Seguridad primero. Un fondo de emergencia s\xf3lido permite mejores decisiones profesionales sin la presi\xf3n de la necesidad."}},{id:"cf_025",category:"cashflow",title:"El Saldo Olvidado",scenario:"Te das cuenta de que ten\xedas $600 olvidados en una cuenta bancaria antigua. \xbfQu\xe9 haces?",choice_liability:{label:"El capricho perfecto sin culpa",feedback:"El dinero 'encontrado' se trata diferente al 'ganado' \u2014 es un sesgo cognitivo. En realidad tiene el mismo valor."},choice_asset:{label:"Tratarlo exactamente como cualquier otro ingreso e invertirlo",feedback:"El tratamiento consistente de todos los flujos de dinero es la marca de un plan financiero real. El dinero no cambia de valor seg\xfan su origen."}},{id:"cf_026",category:"cashflow",title:"El Desaf\xedo de Ahorro",scenario:"Un amigo propone un desaf\xedo: ahorrar $10 m\xe1s por semana durante un a\xf1o. \xbfAceptas?",choice_liability:{label:"Muy poco para cambiar algo, no vale el esfuerzo",feedback:"$10/semana = $520/a\xf1o. No es el monto \u2014 es el h\xe1bito de ahorro e identidad que se est\xe1 construyendo."},choice_asset:{label:"S\xed, y automati\xe7o una transferencia semanal de $10 hoy",feedback:"La automatizaci\xf3n convierte la intenci\xf3n en sistema. Los sistemas superan la fuerza de voluntad con el tiempo."}},{id:"cf_027",category:"cashflow",title:"El Reembolso del Dep\xf3sito",scenario:"Te devuelven el dep\xf3sito de $1,200 al mudarte. \xbfReflejo inmediato?",choice_liability:{label:"Usarlo para amueblar y decorar el nuevo apartamento",feedback:"Natural \u2014 pero si el dep\xf3sito financia el nuevo lugar, empiezas desde cero financieramente, igual que antes."},choice_asset:{label:"Invertir el dep\xf3sito y usar un presupuesto separado (menor) para la mudanza",feedback:"Separar los flujos previene 'consumir' los reembolsos. El dep\xf3sito recuperado es capital a preservar, no a gastar inmediatamente."}},{id:"cf_028",category:"cashflow",title:"La Herencia Modesta",scenario:"Heredas $5,000 de un familiar. \xbfC\xf3mo honras esa herencia?",choice_liability:{label:"Hacer realidad un viaje so\xf1ado en su honor",feedback:"El viaje puede ser significativo y hermoso. Pero $5,000 gastados \xedntegramente no crean ning\xfan legado financiero."},choice_asset:{label:"Invertir la mayor parte, hacer un gesto simb\xf3lico peque\xf1o con una porci\xf3n",feedback:"Transformas esta herencia en un activo duradero que sigue trabajando. Esa puede ser la forma m\xe1s respetuosa de honrar el trabajo de alguien."}},{id:"cf_029",category:"cashflow",title:"El Presupuesto de Vacaciones",scenario:"Ahorras para vacaciones ($150/mes por 8 meses). Tienes $1,200. \xbfC\xf3mo lo manejas?",choice_liability:{label:"Gastar los $1,200 completos para unas vacaciones memorables",feedback:"Las vacaciones anuales asequibles son saludables. Pero si $1,200 es todo tu ahorro, las vacaciones te costaron todo tu margen de seguridad."},choice_asset:{label:"$800 de presupuesto de vacaciones, invertir $400 del monto ahorrado",feedback:"Disfruta mientras construyes. La disciplina de no gastar todo incluso cuando est\xe1 'planificado para eso' es habilidad financiera avanzada."}},{id:"cf_030",category:"cashflow",title:"El Gimnasio Abandonado",scenario:"Pagas $60/mes por el gimnasio pero casi no vas. \xbfQu\xe9 haces?",choice_liability:{label:"Mantener la membres\xeda, ir\xe1s 'pronto'",feedback:"$60/mes \xd7 12 = $720/a\xf1o por una intenci\xf3n. Las intenciones no ejecutadas son los gastos m\xe1s caros."},choice_asset:{label:"Cancelar inmediatamente, reinvertir los $60/mes, encontrar una alternativa gratuita",feedback:"Cortar un gasto in\xfatil y reinvertirlo inmediatamente es uno de los actos de optimizaci\xf3n financiera m\xe1s concretos. Act\xfaa ahora, no ma\xf1ana."}},{id:"dt_001",category:"debt",title:"Tarjeta de Cr\xe9dito al M\xe1ximo",scenario:"Tu tarjeta de cr\xe9dito est\xe1 al 90% de su l\xedmite ($4,500 de saldo). \xbfEstrategia?",choice_liability:{label:"Pagar el m\xednimo cada mes y seguir usando la tarjeta",feedback:"El m\xednimo mantiene el saldo casi permanente. El inter\xe9s compuesto en deuda de consumo es el inverso exacto del inter\xe9s compuesto de inversi\xf3n."},choice_asset:{label:"Detener todo uso, pagar el m\xe1ximo posible cada mes hasta saldar",feedback:"La avalancha de deuda: apunta a la deuda m\xe1s cara primero. Cada d\xf3lar por encima del m\xednimo es un retorno garantizado a la tasa de la tarjeta."}},{id:"dt_002",category:"debt",title:"El Pr\xe9stamo Estudiantil",scenario:"Debes $25,000 en pr\xe9stamos estudiantiles al 5%. \xbfM\xe9todo?",choice_liability:{label:"Pagar exactamente el m\xednimo durante todo el plazo",feedback:"Al 5%, est\xe1s pagando correctamente el costo de tu educaci\xf3n. Pero si puedes invertir con mayores retornos, la estrategia m\xednima puede ser racional \u2014 siempre que realmente inviertas la diferencia."},choice_asset:{label:"Pagar un excedente cada mes para reembolsar m\xe1s r\xe1pido y reducir el inter\xe9s total",feedback:"Cada mes de reembolso anticipado reduce el plazo y el inter\xe9s total. Es un retorno garantizado del 5% en cada d\xf3lar extra reembolsado."}},{id:"dt_003",category:"debt",title:"Consolidaci\xf3n de Deudas",scenario:"Tienes 3 deudas a diferentes tasas. Una empresa ofrece fusionarlas en un pago mensual m\xe1s bajo. \xbfAceptas?",choice_liability:{label:"\xa1S\xed! Un pago m\xe1s bajo, es m\xe1s simple",feedback:"Cuidado: un pago m\xe1s bajo durante m\xe1s tiempo puede significar pagar mucho m\xe1s en inter\xe9s total. Calcula el costo total antes de firmar."},choice_asset:{label:"Analizar la tasa general, duraci\xf3n total y costo real antes de decidir",feedback:"La consolidaci\xf3n puede ser ventajosa \u2014 o una trampa de marketing. La pregunta real: \xbfcu\xe1l es el costo total de la deuda consolidada vs el reembolso actual?"}},{id:"dt_004",category:"debt",title:"Sobregiro Recurrente",scenario:"Usas sistem\xe1ticamente tu sobregiro autorizado de $500 cada mes. \xbfReacci\xf3n?",choice_liability:{label:"El banco lo permite, as\xed que est\xe1 bien",feedback:"Los sobregiros autorizados est\xe1n entre los cr\xe9ditos m\xe1s caros en t\xe9rminos de tasa real. Un sobregiro recurrente se\xf1ala un problema de flujo de caja que empeora."},choice_asset:{label:"Tratar el sobregiro como una emergencia y reestructurar mi presupuesto inmediatamente",feedback:"El sobregiro recurrente es una se\xf1al de alarma, no una herramienta de gesti\xf3n. Indica que los gastos superan los ingresos \u2014 un problema estructural, no temporal."}},{id:"dt_005",category:"debt",title:"La Oferta 0% por 12 Meses",scenario:"Una tienda ofrece pagos a 12 meses sin inter\xe9s en una compra de $1,200. \xbfLo tomas?",choice_liability:{label:"S\xed, 0% es gratis, mejor aprovecharlo",feedback:"El 0% es real \u2014 pero solo si reembolsas ANTES de que termine el per\xedodo. Despu\xe9s, la tasa retroactiva puede ser extremadamente alta."},choice_asset:{label:"No, si no puedo pagar en efectivo, probablemente no me lo puedo permitir",feedback:"La regla de Kiyosaki: si tienes que pedir prestado para comprar un pasivo (consumo), no te lo puedes permitir. El 0% hace el pasivo m\xe1s accesible, no menos pasivo."}},{id:"dt_006",category:"debt",title:"El Pr\xe9stamo de Auto",scenario:"Necesitas un auto. El concesionario ofrece un pr\xe9stamo a 60 meses con un pago mensual 'c\xf3modo'. \xbfFirmas?",choice_liability:{label:"S\xed, el pago cabe en mi presupuesto",feedback:"Un auto es un pasivo que se deprecia en el momento en que sale del concesionario. Financiar un pasivo durante 60 meses significa pagar intereses en algo que pierde valor cada mes."},choice_asset:{label:"Comprar un auto usado confiable con ahorros o un pr\xe9stamo a corto plazo",feedback:"Un auto usado pagado en efectivo o a corto plazo reduce el costo total y la presi\xf3n mensual. Liberar costos fijos libera capital."}},{id:"dt_007",category:"debt",title:"Avalancha vs Bola de Nieve",scenario:"Tienes varias deudas. \xbfQu\xe9 m\xe9todo de pago eliges?",choice_liability:{label:"Pagar las m\xe1s peque\xf1as primero para sentir progreso",feedback:"El m\xe9todo bola de nieve (el m\xe1s peque\xf1o primero) es psicol\xf3gicamente motivador pero matem\xe1ticamente m\xe1s costoso. Pagas m\xe1s inter\xe9s total."},choice_asset:{label:"Pagar la deuda de mayor tasa primero (m\xe9todo avalancha)",feedback:"El m\xe9todo avalancha es matem\xe1ticamente \xf3ptimo \u2014 pagas el menor inter\xe9s total. Si mantienes la disciplina, es la estrategia m\xe1s eficiente."}},{id:"dt_008",category:"debt",title:"Refinanciaci\xf3n de Hipoteca",scenario:"Las tasas bajan y puedes refinanciar tu hipoteca para ahorrar $150/mes. \xbfQu\xe9 haces con el ahorro?",choice_liability:{label:"Elevar tu nivel de vida con este excedente mensual",feedback:"Optimizaste tu deuda pero absorbiste el ahorro en estilo de vida. La optimizaci\xf3n solo crea riqueza si se reinvierte."},choice_asset:{label:"Reinvertir los $150/mes ahorrados en un activo productivo",feedback:"Optimizaci\xf3n de deuda + reinversi\xf3n inmediata del ahorro: doble palanca de riqueza. Trabajas menos y construyes m\xe1s en paralelo."}},{id:"dt_009",category:"debt",title:"Pedir Prestado para Invertir",scenario:"Puedes pedir prestado $10,000 al 4% para invertir en un activo que te\xf3ricamente rinde 8%. \xbfLo haces?",choice_liability:{label:"S\xed, el diferencial del 4% est\xe1 a mi favor",feedback:"El apalancamiento amplifica ganancias Y p\xe9rdidas. Un retorno del 8% es una hip\xf3tesis, no una garant\xeda. Si el activo cae, a\xfan debes el pr\xe9stamo al 4%."},choice_asset:{label:"Esperar hasta tener fondos propios, o limitar estrictamente el apalancamiento",feedback:"El apalancamiento de inversi\xf3n es una herramienta avanzada para manejar con cuidado. Para un principiante, cero apalancamiento es una estrategia en s\xed misma."}},{id:"dt_010",category:"debt",title:"Compra Ahora Paga Despu\xe9s",scenario:"Un servicio online ofrece 'comprar ahora, pagar en 6 meses'. \xbfUsas esta opci\xf3n?",choice_liability:{label:"S\xed, me da tiempo para reunir los fondos",feedback:"'Pagar en 6 meses' a menudo significa retrasar una compra que no puedes pagar ahora. En 6 meses, otros gastos se acumulan \u2014 y la deuda permanece."},choice_asset:{label:"No, si no puedo pagar ahora, no compro ahora",feedback:"La disciplina del pago inmediato es un poderoso filtro contra las compras impulsivas. Si no puedes pagar hoy, la compra puede no ser una prioridad."}},{id:"dt_011",category:"debt",title:"Ser Garante",scenario:"Un amigo cercano te pide co-firmar su hipoteca. \xbfAceptas?",choice_liability:{label:"S\xed, son familia/amigo, conf\xedo en ellos",feedback:"Ser garante significa comprometerse legalmente a reembolsar la deuda si el prestatario no puede. La confianza no protege contra los accidentes de la vida."},choice_asset:{label:"No, o solo despu\xe9s de entender todas las implicaciones legales y financieras",feedback:"Ser co-firmante es un compromiso financiero real que puede afectar tu capacidad de endeudamiento futuro. Una decisi\xf3n que merece an\xe1lisis, no solo amor."}},{id:"dt_012",category:"debt",title:"La Compra de Deuda",scenario:"Una empresa ofrece comprar todos tus pr\xe9stamos para reducir tu pago en $300. \xbfAceptas sin dudar?",choice_liability:{label:"S\xed, $300 menos al mes es exactamente lo que necesito",feedback:"Un pago m\xe1s bajo durante m\xe1s tiempo puede costar miles m\xe1s en total. Calcula el costo total, no solo el pago."},choice_asset:{label:"Primero calcular el costo total antes y despu\xe9s de la compra",feedback:"El pago mensual es solo un dato. El costo total (monto \xd7 duraci\xf3n \xd7 tasa) es la \xfanica m\xe9trica que importa para comparar ofertas de pr\xe9stamos."}},{id:"dt_013",category:"debt",title:"La Deuda Familiar",scenario:"Debes dinero a un familiar. No te presionan. \xbfPriorizas pagarlo?",choice_liability:{label:"No, no me presionan, pagar\xe9 otras deudas primero",feedback:"Financieramente l\xf3gico si la deuda familiar est\xe1 al 0%. Pero no reembolsar puede crear una tensi\xf3n relacional invisible con un costo humano real."},choice_asset:{label:"S\xed, reembolso con un plan claro para no dejar que la deuda contamine la relaci\xf3n",feedback:"La claridad relacional y financiera est\xe1n vinculadas. Un plan de reembolso formalizado, incluso sin inter\xe9s, respeta la confianza dada."}},{id:"dt_014",category:"debt",title:"La Tarjeta de Cr\xe9dito Rotativa",scenario:"El banco te env\xeda una tarjeta de cr\xe9dito rotativa con un l\xedmite de $2,000. \xbfLa activas?",choice_liability:{label:"S\xed, es \xfatil para emergencias y gastos inesperados",feedback:"El cr\xe9dito rotativo es uno de los productos financieros m\xe1s caros. Un fondo de emergencia real en una cuenta de ahorros cumple el mismo papel con cero inter\xe9s."},choice_asset:{label:"No, construyo un fondo de emergencia para nunca necesitar cr\xe9dito rotativo",feedback:"El objetivo final: nunca necesitar cr\xe9dito de emergencia. Un fondo de emergencia de 3-6 meses de gastos es el mejor producto financiero que existe."}},{id:"dt_015",category:"debt",title:"Prestar a un Amigo con Inter\xe9s",scenario:"Tienes $1,000 disponibles. Un amigo propone pedirlos prestados al 5% de inter\xe9s. \xbfPrefieres...",choice_liability:{label:"Prestar los $1,000 al 5% a mi amigo",feedback:"El 5% de inter\xe9s garantizado parece atractivo. Pero si el amigo no reembolsa, pierdes tanto el dinero COMO al amigo."},choice_asset:{label:"Invertir los $1,000 en un activo diversificado para evitar mezclar dinero y amistad",feedback:"Kiyosaki aconseja nunca mezclar dinero y relaciones emocionales sin reglas muy claras. Una inversi\xf3n en un activo mantiene la amistad pura."}},{id:"dt_016",category:"debt",title:"Hipoteca vs Alquiler",scenario:"Dudas entre comprar (hipoteca $1,400/mes) y alquilar ($1,100/mes). \xbfCriterio de decisi\xf3n?",choice_liability:{label:"Comprar \u2014 cuesta m\xe1s pero es una inversi\xf3n, siempre mejor",feedback:"El inmueble a menudo se presenta como activo, pero Kiyosaki matiza: tu residencia principal no genera ingresos. Puede incluso ser un pasivo si cuesta m\xe1s de lo que produce."},choice_asset:{label:"Comparar el costo total de propiedad vs alquiler + invertir la diferencia",feedback:"La pregunta real: si invierto los $300 mensuales de diferencia durante 20 a\xf1os, \xbfcu\xe1l es el valor final vs la apreciaci\xf3n inmobiliaria esperada? La respuesta no es obvia."}},{id:"dt_017",category:"debt",title:"El Cr\xe9dito de Consumo F\xe1cil",scenario:"Un vendedor ofrece cr\xe9dito 'f\xe1cil' a $50/mes por una compra de $600. \xbfAceptas?",choice_liability:{label:"$50/mes no es nada, es asequible",feedback:"$50/mes puede parecer insignificante, pero cada cr\xe9dito de consumo reduce tu capacidad de ahorro y potencialmente tu capacidad de endeudamiento futuro para activos."},choice_asset:{label:"Rechazar y esperar hasta haber ahorrado los $600 para pagar en efectivo",feedback:"La disciplina de esperar: si ahorras $100/mes, tienes los $600 en 6 meses sin intereses. La paciencia es el primer capital del inversor."}},{id:"dt_018",category:"debt",title:"Renegociaci\xf3n de Tasa",scenario:"Puedes dedicar 2 horas a renegociar tu hipoteca para potencialmente ahorrar $5,000 a lo largo del plazo. \xbfLo haces?",choice_liability:{label:"2 horas por $5,000 hipot\xe9ticos es demasiado esfuerzo",feedback:"$5,000 / 2h = $2,500/hora de valor potencial. La renegociaci\xf3n es a menudo la acci\xf3n financiera con mejor ROI disponible para un individuo."},choice_asset:{label:"S\xed, inmediatamente. Es probablemente la mejor hora de mi vida financiera",feedback:"La renegociaci\xf3n de hipoteca es la palanca financiera m\xe1s accesible y m\xe1s ignorada. Una hora puede valer miles \u2014 y nunca es demasiado tarde."}},{id:"dt_019",category:"debt",title:"Saldo de Tarjeta a Fin de Mes",scenario:"No puedes pagar completamente tu saldo de tarjeta de cr\xe9dito este mes. \xbfCu\xe1nto pagas?",choice_liability:{label:"El m\xednimo requerido, lo compensar\xe9 el mes siguiente",feedback:"Pagar el m\xednimo activa el inter\xe9s compuesto en tu contra. 'El mes siguiente' casi nunca llega para saldos peque\xf1os \u2014 que crecen silenciosamente."},choice_asset:{label:"El m\xe1ximo posible, y bloqueo la tarjeta para no empeorar las cosas",feedback:"Pagar el m\xe1ximo posible + bloquear el uso = doble acci\xf3n. Detiene el sangrado Y acelera la recuperaci\xf3n."}},{id:"dt_020",category:"debt",title:"Cr\xe9dito para Formaci\xf3n",scenario:"Un curso cuesta $3,000. Puedes pagar en efectivo o usar cr\xe9dito al 6%. \xbfQu\xe9 haces?",choice_liability:{label:"Usar cr\xe9dito para mantener el efectivo disponible para otra cosa",feedback:"Si 'otra cosa' significa gastarlo, el cr\xe9dito al 6% es la decisi\xf3n equivocada. Si 'otra cosa' significa invertirlo a m\xe1s del 6%, la matem\xe1tica puede favorecer el cr\xe9dito."},choice_asset:{label:"Pagar en efectivo si la formaci\xf3n tiene un ROI claro y medible sobre mis ingresos",feedback:"La formaci\xf3n es un activo si aumenta mediblemente tu capacidad de ingresos. Efectivo o cr\xe9dito depende del ROI esperado y tu tasa de inter\xe9s alternativa."}},{id:"dt_021",category:"debt",title:"Deuda vs Ahorros de Emergencia",scenario:"Tienes $2,000 ahorrados y $1,500 en deuda al 18%. \xbfUsas los ahorros para reembolsar?",choice_liability:{label:"No, mantener los ahorros para emergencias, es seguridad",feedback:"Mantener $2,000 al ~1% mientras pagas 18% en $1,500 te cuesta ~$250/a\xf1o neto. La 'seguridad' tiene un precio real."},choice_asset:{label:"S\xed, reembolsar $1,500 y mantener $500 como fondo m\xednimo de emergencia",feedback:"Reembolsar deuda al 18% con ahorros al 1% es una ganancia neta del 17%. Mant\xe9n un m\xednimo de emergencia ($500), reembolsa el resto."}},{id:"dt_022",category:"debt",title:"Seguro de Cr\xe9dito",scenario:"El banco ofrece seguro de cr\xe9dito a $40/mes para cubrir tus reembolsos en caso de accidente. \xbfLo tomas?",choice_liability:{label:"S\xed, es tranquilizador y el banco lo recomienda",feedback:"El seguro de cr\xe9dito vendido por bancos es a menudo sobrePrecio y mal adaptado. Compara con seguros independientes o un fondo de emergencia autoestructurado."},choice_asset:{label:"Evaluar la necesidad real y comparar con alternativas independientes",feedback:"El seguro puede ser \xfatil \u2014 pero el precio y las condiciones var\xedan enormemente. La alternativa a menudo m\xe1s barata: un fondo de emergencia equivalente a 3-6 meses de cargos."}},{id:"dt_023",category:"debt",title:"Pedido Prestado para Invertir",scenario:"Un amigo te dice que pidi\xf3 prestado para comprar activos especulativos. Est\xe1 ganando mucho. \xbfHaces lo mismo?",choice_liability:{label:"Si \xe9l puede, yo tambi\xe9n \u2014 las ganancias parecen reales",feedback:"Sesgo de confirmaci\xf3n: ves las ganancias, no las p\xe9rdidas. La gente no te habla de las inversiones apalancadas que salieron mal."},choice_asset:{label:"Felicitar al amigo, pero analizar el riesgo real del apalancamiento antes de copiar",feedback:"El apalancamiento amplifica en ambas direcciones. Tu amigo puede haber tenido raz\xf3n por suerte tanto como por estrategia. Analiza tu propio perfil de riesgo primero."}},{id:"dt_024",category:"debt",title:"Pago Extra de Hipoteca vs Invertir",scenario:"Puedes pagar $500/mes extra en tu hipoteca (al 3%) O invertir esos $500. \xbfQu\xe9 haces?",choice_liability:{label:"Pagar la hipoteca m\xe1s r\xe1pido para 'librarse de deudas' antes",feedback:"Al 3% de hipoteca, el prepago anticipado ofrece un retorno garantizado del 3%. Excelente en entornos de bajo rendimiento, menos \xf3ptimo si puedes invertir al 7%+."},choice_asset:{label:"Invertir los $500 si los retornos esperados superan significativamente el 3%",feedback:"Matem\xe1ticamente, si puedes invertir a largo plazo con un retorno esperado del 6-8% y tu hipoteca est\xe1 al 3%, la inversi\xf3n gana. Pero es arriesgado \u2014 el 3% es garantizado, el 7% no."}},{id:"dt_025",category:"debt",title:"Liquidaci\xf3n de Deuda",scenario:"Una empresa ofrece comprar tu deuda por 50 centavos por d\xf3lar. \xbfAceptas?",choice_liability:{label:"\xa1S\xed! Pagar el 50% de mi deuda es el mejor trato posible",feedback:"Una liquidaci\xf3n del 50% puede impactar tu historial crediticio y relaci\xf3n con los acreedores. Tambi\xe9n verifica las posibles implicaciones fiscales."},choice_asset:{label:"Analizar implicaciones legales, fiscales y de puntaje de cr\xe9dito antes de decidir",feedback:"La liquidaci\xf3n de deuda puede ser una soluci\xf3n viable pero compleja. Entender todas las consecuencias \u2014 particularmente en la capacidad de endeudamiento futuro \u2014 es esencial."}},{id:"dt_026",category:"debt",title:"El Cr\xe9dito Gratuito del Vendedor",scenario:"Un vendedor inmobiliario ofrece financiamiento al 0% por 2 a\xf1os. \xbfDemasiado bueno para ser verdad?",choice_liability:{label:"0% es genial, firmo sin analizar los detalles",feedback:"El cr\xe9dito del vendedor al 0% a menudo compensa con un precio de venta m\xe1s alto. El costo del financiamiento est\xe1 integrado en el precio, no en la tasa."},choice_asset:{label:"Analizar si el precio incluye el costo del financiamiento y negociar ambas variables",feedback:"Un vendedor que ofrece financiamiento generalmente integra ese costo en el precio. La pregunta real: \xbfcu\xe1l ser\xeda el precio con un pago en efectivo?"}},{id:"dt_027",category:"debt",title:"Incapaz de Pagar",scenario:"Ya no puedes cumplir con tus obligaciones de deuda. \xbfPrimera acci\xf3n?",choice_liability:{label:"Esperar y esperar que la situaci\xf3n se resuelva sola",feedback:"Esperar casi siempre empeora la situaci\xf3n. Los intereses se acumulan, las penalidades se a\xf1aden, las opciones de negociaci\xf3n se reducen."},choice_asset:{label:"Contactar proactivamente a los acreedores y buscar un asesor financiero inmediatamente",feedback:"La acci\xf3n proactiva en una crisis financiera es contraintuitiva pero esencial. Los acreedores generalmente prefieren negociar antes que perseguir."}},{id:"dt_028",category:"debt",title:"Deuda Estudiantil Temprana",scenario:"Puedes elegir una universidad m\xe1s econ\xf3mica con ayuda financiera o una escuela top con $60,000 en pr\xe9stamos. \xbfCriterio de decisi\xf3n?",choice_liability:{label:"La escuela top \u2014 la red y el prestigio justifican la deuda",feedback:"El prestigio tiene valor real en algunos campos. Pero $60,000 en deuda estudiantil representa a\xf1os de reembolso que retrasan la construcci\xf3n de riqueza."},choice_asset:{label:"Calcular el ROI real de cada opci\xf3n: diferencial salarial vs costo de la deuda",feedback:"La educaci\xf3n es una inversi\xf3n \u2014 como cualquier inversi\xf3n, calcula el retorno. El diferencial salarial esperado deber\xeda cubrir el costo extra de la deuda en un plazo razonable."}},{id:"dt_029",category:"debt",title:"El Micro Pr\xe9stamo Empresarial",scenario:"Puedes pedir prestado $5,000 para lanzar tu negocio paralelo. El proyecto es s\xf3lido pero incierto. \xbfPides prestado?",choice_liability:{label:"S\xed, sin riesgo no hay recompensa, el emprendimiento requiere inversi\xf3n",feedback:"El riesgo calculado es saludable. Pero pedir prestado para un proyecto incierto significa que si falla, a\xfan debes el reembolso."},choice_asset:{label:"Bootstrap hasta validar el concepto, luego financiar el crecimiento con ingresos",feedback:"El bootstrapping fuerza la validaci\xf3n del modelo de negocio antes de comprometer capital. Un proyecto que puede crecer lentamente con sus propios ingresos es m\xe1s robusto."}},{id:"dt_030",category:"debt",title:"Buena Deuda vs Mala Deuda",scenario:"Dos oportunidades de endeudamiento: $10,000 para un auto de lujo O $10,000 para una propiedad en alquiler que genera ingresos. \xbfCu\xe1l es la diferencia?",choice_liability:{label:"Ambas son deudas, es lo mismo de todos modos",feedback:"No, Kiyosaki hace una distinci\xf3n fundamental: la buena deuda financia un activo que genera ingresos mayores que el costo de la deuda."},choice_asset:{label:"La deuda de alquiler es potencialmente 'buena' si el alquiler cubre los intereses y genera excedente",feedback:"Esta es la distinci\xf3n clave de Kiyosaki entre buena y mala deuda. Pedir prestado para adquirir un activo productivo cuyo retorno supera la tasa de inter\xe9s es una palanca leg\xedtima."}},{id:"inv_001",category:"investment",title:"Los Primeros $1,000",scenario:"Has ahorrado $1,000 para invertir por primera vez. \xbfAd\xf3nde vas?",choice_liability:{label:"Comprar una acci\xf3n de una empresa de la que todos hablan",feedback:"Seguir el hype de los medios es la forma m\xe1s efectiva de pagar de m\xe1s en la cima y vender en p\xe1nico en la ca\xedda."},choice_asset:{label:"Invertir en un fondo \xedndice diversificado para empezar sin sesgo de selecci\xf3n",feedback:"Para una primera inversi\xf3n, la m\xe1xima diversificaci\xf3n a bajo costo es estad\xedsticamente la estrategia m\xe1s s\xf3lida."}},{id:"inv_002",category:"investment",title:"El Crash del Mercado",scenario:"Los mercados caen 20%. Tu portafolio pierde $2,000 en 48 horas. \xbfQu\xe9 haces?",choice_liability:{label:"Vender antes de que empeore \u2014 mejor proteger lo que queda",feedback:"Vender durante un crash convierte una p\xe9rdida en papel en una p\xe9rdida real. Hist\xf3ricamente, los inversores que venden durante crisis casi siempre se pierden la recuperaci\xf3n."},choice_asset:{label:"No hacer nada \u2014 o comprar m\xe1s si tienes efectivo disponible",feedback:"Las crisis son ventas para inversores a largo plazo. Buffett dice ser codicioso cuando otros tienen miedo."}},{id:"inv_003",category:"investment",title:"El Soplo Caliente",scenario:"Un colega dice que tiene un 'soplo' sobre una acci\xf3n que va a explotar. \xbfInviertes?",choice_liability:{label:"S\xed, si est\xe1 seguro, es una oportunidad que no se puede perder",feedback:"Invertir en 'soplos' te expone a dos riesgos: el soplo est\xe1 equivocado (frecuente) o constituye informaci\xf3n privilegiada (riesgo legal real)."},choice_asset:{label:"No, analiza el activo t\xfa mismo o pasa \u2014 nunca por un rumor",feedback:"Una buena inversi\xf3n debe resistir el an\xe1lisis personal. Si no entiendes t\xfa mismo por qu\xe9 deber\xeda subir el activo, tampoco sabr\xe1s cu\xe1ndo vender."}},{id:"inv_004",category:"investment",title:"Diversificaci\xf3n",scenario:"Lo pusiste todo en 2 acciones que han funcionado bien durante un a\xf1o. \xbfEstrategia?",choice_liability:{label:"Mantener la concentraci\xf3n, est\xe1 funcionando y diversificar diluir\xeda las ganancias",feedback:"La concentraci\xf3n amplifica ganancias Y p\xe9rdidas. 2 acciones representan un riesgo de portafolio extremo."},choice_asset:{label:"Diversificar progresivamente hacia un portafolio de 15+ activos no correlacionados",feedback:"La diversificaci\xf3n reduce el riesgo sin necesariamente reducir el retorno esperado."}},{id:"inv_005",category:"investment",title:"Inmuebles vs Bolsa",scenario:"Tienes $30,000 ahorrados. \xbfInmueble en alquiler o bolsa de valores? \xbfCriterio principal?",choice_liability:{label:"Inmuebles, es tangible y 'en inmuebles nunca se pierde'",feedback:"Los inmuebles pueden perder valor. Y 'tangible' no es una estrategia \u2014 es un sesgo emocional."},choice_asset:{label:"Analizar retorno neto, liquidez y nivel de gesti\xf3n requerido para cada opci\xf3n",feedback:"Ninguno es universalmente superior. El retorno neto del inmueble en alquiler (renta - gastos - impuestos - tiempo) es a menudo menor de lo que parece."}},{id:"inv_006",category:"investment",title:"Sincronizaci\xf3n del Mercado",scenario:"Un analista predice que los mercados caer\xe1n en 3 meses. \xbfEsperas para invertir?",choice_liability:{label:"Esperar la ca\xedda para invertir a mejor precio",feedback:"Nadie puede predecir mercados a corto plazo de forma confiable \u2014 ni analistas, ni algoritmos. Esperar suele significar perderse ganancias que compensan las ca\xeddas anticipadas."},choice_asset:{label:"Invertir ahora con mi plan regular \u2014 el tiempo en el mercado supera al momento de entrada",feedback:"'El tiempo en el mercado supera al momento de entrada' es una de las conclusiones m\xe1s robustas en finanzas del comportamiento."}},{id:"inv_007",category:"investment",title:"Comisiones de Gesti\xf3n",scenario:"Eliges entre un fondo con 0.2% de comisiones anuales y uno con 2% pero 'gestionado activamente'. \xbfCu\xe1l elegir?",choice_liability:{label:"El 2% est\xe1 justificado si el gestor es experto",feedback:"Estad\xedsticamente, la mayor\xeda de los fondos gestionados activamente no superan su \xedndice de referencia en 10 a\xf1os, especialmente despu\xe9s de comisiones."},choice_asset:{label:"El fondo 0.2% \u2014 los estudios muestran que las bajas comisiones son el mejor predictor de rendimiento neto",feedback:"1.8% de comisiones extra anuales sobre $10,000 durante 20 a\xf1os representa una diferencia de miles de d\xf3lares."}},{id:"inv_008",category:"investment",title:"Inversi\xf3n Socialmente Responsable",scenario:"Puedes elegir entre un fondo ESG (menos diversificado, comisiones ligeramente m\xe1s altas) o un fondo \xedndice amplio. \xbfQu\xe9 priorizas?",choice_liability:{label:"ESG sin dudarlo \u2014 valores antes que retornos",feedback:"Los valores importan. Pero 'ESG' no garantiza mejores retornos ni impacto real. Verifica la metodolog\xeda ESG y las comisiones reales antes de elegir."},choice_asset:{label:"Analizar impacto real, comisiones y retorno hist\xf3rico antes de decidir",feedback:"La inversi\xf3n \xe9tica es leg\xedtima \u2014 pero merece tanto rigor como cualquier otra inversi\xf3n."}},{id:"inv_009",category:"investment",title:"DCA vs Suma Global",scenario:"Tienes $5,000 para invertir. \xbfPoner todo de una vez o distribuir en 12 meses?",choice_liability:{label:"Distribuir en 12 meses para 'reducir el riesgo de mal momento'",feedback:"Matem\xe1ticamente, la suma global (todo a la vez) supera al DCA (distribuir) 2/3 del tiempo hist\xf3ricamente, ya que los mercados suben m\xe1s de lo que caen."},choice_asset:{label:"Todo a la vez si los mercados son 'normales', DCA si est\xe1n muy altos o muy vol\xe1tiles",feedback:"Ambos tienen su lugar. La suma global gana estad\xedsticamente pero el DCA reduce el estr\xe9s emocional."}},{id:"inv_010",category:"investment",title:"Criptomonedas",scenario:"Un amigo multiplic\xf3 su inversi\xf3n en cripto por 5. \xbfQuieres entrar?",choice_liability:{label:"Invertir fuerte \u2014 el potencial de ganancias es enorme",feedback:"Los activos que pueden multiplicarse por 5 tambi\xe9n pueden dividirse por 5. Las criptos son una clase de activo de alta volatilidad adecuada para una fracci\xf3n de un portafolio (5-10% m\xe1ximo para la mayor\xeda)."},choice_asset:{label:"Si te interesa, asigna una fracci\xf3n limitada que est\xe9s preparado para perder completamente",feedback:"La regla cripto responsable: solo invierte lo que est\xe1s preparado para perder completamente. La volatilidad es real y los ciclos pueden ser muy largos."}},{id:"inv_011",category:"investment",title:"Bonos vs Acciones",scenario:"Te acercas a la jubilaci\xf3n. \xbfMantienes el 100% en acciones o reequilibras?",choice_liability:{label:"Mantener 100% acciones para maximizar ganancias hasta el final",feedback:"El riesgo de secuencia de retornos es crucial cerca de la jubilaci\xf3n: una ca\xedda pronunciada en el momento equivocado puede reducir dr\xe1sticamente la longevidad del portafolio."},choice_asset:{label:"Reequilibrar progresivamente hacia activos menos vol\xe1tiles a medida que te acercas",feedback:"La regla cl\xe1sica: (100 - edad)% en acciones. Cerca de la jubilaci\xf3n, reducir la volatilidad es tan importante como maximizar los retornos."}},{id:"inv_012",category:"investment",title:"Invertir en Lo que Conoces",scenario:"Trabajas en tecnolog\xeda. \xbfInviertes principalmente en empresas tecnol\xf3gicas?",choice_liability:{label:"S\xed, invierto donde tengo una ventaja informacional real",feedback:"Peter Lynch recomienda 'invertir en lo que conoces' \u2014 pero el sesgo de familiaridad tambi\xe9n puede llevar a sobre-concentrar en un sector."},choice_asset:{label:"Usar el conocimiento sectorial para la selecci\xf3n, pero mantener la diversificaci\xf3n global",feedback:"El conocimiento sectorial es una ventaja real \u2014 siempre que sirva para la selecci\xf3n, no para la sobre-concentraci\xf3n."}},{id:"inv_013",category:"investment",title:"Reequilibrio Anual",scenario:"Despu\xe9s de un a\xf1o de ganancias, las acciones representan el 80% de tu portafolio en lugar del 60%. \xbfReequilibras?",choice_liability:{label:"No, las acciones est\xe1n funcionando bien, d\xe9jalas crecer",feedback:"No reequilibrar permite que el perfil de riesgo derive hacia m\xe1s volatilidad de la prevista."},choice_asset:{label:"S\xed, vender algunas acciones para volver a la asignaci\xf3n objetivo",feedback:"El reequilibrio sistem\xe1tico aplica mec\xe1nicamente 'vender alto, comprar bajo'. Es una de las pocas acciones mec\xe1nicas que produce mejor rendimiento ajustado al riesgo."}},{id:"inv_014",category:"investment",title:"Inmueble en Alquiler",scenario:"Puedes comprar un apartamento por $150,000 y alquilarlo por $700/mes. \xbfEs un buen negocio?",choice_liability:{label:"$700/mes es ingreso garantizado, es excelente",feedback:"$700/mes bruto \u2260 $700 de ingreso neto. Gastos comunes, impuestos, vacancia, reparaciones, gesti\xf3n: el retorno neto puede caer al 2-3%."},choice_asset:{label:"Calcular el retorno neto (renta - todos los gastos - impuestos) y comparar alternativas",feedback:"El rendimiento real del alquiler: (renta anual - gastos - impuestos - vacancia - gesti\xf3n) / precio de compra. Una propiedad al 3% neto no es necesariamente mejor que un fondo \xedndice de bajo costo."}},{id:"inv_015",category:"investment",title:"Invertir en Tu Propia Formaci\xf3n",scenario:"Un curso avanzado cuesta $2,500 y podr\xeda potencialmente aumentar tus ingresos en $300/mes. \xbfHaces los c\xe1lculos?",choice_liability:{label:"Demasiado caro para resultados inciertos",feedback:"$2,500 / $300 = 8.3 meses de recuperaci\xf3n. Si la formaci\xf3n realmente entrega $300/mes extra, es uno de los mejores retornos de inversi\xf3n disponibles."},choice_asset:{label:"S\xed, un ROI de ~8 meses es excelente \u2014 pero verifica los resultados probados de la formaci\xf3n",feedback:"La inversi\xf3n en uno mismo es a menudo la m\xe1s rentable. Pero 'potencialmente' no es una garant\xeda. Busca testimonios verificables antes de invertir."}},{id:"inv_016",category:"investment",title:"Portafolio Concentrado vs Diversificado",scenario:"\xbfInvertir en 5 activos que entiendes perfectamente O en 50 activos a trav\xe9s de un fondo? \xbfQu\xe9 prefieres?",choice_liability:{label:"5 activos que entiendo bien, la concentraci\xf3n maximiza las ganancias",feedback:"La concentraci\xf3n puede maximizar ganancias \u2014 y p\xe9rdidas. Warren Buffett puede hacerlo porque pasa 12 horas/d\xeda en an\xe1lisis. Para la mayor\xeda de inversores, la concentraci\xf3n es riesgo excesivo."},choice_asset:{label:"50 activos diversificados para reducir el riesgo idiosincr\xe1tico de cada uno",feedback:"La diversificaci\xf3n es el \xfanico almuerzo gratis en finanzas. 50 activos no correlacionados reducen dram\xe1ticamente la volatilidad sin necesariamente reducir el retorno esperado a largo plazo."}},{id:"inv_017",category:"investment",title:"Vender Antes del Crash",scenario:"Expertos predicen una recesi\xf3n. \xbfLo vendes todo para esperar?",choice_liability:{label:"S\xed, mejor proteger las ganancias mientras espero certeza",feedback:"La certeza no existe en finanzas. Vender todo crea dos problemas: \xbfcu\xe1ndo volver a entrar? Y si el crash no ocurre, te perdiste la ganancia mientras esperabas."},choice_asset:{label:"Permanecer invertido seg\xfan mi asignaci\xf3n objetivo y quiz\xe1s aumentar ahorros para comprar la ca\xedda",feedback:"Estar listo para comprar durante una ca\xedda sin vender en p\xe1nico es la estrategia del inversor maduro."}},{id:"inv_018",category:"investment",title:"Inversi\xf3n en Start-up",scenario:"Un amigo est\xe1 lanzando una start-up y busca inversores. Te ofrece participaci\xf3n por $5,000. \xbfTe unes?",choice_liability:{label:"S\xed, las start-ups pueden retornar 10x si entras temprano",feedback:"Las estad\xedsticas: el 90% de las start-ups fracasan. Una inversi\xf3n de $5,000 en la start-up de un amigo tiene una alta probabilidad de ir a cero Y crear tensi\xf3n relacional."},choice_asset:{label:"Evaluar como cualquier inversi\xf3n: plan de negocios, tracci\xf3n, equipo y riesgo de p\xe9rdida total",feedback:"Una inversi\xf3n en start-up merece tanto rigor como una inversi\xf3n burs\xe1til. Solo invierte si aceptas la probable p\xe9rdida total y realmente entiendes el modelo de negocio."}},{id:"inv_019",category:"investment",title:"Liquidez",scenario:"Todos tus activos est\xe1n invertidos a largo plazo y surge una emergencia de $1,500. \xbfQu\xe9 haces?",choice_liability:{label:"Vender r\xe1pidamente parte de mis inversiones",feedback:"Vender activos a largo plazo para una emergencia a corto plazo es exactamente lo que el fondo de emergencia est\xe1 destinado a prevenir."},choice_asset:{label:"Usar mi fondo de emergencia l\xedquido \u2014 para eso est\xe1 exactamente",feedback:"El fondo de emergencia es el amortiguador que te permite nunca tocar las inversiones a largo plazo."}},{id:"inv_020",category:"investment",title:"ESG en Portafolio",scenario:"Descubres que una empresa de tu portafolio tiene comportamiento ambiental controvertido. \xbfQu\xe9 haces?",choice_liability:{label:"No hacer nada \u2014 es su problema, no el m\xedo",feedback:"Como accionista, eres propietario parcial de la empresa y sus pr\xe1cticas. Tu inversi\xf3n las financia indirectamente."},choice_asset:{label:"Evaluar si vender o mantener bas\xe1ndote tanto en tus valores COMO en las perspectivas financieras",feedback:"Ambos criterios pueden alinearse: las pr\xe1cticas controvertidas a menudo crean riesgos regulatorios y reputacionales a largo plazo."}},{id:"inv_021",category:"investment",title:"Dividendos vs Ganancias de Capital",scenario:"\xbfPrefieres acciones de dividendo (4%/a\xf1o) o acciones de crecimiento (0% dividendo pero 12% de crecimiento esperado)?",choice_liability:{label:"Dividendos \u2014 es ingreso regular real",feedback:"Los dividendos son atractivos pero fiscalmente menos eficientes en algunos pa\xedses. Una acci\xf3n que crece 12% crea tanto valor como 4% dividendo + 8% de crecimiento de precio."},choice_asset:{label:"Analizar retorno total (dividendo + apreciaci\xf3n) y tratamiento fiscal en tu pa\xeds",feedback:"El retorno total (dividendo + crecimiento) es la m\xe9trica verdadera. La preferencia por dividendo vs crecimiento tambi\xe9n depende de tu tramo impositivo."}},{id:"inv_022",category:"investment",title:"Invertir en Oro",scenario:"Durante incertidumbre econ\xf3mica, un asesor recomienda 'poner todo en oro'. \xbfEst\xe1s de acuerdo?",choice_liability:{label:"S\xed, el oro es un refugio seguro universal",feedback:"El oro es una reserva de valor, no un activo productivo. No genera dividendo, renta, ni inter\xe9s. A muy largo plazo, su retorno real es cercano a cero despu\xe9s de la inflaci\xf3n."},choice_asset:{label:"Asignar una fracci\xf3n limitada al oro como diversificaci\xf3n, no como estrategia principal",feedback:"El oro tiene su lugar en un portafolio diversificado como protecci\xf3n contra la inflaci\xf3n. Pero 'todo' en oro reemplaza un riesgo con otro."}},{id:"inv_023",category:"investment",title:"ETFs vs Fondos Activos",scenario:"Debes elegir entre un ETF al 0.15%/a\xf1o y un fondo activo que afirma superar el mercado al 1.5%/a\xf1o. \xbfCriterio?",choice_liability:{label:"El fondo activo si su gestor tiene buena reputaci\xf3n",feedback:"La reputaci\xf3n pasada no predice el rendimiento futuro. El 90% de los gestores activos rinden por debajo de su \xedndice durante 15 a\xf1os despu\xe9s de comisiones."},choice_asset:{label:"El ETF en la gran mayor\xeda de casos \u2014 los datos muestran la superioridad de los \xedndices a largo plazo",feedback:"Los estudios acad\xe9micos son un\xe1nimes: en 15+ a\xf1os, m\xe1s del 90% de los fondos activos rinden por debajo de su \xedndice de referencia despu\xe9s de comisiones."}},{id:"inv_024",category:"investment",title:"Asignaci\xf3n de Activos al Inicio de Carrera",scenario:"Tienes 25 a\xf1os y empiezas a invertir. \xbfQu\xe9 asignaci\xf3n elegir?",choice_liability:{label:"50% acciones, 50% bonos para 'riesgo equilibrado'",feedback:"A los 25, tienes un horizonte de inversi\xf3n de 40 a\xf1os. Los bonos sobre-diversifican hacia la baja. A esta edad, la resiliencia al ciclo favorece una asignaci\xf3n m\xe1s agresiva en activos productivos."},choice_asset:{label:"Asignaci\xf3n mayoritaria en activos productivos \u2014 el largo horizonte compensa la volatilidad",feedback:"A los 25, el tiempo es tu mejor activo. La volatilidad a corto plazo es absorbida por las d\xe9cadas que vienen. Una asignaci\xf3n adecuada a un horizonte largo maximiza el potencial de crecimiento."}},{id:"inv_025",category:"investment",title:"Noticias Financieras",scenario:"Las noticias financieras anuncian una crisis inminente. \xbfRevisas tus inversiones?",choice_liability:{label:"S\xed, monitorear diariamente para reaccionar r\xe1pido si algo va mal",feedback:"Los estudios muestran que cuanto m\xe1s revisa un inversor su portafolio, m\xe1s opera (a menudo en el momento equivocado). El monitoreo diario aumenta la ansiedad sin mejorar los resultados."},choice_asset:{label:"No, mi estrategia est\xe1 definida. Reeval\xfao a lo sumo trimestralmente",feedback:"El inversor apasionado que monitorea diariamente generalmente rinde peor que el que define su estrategia y ejecuta sin ver las noticias."}},{id:"inv_026",category:"investment",title:"Invertir a Trav\xe9s de una Estructura Dedicada",scenario:"Puedes invertir a trav\xe9s de una sociedad o holding de inversi\xf3n dedicado para optimizar tu situaci\xf3n. \xbfVale el costo de la estructura?",choice_liability:{label:"No, demasiado complejo y costoso de gestionar",feedback:"Para cantidades significativas, una estructura dedicada puede representar ventajas que superan en gran medida los costos de gesti\xf3n. Eval\xfaa seg\xfan las cantidades involucradas y las regulaciones locales."},choice_asset:{label:"Analizar el punto de equilibrio entre los costos de la estructura y las ventajas reales seg\xfan los montos y tu jurisdicci\xf3n",feedback:"Una estructura de inversi\xf3n dedicada se vuelve relevante por encima de cierto nivel de patrimonio. Por debajo de eso, los costos de creaci\xf3n y gesti\xf3n superan los beneficios \u2014 y las reglas var\xedan mucho seg\xfan el pa\xeds."}},{id:"inv_027",category:"investment",title:"Invertir en Tu Propio Negocio",scenario:"Puedes invertir $10,000 en la bolsa o en tu propio negocio. \xbfQu\xe9 eliges?",choice_liability:{label:"Bolsa \u2014 es m\xe1s segura y m\xe1s l\xedquida",feedback:"La bolsa es l\xedquida pero no tienes control sobre las empresas. Tu propio negocio ofrece control total y potencialmente los mejores retornos \u2014 pero tambi\xe9n el mayor riesgo."},choice_asset:{label:"Depende del estadio del negocio: etapa temprana va al negocio, negocio maduro \u2192 diversificar",feedback:"Las mejores oportunidades de retorno est\xe1n a menudo en tu propio negocio en etapa temprana. A medida que el negocio madura, diversificar progresivamente reduce el riesgo de concentraci\xf3n."}},{id:"inv_028",category:"investment",title:"El Portafolio Heredado",scenario:"Heredas un portafolio invertido en valores que no entiendes. \xbfMantienes o reestructuras?",choice_liability:{label:"Mantener sin cambiar \u2014 funcion\xf3 para el difunto",feedback:"Un portafolio adecuado para otra persona (diferente edad, objetivos, situaci\xf3n fiscal) no es necesariamente adecuado para los tuyos. Entender lo que posees es un m\xednimo."},choice_asset:{label:"Entender cada posici\xf3n, evaluar si coincide con mis objetivos, reestructurar si es necesario",feedback:"Heredar un portafolio merece tanto an\xe1lisis como construir el propio. Alinear las inversiones heredadas con tus propios objetivos y horizonte temporal es una responsabilidad fiduciaria hacia ti mismo."}},{id:"inv_029",category:"investment",title:"La Inversi\xf3n Clim\xe1tica",scenario:"Crees que la transici\xf3n energ\xe9tica crear\xe1 las mayores oportunidades de la d\xe9cada. \xbfC\xf3mo inviertes?",choice_liability:{label:"Todo en empresas verdes y renovables",feedback:"La convicci\xf3n tem\xe1tica puede ser correcta pero el momento y la selecci\xf3n siguen siendo cruciales. Un sector puede tener un futuro brillante pero ya tener valoraciones excesivas."},choice_asset:{label:"Asignar una fracci\xf3n del portafolio a este tema manteniendo una base diversificada",feedback:"Una convicci\xf3n tem\xe1tica justifica una sobreponderaci\xf3n, no una concentraci\xf3n total. Mantener una base diversificada protege contra la posibilidad de que el tema sea correcto pero el momento equivocado."}},{id:"inv_030",category:"investment",title:"Inmueble Directo vs REITs",scenario:"Quieres exposici\xf3n al sector inmobiliario. \xbfPropiedad directa o fondo de bienes ra\xedces listado?",choice_liability:{label:"Inmueble directo \u2014 es tangible y controlas todo",feedback:"El inmueble directo ofrece control total pero tambi\xe9n gesti\xf3n activa, baja liquidez y concentraci\xf3n geogr\xe1fica. No es un activo pasivo."},choice_asset:{label:"Evaluar ambos por liquidez, diversificaci\xf3n, retorno neto y tiempo de gesti\xf3n",feedback:"Los fondos inmobiliarios listados ofrecen diversificaci\xf3n, liquidez y gesti\xf3n cero. El inmueble directo ofrece apalancamiento, control y posibles ventajas fiscales. Ambos tienen su lugar seg\xfan el perfil."}},{id:"mn_001",category:"mindset",title:"El Reflejo E vs B",scenario:"Tienes una idea de negocio pero tu trabajo actual es estable y bien pagado. \xbfQu\xe9 haces?",choice_liability:{label:"Mantener el trabajo estable \u2014 la seguridad primero",feedback:"La mentalidad de Empleado (E) valora la seguridad del sueldo. La estabilidad tiene valor real \u2014 pero tambi\xe9n puede convertirse en un techo que impide la verdadera libertad financiera."},choice_asset:{label:"Probar la idea en paralelo por las noches/fines de semana antes de dar el salto",feedback:"El cuadrante B (Due\xf1o de Negocio) a menudo comienza fuera del horario laboral. Probar con bajo riesgo antes de saltar es la estrategia de la mayor\xeda de los emprendedores exitosos."}},{id:"mn_002",category:"mindset",title:"La Definici\xf3n de Riesgo",scenario:"Tu entorno dice 'invertir es arriesgado'. \xbfC\xf3mo reaccionas?",choice_liability:{label:"Tienen raz\xf3n \u2014 mejor mantener el dinero en una cuenta de ahorros segura",feedback:"No invertir tambi\xe9n tiene un riesgo: el riesgo de inflaci\xf3n que erosiona el poder adquisitivo y el riesgo de no alcanzar los objetivos financieros a largo plazo."},choice_asset:{label:"No invertir tambi\xe9n es un riesgo \u2014 perder poder adquisitivo y d\xe9cadas de crecimiento",feedback:"Kiyosaki dice que la educaci\xf3n financiera reduce el riesgo. Lo que es arriesgado para alguien sin formaci\xf3n no es arriesgado para alguien que entiende lo que est\xe1 haciendo."}},{id:"mn_003",category:"mindset",title:"El Dinero y las Emociones",scenario:"Tomas una mala decisi\xf3n financiera y pierdes $500. \xbfC\xf3mo lo manejas?",choice_liability:{label:"Castigarte mentalmente y evitar riesgos por meses",feedback:"La aversi\xf3n a las p\xe9rdidas es el sesgo conductual m\xe1s documentado. Un inversor que se auto-castiga despu\xe9s de un error toma peores decisiones futuras por exceso de cautela."},choice_asset:{label:"Analizar objetivamente el error, sacar una lecci\xf3n de \xe9l y seguir adelante",feedback:"Los mejores inversores cometen errores \u2014 y sacan lecciones sin ahogarse emocionalmente en ellos. La objetividad post-error es una habilidad que se cultiva."}},{id:"mn_004",category:"mindset",title:"La Riqueza Visible",scenario:"Tu vecino compra un auto de lujo. \xbfCu\xe1l es tu reacci\xf3n interior?",choice_liability:{label:"Lo logr\xf3 \u2014 puede permit\xedrselo, yo deber\xeda trabajar m\xe1s duro",feedback:"El s\xedndrome del vecino rico. Los estudios sobre millonarios muestran que la riqueza real es a menudo invisible: autos modestos, casas moderadas, riqueza en activos no exhibidos."},choice_asset:{label:"El auto no prueba nada \u2014 la riqueza real est\xe1 en activos invisibles",feedback:"'El Millonario de la Puerta de al Lado' documenta que la mayor\xeda de los verdaderamente ricos no lo exhiben. Un auto de lujo puede se\xf1alar riqueza real o deuda bien escondida."}},{id:"mn_005",category:"mindset",title:"Educaci\xf3n Financiera",scenario:"Tienes 2 horas libres este fin de semana. \xbfQu\xe9 haces?",choice_liability:{label:"Ver una serie o descansar \u2014 trabajaste duro esta semana",feedback:"El descanso es leg\xedtimo y necesario. Pero 2 horas de contenido educativo financiero por semana pueden transformar tu relaci\xf3n con el dinero en 1 a\xf1o."},choice_asset:{label:"Leer un libro o escuchar un podcast sobre finanzas e inversi\xf3n",feedback:"Kiyosaki dice que la diferencia entre los ricos y los dem\xe1s es lo que hacen con su tiempo libre. La educaci\xf3n financiera es una inversi\xf3n en uno mismo que paga de por vida."}},{id:"mn_006",category:"mindset",title:"Consejos de los Ricos",scenario:"Tienes la oportunidad de almorzar con una persona muy adinerada. \xbfQu\xe9 pregunta le haces?",choice_liability:{label:"\xbfC\xf3mo empezaste? \xbfCu\xe1l fue tu gran golpe de suerte?",feedback:"La pregunta del 'golpe de suerte' busca el atajo. Pero la mayor\xeda de las fortunas duraderas resultan de una construcci\xf3n met\xf3dica, no de un solo dado de azar."},choice_asset:{label:"\xbfQu\xe9 error me ahorrar\xedas? \xbfQu\xe9 h\xe1bito m\xe1s cambi\xf3 tu trayectoria?",feedback:"Las preguntas sobre errores y h\xe1bitos dan informaci\xf3n accionable. Los que tienen \xe9xito a largo plazo generalmente tienen sistemas y h\xe1bitos m\xe1s que golpes de suerte."}},{id:"mn_007",category:"mindset",title:"El Miedo a Empezar",scenario:"Quieres invertir pero piensas 'todav\xeda no, necesito saber m\xe1s primero'. Desde hace 2 a\xf1os. \xbfQu\xe9 haces?",choice_liability:{label:"Seguir aprendiendo \u2014 mejor estar seguro antes de empezar",feedback:"La espera perfecta es el enemigo de la realidad imperfecta. 2 a\xf1os de no inversi\xf3n tiene un costo de oportunidad real. El conocimiento perfecto no existe \u2014 la acci\xf3n con incertidumbre s\xed."},choice_asset:{label:"Empezar peque\xf1o con lo que sabes, y aprender haciendo",feedback:"Las habilidades financieras reales se desarrollan en la pr\xe1ctica, no solo en la teor\xeda. Una peque\xf1a inversi\xf3n real ense\xf1a m\xe1s que cien horas de lectura."}},{id:"mn_008",category:"mindset",title:"La Cr\xedtica de Tu Entorno",scenario:"Decides invertir y tu familia dice 'lo perder\xe1s todo'. \xbfC\xf3mo reaccionas?",choice_liability:{label:"Rendirse o mantener los planes en secreto para evitar el conflicto",feedback:"Ocultar tus proyectos financieros o ceder a la presi\xf3n social permiten que tu entorno controle tu trayectoria financiera."},choice_asset:{label:"Escuchar la preocupaci\xf3n, analizarla racionalmente, luego decidir bas\xe1ndote en tu propia investigaci\xf3n",feedback:"La cr\xedtica familiar a menudo viene del miedo, no de la experiencia. Escucha sin obedecer autom\xe1ticamente. Analiza el fondo del argumento, no la forma emocional."}},{id:"mn_009",category:"mindset",title:"Tiempo vs Dinero",scenario:"Puedes aceptar una tarea extra por $500 m\xe1s este mes. Pero tomar\xeda 20 horas de tu tiempo libre. \xbfAceptas?",choice_liability:{label:"S\xed, $500 son $500 \u2014 no se rechaza el dinero",feedback:"$500 / 20h = $25/h. La pregunta real: \xbfcu\xe1nto vale tu tiempo libre? Y \xbfpodr\xedan esas 20 horas usarse para construir algo que pague m\xe1s a largo plazo?"},choice_asset:{label:"Depende de mis finanzas y de qu\xe9 har\xeda con ese tiempo de otra manera",feedback:"El tiempo es el activo no renovable. A $25/h, la tarea puede valer la pena \u2014 o no. La decisi\xf3n debe considerar qu\xe9 podr\xedan crear 20 horas de tiempo libre alternativamente."}},{id:"mn_010",category:"mindset",title:"La Verg\xfcenza de Hablar de Dinero",scenario:"Nunca hablas de dinero con amigos por miedo a parecer 'obsesionado'. \xbfEs saludable?",choice_liability:{label:"S\xed, el dinero es un tema privado que no se debe mencionar",feedback:"El tab\xfa del dinero est\xe1 culturalmente construido \u2014 y es muy costoso. Impide compartir buenas pr\xe1cticas, descubrir errores comunes y ayudarse mutuamente financieramente."},choice_asset:{label:"No, hablar de dinero con amabilidad es una fuente de aprendizaje colectivo",feedback:"Las personas que hablan abiertamente de dinero con su c\xedrculo aprenden m\xe1s r\xe1pido y cometen menos errores. El tab\xfa financiero protege a los que venden productos caros y mal adaptados."}},{id:"mn_011",category:"mindset",title:"Identidad Financiera",scenario:"Te describes como 'alguien que no es bueno con el dinero'. \xbfEs verdad?",choice_liability:{label:"S\xed, algunas personas simplemente tienen ese don y otras no",feedback:"La identidad financiera negativa es una profec\xeda que se cumple a s\xed misma. Creer que 'no eres bueno con el dinero' impide aprender y cambiar comportamientos."},choice_asset:{label:"No, es una habilidad que se puede aprender \u2014 no un rasgo de car\xe1cter innato",feedback:"La educaci\xf3n financiera es una habilidad, no un talento innato. Kiyosaki era pobre antes de ser rico. Los buenos h\xe1bitos financieros se pueden aprender a cualquier edad."}},{id:"mn_012",category:"mindset",title:"La Envidia del \xc9xito",scenario:"Ves el \xe9xito financiero de un compa\xf1ero y sientes envidia. \xbfC\xf3mo la transformas?",choice_liability:{label:"Evitar verlos \u2014 su \xe9xito te incomoda",feedback:"La envidia evitada se estanca. No se transforma en motivaci\xf3n sin reflexi\xf3n consciente sobre lo que revela acerca de tus propios deseos y bloqueos."},choice_asset:{label:"Usar la envidia como se\xf1al para identificar lo que verdaderamente quieres y c\xf3mo obtenerlo",feedback:"La envidia es una br\xfajula emocional. Apunta hacia algo que valoras pero no tienes. Usada conscientemente, se convierte en motivaci\xf3n y clarificaci\xf3n de prioridades."}},{id:"mn_013",category:"mindset",title:"Generosidad y Riqueza",scenario:"Piensas que ser rico significa ser codicioso. \xbfEstar\xeda de acuerdo Kiyosaki?",choice_liability:{label:"S\xed, los ricos se quedan con todo para s\xed, por eso se enriquecen",feedback:"La correlaci\xf3n riqueza-codicia es un mito. Los estudios sobre millonarios muestran que la generosidad es m\xe1s prevalente entre los ricos que entre los que buscan aparentar ser ricos."},choice_asset:{label:"No, la generosidad y la riqueza son compatibles \u2014 la riqueza real viene del excedente, no de la privaci\xf3n",feedback:"Kiyosaki enfatiza que la riqueza real crea abundancia para compartir. La generosidad de una persona rica con activos productivos cuesta proporcionalmente menos que la generosidad forzada por la culpa."}},{id:"mn_014",category:"mindset",title:"Disciplina Financiera Diaria",scenario:"Tienes un presupuesto mensual que a menudo no respetas. \xbfPor qu\xe9?",choice_liability:{label:"Porque la vida es impredecible y los presupuestos son demasiado r\xedgidos",feedback:"Un presupuesto puede ser flexible sin ser ignorado. Lo impredecible puede presupuestarse (fondo de emergencia, presupuesto miscel\xe1nea). El problema real es a menudo la falta de seguimiento, no la rigidez."},choice_asset:{label:"Porque el presupuesto no est\xe1 automatizado y la fuerza de voluntad sola no es suficiente",feedback:"La fuerza de voluntad es un m\xfasculo que se agota. Los sistemas autom\xe1ticos (transferencias autom\xe1ticas, presupuestos categorizados a trav\xe9s de apps) reemplazan la fuerza de voluntad con mecanismos confiables."}},{id:"mn_015",category:"mindset",title:"El Dinero y la Felicidad",scenario:"Un amigo dice: 'El dinero no da la felicidad'. \xbfQu\xe9 respondes?",choice_liability:{label:"Tiene raz\xf3n, la felicidad viene de las relaciones y las experiencias, no del dinero",feedback:"Parcialmente cierto. Pero por debajo de cierto umbral de seguridad financiera, la falta de dinero causa estr\xe9s cr\xf3nico real que afecta directamente la felicidad."},choice_asset:{label:"El dinero no da felicidad, pero su ausencia puede crear mucho sufrimiento",feedback:"La investigaci\xf3n psicol\xf3gica muestra que el dinero aumenta la felicidad hasta un umbral de seguridad. Por debajo de ese umbral, los problemas financieros son la fuente n\xfamero uno de estr\xe9s cr\xf3nico."}},{id:"mn_016",category:"mindset",title:"La Libertad Financiera como Objetivo",scenario:"Tu objetivo a 10 a\xf1os: \xbflibertad financiera o ascenso profesional?",choice_liability:{label:"Ascenso \u2014 es concreto, medible y socialmente valorado",feedback:"El ascenso aumenta el salario \u2014 un ingreso activo. La libertad financiera apunta a ingresos pasivos. Ambos pueden coexistir, pero el ascenso solo no lleva autom\xe1ticamente a la libertad."},choice_asset:{label:"Los dos no se oponen \u2014 usar el ascenso para acelerar la libertad financiera",feedback:"El ascenso puede financiar la inversi\xf3n que lleva a la libertad. El error es gastar el aumento en vez de invertirlo. El ascenso es un acelerador, no un destino."}},{id:"mn_017",category:"mindset",title:"Paciencia y Riqueza",scenario:"Quieres resultados financieros r\xe1pidos. \xbfEs realista?",choice_liability:{label:"S\xed, con las inversiones correctas puedes enriquecerte r\xe1pido",feedback:"La b\xfasqueda de riqueza r\xe1pida es la fuente de la mayor\xeda de las estafas financieras. Los retornos excepcionales a corto plazo implican un riesgo excepcional \u2014 a menudo mal comprendido."},choice_asset:{label:"La riqueza real es lenta y predecible \u2014 los atajos casi siempre cuestan m\xe1s",feedback:"La riqueza duradera se construye durante d\xe9cadas, no meses. Las personas m\xe1s ricas del mundo se han beneficiado masivamente de d\xe9cadas de inter\xe9s compuesto, no de golpes de genio."}},{id:"mn_018",category:"mindset",title:"El Error Financiero",scenario:"Te das cuenta de que pagaste de m\xe1s por un activo. \xbfLo vendes a p\xe9rdida o lo mantienes?",choice_liability:{label:"Mantener para no 'realizar la p\xe9rdida'",feedback:"Este es el sesgo de aversi\xf3n a las p\xe9rdidas. Una p\xe9rdida en papel es una p\xe9rdida econ\xf3mica real independientemente de la columna contable. Mantener un mal activo esperando una recuperaci\xf3n es irracional si el an\xe1lisis cambia."},choice_asset:{label:"Analizar objetivamente si las perspectivas justifican mantener \u2014 independientemente del precio pagado",feedback:"El an\xe1lisis de '\xbfqu\xe9 har\xeda si no tuviera ya este activo? \xbfLo comprar\xeda hoy?' elimina el sesgo del precio pagado. La decisi\xf3n debe basarse en las perspectivas futuras, no en el costo pasado."}},{id:"mn_019",category:"mindset",title:"Trabajo Duro vs Sistema",scenario:"Crees que trabajar m\xe1s duro que todos es la clave del \xe9xito financiero. \xbfEstar\xeda de acuerdo Kiyosaki?",choice_liability:{label:"S\xed, el esfuerzo y la perseverancia son la clave absoluta",feedback:"El trabajo duro es necesario pero insuficiente. Kiyosaki se\xf1ala que los empleados que trabajan m\xe1s duro son a menudo los menos adinerados, porque su esfuerzo enriquece a la empresa, no a su propia columna de activos."},choice_asset:{label:"No, Kiyosaki insiste: el sistema correcto > el trabajo duro solo",feedback:"'Trabaja duro para ti mismo, no para alguien m\xe1s' es el mensaje central de Padre Rico Padre Pobre. Construir sistemas (negocio, activos) que trabajen sin ti es la verdadera libertad."}},{id:"mn_020",category:"mindset",title:"Comparaci\xf3n Social",scenario:"Tus amigos parecen 'tener \xe9xito' en las redes sociales. \xbfTe afecta financieramente?",choice_liability:{label:"S\xed, sus publicaciones me impulsan a gastar para aparecer al mismo nivel",feedback:"La comparaci\xf3n alimentada por las redes sociales es un poderoso impulsor del gasto impulsivo. Pagas gastos reales por una imagen virtual."},choice_asset:{label:"No, s\xe9 que las redes muestran lo mejor de todos \u2014 solo me comparo con mi yo del pasado",feedback:"Comparar tu realidad con el escaparate de otros es una ilusi\xf3n. La \xfanica comparaci\xf3n relevante: \xbfest\xe1s en mejor situaci\xf3n que hace un a\xf1o? El progreso personal es la verdadera m\xe9trica."}},{id:"mn_021",category:"mindset",title:"Delegaci\xf3n",scenario:"Gestionas todo t\xfa mismo para 'evitar estafas'. \xbfEs \xf3ptimo?",choice_liability:{label:"S\xed, nadie gestiona mi dinero mejor que yo",feedback:"La sobre-centralizaci\xf3n es un cuello de botella. Las personas muy adineradas delegan la ejecuci\xf3n mientras mantienen la supervisi\xf3n estrat\xe9gica."},choice_asset:{label:"Delegar la ejecuci\xf3n de ciertas tareas financieras manteniendo la supervisi\xf3n estrat\xe9gica",feedback:"La riqueza escalable implica delegaci\xf3n. Contador, asesor, administrador de propiedades: delegar la ejecuci\xf3n libera tu tiempo para decisiones de alto valor."}},{id:"mn_022",category:"mindset",title:"Aprender de los Errores de Otros",scenario:"Conoces a alguien que quebr\xf3. \xbfC\xf3mo usas esa experiencia?",choice_liability:{label:"Evitar todo lo que hicieron, aunque los contextos sean diferentes",feedback:"Copiar el miedo de alguien sin analizar el contexto es tan irracional como copiar sus acciones sin reflexi\xf3n. Cada situaci\xf3n financiera es \xfanica."},choice_asset:{label:"Analizar las causas estructurales del fracaso para extraer principios aplicables",feedback:"Los fracasos ajenos son lecciones gratuitas. Entender los mecanismos (apalancamiento excesivo, falta de liquidez, concentraci\xf3n) m\xe1s que las an\xe9cdotas espec\xedficas extrae principios transferibles."}},{id:"mn_023",category:"mindset",title:"El Lujo y el Valor",scenario:"Dudas sobre un art\xedculo de lujo de $800. \xbfC\xf3mo decides?",choice_liability:{label:"El lujo recompensa el trabajo duro \u2014 te lo mereces si te fijas el objetivo",feedback:"La recompensa material no es problem\xe1tica en s\xed misma \u2014 si est\xe1 presupuestada y es proporcional a los activos construidos. El problema es cuando el lujo precede a los activos."},choice_asset:{label:"Comprar si mis activos lo cubren f\xe1cilmente \u2014 no si compromete mi inversi\xf3n mensual",feedback:"La regla de Kiyosaki: los ricos compran el lujo al final, con los ingresos de sus activos. Los pobres y la clase media compran el lujo primero, con sus ingresos activos."}},{id:"mn_024",category:"mindset",title:"La Libertad del Empleado",scenario:"Tu jefe ofrece una gran promoci\xf3n con m\xe1s responsabilidad pero m\xe1s restricciones. \xbfLa aceptas?",choice_liability:{label:"S\xed, la promoci\xf3n es la progresi\xf3n natural de la carrera",feedback:"Una promoci\xf3n que te encadena m\xe1s al intercambio tiempo-por-dinero no es progreso hacia la libertad. Es progreso dentro del cuadrante E/S."},choice_asset:{label:"Aceptar si la promoci\xf3n financia un proyecto de activo \u2014 rechazar si consume m\xe1s tiempo sin crear independencia",feedback:"La promoci\xf3n no es ni buena ni mala \u2014 es lo que haces con ella. Si financia una inversi\xf3n que reduce la dependencia del salario, es apalancamiento. De lo contrario, es una cadena de oro."}},{id:"mn_025",category:"mindset",title:"Mentalidad de Abundancia",scenario:"Un competidor copia tu idea de negocio. \xbfPrimera reacci\xf3n?",choice_liability:{label:"Es una traici\xf3n \u2014 har\xe1s todo para bloquearlos",feedback:"La mentalidad de escasez ve la competencia como una amenaza existencial. La mentalidad de abundancia la ve como validaci\xf3n del mercado y una oportunidad para diferenciarse."},choice_asset:{label:"La competencia valida el mercado \u2014 enf\xf3cate en lo que te diferencia",feedback:"Un competidor que copia tu idea prueba que el mercado existe. Kiyosaki habla de abundancia: hay suficiente \xe9xito para todos. La carrera por la diferenciaci\xf3n es m\xe1s productiva que la batalla legal."}},{id:"mn_026",category:"mindset",title:"Primer Trabajo y Dinero",scenario:"Consigues tu primer trabajo a los 22. \xbfPrimera decisi\xf3n financiera?",choice_liability:{label:"Instalarse c\xf3modamente: buen apartamento, auto, salidas",feedback:"La trampa del primer sueldo: inflaci\xf3n de estilo de vida desde el inicio. Los h\xe1bitos establecidos a los 22 ser\xe1n dif\xedciles de cambiar a los 30."},choice_asset:{label:"Automatizar el 20% del salario a inversi\xf3n desde el primer mes, antes de acostumbrarse al monto",feedback:"P\xe1gate a ti mismo primero es el principio de Kiyosaki. Antes de acostumbrarse al salario completo, asignar autom\xe1ticamente una porci\xf3n a la inversi\xf3n crea un h\xe1bito fundamental."}},{id:"mn_027",category:"mindset",title:"El Respeto por el Dinero",scenario:"Recibes $20 de m\xe1s de cambio en el supermercado. \xbfQu\xe9 haces?",choice_liability:{label:"Qued\xe1rtelo \u2014 no es tu culpa que el cajero se equivocara",feedback:"Una pregunta de valores m\xe1s all\xe1 de las finanzas. Pero c\xf3mo tratas el dinero en cantidades peque\xf1as refleja tu relaci\xf3n con el dinero en general."},choice_asset:{label:"Se\xf1alarlo y devolver el cambio \u2014 la integridad aplica tambi\xe9n a las peque\xf1as cantidades",feedback:"Kiyosaki habla de respetar el dinero en todas sus formas. La integridad financiera en las cosas peque\xf1as es la base de la confianza en uno mismo en las decisiones grandes."}},{id:"mn_028",category:"mindset",title:"La Mentalidad E\u2192S\u2192B\u2192I",scenario:"Eres empleado y quieres convertirte en 'propietario de activos'. \xbfPor d\xf3nde empiezas?",choice_liability:{label:"Dejar inmediatamente el trabajo para lanzar algo",feedback:"El salto inmediato de E a B sin red de seguridad es arriesgado. La mayor\xeda de los emprendedores exitosos prepararon su transici\xf3n junto con su trabajo, no abandon\xe1ndolo abruptamente."},choice_asset:{label:"Construir progresivamente: E \u2192 proyecto paralelo S \u2192 negocio B \u2192 activos pasivos I en paralelo",feedback:"El cuadrante de Kiyosaki no es un salto \u2014 es una progresi\xf3n. Cada paso se construye sobre el anterior. La transici\xf3n se prepara mientras se est\xe1 en seguridad."}},{id:"mn_029",category:"mindset",title:"Rechazar la Mediocridad",scenario:"Te preguntas si aspirar a la libertad financiera es arrogante o poco realista. \xbfTe detiene eso?",choice_liability:{label:"Un poco s\xed \u2014 \xbfqui\xe9n soy yo para querer m\xe1s que el promedio?",feedback:"La normalizaci\xf3n de la mediocridad financiera est\xe1 culturalmente construida. Preguntar '\xbfqui\xe9n soy yo para querer m\xe1s?' es un l\xedmite mental con un costo financiero real durante d\xe9cadas."},choice_asset:{label:"No \u2014 aspirar a la libertad financiera no es arrogante, es responsable",feedback:"La libertad financiera no es un lujo \u2014 es la capacidad de elegir tu tiempo, tus proyectos y tus contribuciones. Aspirar a ella es un acto de responsabilidad hacia ti mismo y tus seres queridos."}},{id:"mn_030",category:"mindset",title:"La Definici\xf3n de \xc9xito",scenario:"\xbfC\xf3mo defines el \xe9xito financiero? \xbfAlto salario o libertad de tiempo?",choice_liability:{label:"Alto salario \u2014 el reconocimiento y la compensaci\xf3n prueban el valor",feedback:"Un alto salario es \xe9xito en el cuadrante E. Pero Kiyosaki pregunta: si dejaras de trabajar ma\xf1ana, \xbfcambiar\xeda tu estilo de vida? Si s\xed, a\xfan no eres financieramente libre."},choice_asset:{label:"Libertad de tiempo \u2014 tener activos que cubran mis gastos sin que yo trabaje",feedback:"Esta es la definici\xf3n de Kiyosaki: la libertad financiera es cuando tus activos generan m\xe1s de lo que cuestan tus gastos. El salario es un medio, no un fin. La libertad de tiempo es el destino."}},{id:"cf_031",category:"cashflow",title:"El Presupuesto de Comida Inesperado",scenario:"Te das cuenta de que gastas $400/mes en comida y delivery, $200 m\xe1s de lo planificado. \xbfQu\xe9 haces?",choice_liability:{label:"Es normal, la vida es cara \u2014 ajusto el presupuesto hacia arriba",feedback:"Ajustar el presupuesto hacia arriba para justificar un gasto no optimizado es lo inverso de la gesti\xf3n financiera. El presupuesto gu\xeda los gastos, no al rev\xe9s."},choice_asset:{label:"Identificar los $200 en fugas (deliveries impulsivos, desperdicio) y redirigirlos",feedback:"$200/mes = $2,400/a\xf1o = una inversi\xf3n significativa. Analizar fugas y redirigir a un activo es una decisi\xf3n de pocos minutos para un impacto anual mayor."}}],pt:[{id:"cf_001",category:"cashflow",title:"O B\xf4nus Inesperado",scenario:"Voc\xea recebe um b\xf4nus de $3.000 no trabalho. O que faz?",choice_liability:{label:"Comprar o \xfaltimo smartphone + fones de ouvido",feedback:"Voc\xea acabou de converter $3.000 em algo que vale $1.800 amanh\xe3. Kiyosaki chama isso de alimentar a coluna de passivos."},choice_asset:{label:"Investir em um fundo de \xedndice que gera renda mensal",feedback:"Seu b\xf4nus agora trabalha para voc\xea todo m\xeas. Esse \xe9 o reflexo de ativo que a Philia Vault te treina a construir."}},{id:"cf_002",category:"cashflow",title:"O Aumento",scenario:"Voc\xea recebe um aumento de $400/m\xeas. Como lida com o excedente?",choice_liability:{label:"Melhorar o apartamento e comprar um carro novo",feedback:"Infla\xe7\xe3o de estilo de vida: suas despesas absorveram o aumento antes de criar algo. O fluxo de caixa l\xedquido continua zero."},choice_asset:{label:"Automatizar uma transfer\xeancia de $350 para uma conta de investimentos",feedback:"A automa\xe7\xe3o \xe9 o segredo dos ricos. Voc\xea nunca v\xea o dinheiro, ele nunca \xe9 gasto \u2014 \xe9 composto."}},{id:"cf_003",category:"cashflow",title:"O B\xf4nus de Natal",scenario:"Voc\xea recebe um b\xf4nus de fim de ano de $1.500. \xc9 hora de celebrar?",choice_liability:{label:"Organizar um grande jantar natalino e presentes para todos",feedback:"Generoso, mas esse dinheiro desapareceu em 48 horas. A experi\xeancia \xe9 real, o ativo \xe9 zero."},choice_asset:{label:"Investir $1.000 e usar $500 para as festas",feedback:"Equil\xedbrio perfeito. Aproveite sem sacrificar seu futuro. A regra 80/20 aplicada a um b\xf4nus."}},{id:"cf_004",category:"cashflow",title:"A Restitui\xe7\xe3o do Imposto",scenario:"Voc\xea recebe uma restitui\xe7\xe3o de $2.200. Primeira rea\xe7\xe3o?",choice_liability:{label:"Reservar umas f\xe9rias all-inclusive \u2014 voc\xea merece",feedback:"Mem\xf3rias preciosas, mas nenhum ativo criado. Em 30 dias o dinheiro acabou e as d\xedvidas continuam."},choice_asset:{label:"Pagar uma d\xedvida de juros altos ou construir um fundo de emerg\xeancia",feedback:"Pagar d\xedvidas caras \xe9 um retorno garantizado igual \xe0 sua taxa de juros. Matematicamente imbat\xedvel no curto prazo."}},{id:"cf_005",category:"cashflow",title:"O Fundo de Anivers\xe1rio",scenario:"Seus amigos juntam $800 para seu anivers\xe1rio. O que voc\xea faz?",choice_liability:{label:"Levar todos a um bom restaurante para celebrar",feedback:"\xd3tima experi\xeancia \u2014 e o dinheiro evaporou. A coluna de ativos n\xe3o se moveu."},choice_asset:{label:"Comprar a\xe7\xf5es fracionadas de ativos produtivos",feedback:"Voc\xea transforma um presente em renda recorrente. Seus amigos te deram um ativo sem saber."}},{id:"cf_006",category:"cashflow",title:"O Extra Mensal",scenario:"Seu empregador aumenta seu vale-refei\xe7\xe3o em $150/m\xeas. Como usa a diferen\xe7a?",choice_liability:{label:"Comer em melhores restaurantes todos os dias",feedback:"Voc\xea elevou seu estilo de vida, n\xe3o seu patrim\xf4nio. A cada m\xeas, $150 desaparecem em prazer imediato."},choice_asset:{label:"Levar sua pr\xf3pria comida e investir os $150 todo m\xeas",feedback:"$150/m\xeas por 10 anos, mesmo com retorno modesto, \xe9 significativo. A consist\xeancia supera a intensidade."}},{id:"cf_007",category:"cashflow",title:"O Projeto Freelance",scenario:"Voc\xea consegue um projeto freelance de $2.500 neste m\xeas. Primeira decis\xe3o?",choice_liability:{label:"Se recompensar com compras que vinha adiando",feedback:"Voc\xea trabalhou o dobro para consumir o dobro. O hamster corre mais r\xe1pido mas a roda gira do mesmo jeito."},choice_asset:{label:"Investir 80% e usar 20% como quiser",feedback:"A regra de ouro para renda extra. 80% constr\xf3i sua liberdade, 20% recompensa o esfor\xe7o. O ciclo virtuoso come\xe7a aqui."}},{id:"cf_008",category:"cashflow",title:"A Venda de Garagem",scenario:"Voc\xea vende coisas sem uso e recebe $400. O que vem depois?",choice_liability:{label:"Aproveitar para comprar coisas novas em promo\xe7\xe3o",feedback:"Voc\xea vendeu passivos para comprar passivos. Uma troca perfeita \u2014 mas sua situa\xe7\xe3o n\xe3o mudou."},choice_asset:{label:"Depositar imediatamente na sua conta de investimentos",feedback:"Voc\xea acabou de converter passivos dormentes (coisas velhas) em capital produtivo. Isso \xe9 exatamente o que Kiyosaki ensina."}},{id:"cf_009",category:"cashflow",title:"O Cashback do Cart\xe3o",scenario:"Voc\xea acumula $250 em cashback durante o ano. O que faz?",choice_liability:{label:"Usar o cashback para um jantar especial",feedback:"Um prazer merecido, mas o dinheiro n\xe3o trabalha para voc\xea."},choice_asset:{label:"Reinvestir automaticamente o cashback em um ativo produtivo",feedback:"Mesmo $250 investidos regularmente constroem um h\xe1bito mental mais valioso do que o valor em d\xf3lares."}},{id:"cf_010",category:"cashflow",title:"O Aluguel Reduzido",scenario:"Seu propriet\xe1rio reduz o aluguel em $200/m\xeas por 6 meses. O que faz com a diferen\xe7a?",choice_liability:{label:"Se dar pequenos mimos \u2014 streaming, delivery, sa\xeddas",feedback:"A facilidade absorve o excedente. Em 6 meses, voc\xea n\xe3o ter\xe1 nada a mostrar por esses 6 meses de 'economia'."},choice_asset:{label:"Automatizar uma transfer\xeancia de $200 no dia 1\xb0 de cada m\xeas",feedback:"Voc\xea nunca viu esse dinheiro. Foi diretamente para construir seu futuro. A melhor forma de gastar menos \xe9 nunca ver o dinheiro chegar."}},{id:"cf_011",category:"cashflow",title:"A Negocia\xe7\xe3o do Seguro",scenario:"Voc\xea renegocia seu seguro e economiza $80/m\xeas. Para onde vai o excedente?",choice_liability:{label:"Incorpor\xe1-lo mentalmente ao seu or\xe7amento de 'lazer'",feedback:"A despesa invis\xedvel. Dinheiro n\xe3o alocado sempre acaba em gastos n\xe3o planejados."},choice_asset:{label:"Criar uma transfer\xeancia autom\xe1tica de $80 para um ativo neste m\xeas",feedback:"Toda economia \xe9 uma oportunidade de investimento disfar\xe7ada. Voc\xea n\xe3o cortou seu or\xe7amento \u2014 o realocou de forma inteligente."}},{id:"cf_012",category:"cashflow",title:"O Reembolso do Amigo",scenario:"Um amigo te paga de volta $300 que te devia. Reflexo?",choice_liability:{label:"A ocasi\xe3o perfeita para comprar algo que voc\xea queria",feedback:"Dinheiro inesperado sempre vai para gastos n\xe3o planejados sem uma regra preestabelecida."},choice_asset:{label:"Aplicar minha regra: todo dinheiro inesperado vai direto para ativos",feedback:"A disciplina em quantias pequenas forja h\xe1bitos para as grandes. Uma regra clara elimina a tenta\xe7\xe3o."}},{id:"cf_013",category:"cashflow",title:"A Comiss\xe3o de Vendas",scenario:"Voc\xea ganha uma comiss\xe3o excepcional de $1.800 neste m\xeas. Plano de a\xe7\xe3o?",choice_liability:{label:"Celebrar com sa\xeddas e compras impulsivas",feedback:"A celebra\xe7\xe3o \xe9 natural. Mas se cada sucesso \xe9 gasto imediatamente, o sucesso n\xe3o constr\xf3i nada."},choice_asset:{label:"Celebrar modestamente e investir o resto para renda recorrente",feedback:"A comiss\xe3o \xe9 um evento. A renda passiva que ela gera \xe9 permanente. Transforme o excepcional em estrutural."}},{id:"cf_014",category:"cashflow",title:"O Dividendo da Cooperativa",scenario:"Voc\xea recebe $120 em dividendos da sua cooperativa de compras. O que faz?",choice_liability:{label:"Usar os dividendos para as compras do m\xeas",feedback:"Dividendos gastos em consumo nunca crescem. O ciclo de crescimento \xe9 quebrado na primeira retirada."},choice_asset:{label:"Reinvestir automaticamente os dividendos para comprar mais cotas",feedback:"O juros composto em a\xe7\xe3o. Cada dividendo reinvestido gera dividendos futuros. Este \xe9 o motor da riqueza."}},{id:"cf_015",category:"cashflow",title:"Or\xe7amento de Lazer Sobrando",scenario:"Voc\xea percebe que gastou apenas $150 do seu or\xe7amento de lazer de $300 neste m\xeas. O que faz com os $150?",choice_liability:{label:"Transferir para o pr\xf3ximo m\xeas para 'recuperar'",feedback:"A mentalidade de 'or\xe7amento para gastar' transforma as economias em permiss\xe3o para gastar mais depois."},choice_asset:{label:"Transferir imediatamente os $150 n\xe3o gastos para seu investimento",feedback:"A economia feita \xe9 um ativo potencial. Agir imediatamente previne a tenta\xe7\xe3o de gast\xe1-lo 'depois'."}},{id:"cf_016",category:"cashflow",title:"Empr\xe9stimo para um Amigo",scenario:"Voc\xea tem $500 dispon\xedveis. Um amigo pede emprestado 'para passar o m\xeas'. O que faz?",choice_liability:{label:"Emprestar sem hesitar, s\xe3o fam\xedlia/amigo",feedback:"A generosidade \xe9 um valor. Mas um empr\xe9stimo informal \xe9 muitas vezes um presente disfar\xe7ado que cria tens\xe3o no relacionamento."},choice_asset:{label:"Avalie sua situa\xe7\xe3o, seja claro se \xe9 empr\xe9stimo ou presente, documente",feedback:"A clareza e honestidade protegem tanto o relacionamento quanto suas finan\xe7as. Um presente reconhecido \xe9 mais saud\xe1vel do que um empr\xe9stimo sem retorno."}},{id:"cf_017",category:"cashflow",title:"O Caf\xe9 Di\xe1rio",scenario:"Voc\xea gasta $5/dia em caf\xe9. Um colega diz que s\xe3o $150/m\xeas 'desperdi\xe7ados'. Ele tem raz\xe3o?",choice_liability:{label:"Tem raz\xe3o, vou cortar o caf\xe9 imediatamente para economizar",feedback:"A priva\xe7\xe3o total raramente \xe9 sustent\xe1vel. A gest\xe3o financeira \xe9 otimiza\xe7\xe3o, n\xe3o puni\xe7\xe3o."},choice_asset:{label:"Manter o caf\xe9 mas auditar meus gastos reais n\xe3o intencionais",feedback:"O caf\xe9 di\xe1rio \xe9 muitas vezes o \xfanico gasto consciente. Os verdadeiros vazamentos do or\xe7amento s\xe3o assinaturas esquecidas e compras impulsivas online."}},{id:"cf_018",category:"cashflow",title:"Custos Fixos em Alta",scenario:"Seus custos fixos aumentam $100/m\xeas. Como voc\xea reage?",choice_liability:{label:"Aceitar o aumento e cortar aleatoriamente em outro lugar",feedback:"Sem um plano espec\xedfico, os cortes 'aleat\xf3rios' sempre caem nas coisas erradas \u2014 nunca nos verdadeiros vazamentos."},choice_asset:{label:"Auditar todas as despesas, identificar os $100 menos \xfateis e elimin\xe1-los",feedback:"Um aumento de custos \xe9 uma oportunidade de auditoria. Voc\xea otimiza seu or\xe7amento em vez de sofr\xea-lo."}},{id:"cf_019",category:"cashflow",title:"O Projeto Paralelo Rent\xe1vel",scenario:"Seu projeto paralelo gera seus primeiros $300 l\xedquidos neste m\xeas. O que faz?",choice_liability:{label:"Finalmente se pagar \u2014 voc\xea merece",feedback:"Pagar-se de um projeto jovem desacelera seu crescimento. Empreendedores bem-sucedidos se pagam por \xfaltimo."},choice_asset:{label:"Reinvestir $250 no projeto e guardar $50 simbolicamente",feedback:"O reinvestimento precoce acelera o crescimento exponencial. $50 de 'sal\xe1rio' simb\xf3lico mant\xe9m a motiva\xe7\xe3o sem frear o projeto."}},{id:"cf_020",category:"cashflow",title:"A Auditoria de Assinaturas",scenario:"Voc\xea percebe que paga 4 servi\xe7os de streaming ($55/m\xeas no total). O que faz?",choice_liability:{label:"Manter todas as assinaturas, voc\xea usa todas 'um pouco'",feedback:"$55/m\xeas = $660/ano por conte\xfado consumido passivamente. Um ativo compar\xe1vel poderia gerar renda mensal."},choice_asset:{label:"Manter 1-2 no m\xe1ximo, redirecionar os $30-40 economizados para um investimento",feedback:"Cada assinatura in\xfatil \xe9 aluguel pago por distra\xe7\xe3o. Otimizar custos fixos libera capital de investimento real."}},{id:"cf_021",category:"cashflow",title:"Pr\xe9-pagamento vs Investimento",scenario:"Voc\xea pode pagar $500 de cr\xe9dito ao consumidor neste m\xeas. Ou investir esses $500. O que faz?",choice_liability:{label:"Investir os $500 \u2014 os retornos cobririam os juros do cr\xe9dito",feedback:"Erro matem\xe1tico cl\xe1ssico: as taxas de cr\xe9dito ao consumidor quase sempre superam os retornos de investimento. O pagamento \xe9 a prioridade."},choice_asset:{label:"Pagar o cr\xe9dito \u2014 \xe9 um retorno garantido \xe0 taxa do cr\xe9dito",feedback:"Excelente racioc\xednio. Pagar d\xedvida cara oferece um retorno garantido igual \xe0 sua taxa. O investimento mais seguro agora."}},{id:"cf_022",category:"cashflow",title:"O Or\xe7amento de Alimenta\xe7\xe3o",scenario:"Voc\xea pode reduzir sua conta de alimenta\xe7\xe3o em $80/m\xeas cozinhando mais. Vale a pena?",choice_liability:{label:"N\xe3o, o tempo que leva n\xe3o vale",feedback:"$80/m\xeas = $960/ano. Avaliar tempo/dinheiro \xe9 v\xe1lido, mas a barreira real costuma ser o h\xe1bito, n\xe3o o tempo."},choice_asset:{label:"Sim, cozinhar em lote nos fins de semana e reinvestir as economias",feedback:"Duplo benef\xedcio: melhor nutri\xe7\xe3o + $80/m\xeas extra para investir. Cozinhar em lote \xe9 uma alavanca subestimada."}},{id:"cf_023",category:"cashflow",title:"O Gadget Tecnol\xf3gico em Promo\xe7\xe3o",scenario:"Um gadget que voc\xea queria est\xe1 em promo\xe7\xe3o a $400 (de $600). \xc9 a hora?",choice_liability:{label:"Sim, -33% \xe9 uma oportunidade que n\xe3o se pode perder",feedback:"Um desconto em algo que voc\xea n\xe3o planejou comprar n\xe3o \xe9 uma economia \u2014 \xe9 um gasto disfar\xe7ado de oportunidade."},choice_asset:{label:"N\xe3o, n\xe3o estava no meu plano. Guardo os $400 para um ativo",feedback:"A disciplina financeira real \xe9 resistir a 'boas ofertas' n\xe3o planejadas. Seu plano de aloca\xe7\xe3o supera as promo\xe7\xf5es."}},{id:"cf_024",category:"cashflow",title:"A Indeniza\xe7\xe3o",scenario:"Voc\xea sai de um emprego e recebe $4.000 de indeniza\xe7\xe3o. Plano de emerg\xeancia?",choice_liability:{label:"Viajar durante a transi\xe7\xe3o de carreira",feedback:"As transi\xe7\xf5es s\xe3o caras. Usar a indeniza\xe7\xe3o para viajar sem renda cria press\xe3o financeira desnecess\xe1ria."},choice_asset:{label:"Construir um fundo de emerg\xeancia de 3 meses e investir o restante",feedback:"Seguran\xe7a primeiro. Um fundo de emerg\xeancia s\xf3lido permite melhores decis\xf5es profissionais sem a press\xe3o da necessidade."}},{id:"cf_025",category:"cashflow",title:"O Saldo Esquecido",scenario:"Voc\xea percebe que tinha $600 esquecidos em uma conta banc\xe1ria antiga. O que faz?",choice_liability:{label:"O mimo perfeito sem culpa",feedback:"O dinheiro 'encontrado' \xe9 tratado diferente do 'ganho' \u2014 \xe9 um vi\xe9s cognitivo. Na realidade tem o mesmo valor."},choice_asset:{label:"Trat\xe1-lo exatamente como qualquer outra renda e investir",feedback:"O tratamento consistente de todos os fluxos de dinheiro \xe9 a marca de um plano financeiro real. O dinheiro n\xe3o muda de valor com base em sua origem."}},{id:"cf_026",category:"cashflow",title:"O Desafio de Poupan\xe7a",scenario:"Um amigo prop\xf5e um desafio: economizar $10 a mais por semana durante um ano. Voc\xea aceita?",choice_liability:{label:"Muito pouco para mudar algo, n\xe3o vale o esfor\xe7o",feedback:"$10/semana = $520/ano. N\xe3o \xe9 o valor \u2014 \xe9 o h\xe1bito de poupan\xe7a e a identidade que est\xe1 sendo constru\xedda."},choice_asset:{label:"Sim, e automatizo uma transfer\xeancia semanal de $10 hoje",feedback:"A automa\xe7\xe3o transforma a inten\xe7\xe3o em sistema. Sistemas superam a for\xe7a de vontade ao longo do tempo."}},{id:"cf_027",category:"cashflow",title:"O Reembolso do Dep\xf3sito",scenario:"Voc\xea recebe de volta o dep\xf3sito de $1.200 ao se mudar. Reflexo imediato?",choice_liability:{label:"Usar para mobiliar e decorar o novo apartamento",feedback:"Natural \u2014 mas se o dep\xf3sito financia o novo lugar, voc\xea come\xe7a do zero financeiramente, igual a antes."},choice_asset:{label:"Investir o dep\xf3sito e usar um or\xe7amento separado (menor) para a mudan\xe7a",feedback:"Separar os fluxos evita 'consumir' os reembolsos. O dep\xf3sito recuperado \xe9 capital a preservar, n\xe3o a gastar imediatamente."}},{id:"cf_028",category:"cashflow",title:"A Heran\xe7a Modesta",scenario:"Voc\xea herda $5.000 de um parente. Como honra essa heran\xe7a?",choice_liability:{label:"Realizar uma viagem dos sonhos em sua homenagem",feedback:"A viagem pode ser significativa e bela. Mas $5.000 gastos integralmente n\xe3o criam nenhum legado financeiro."},choice_asset:{label:"Investir a maior parte, fazer um gesto simb\xf3lico pequeno com uma por\xe7\xe3o",feedback:"Voc\xea transforma esta heran\xe7a em um ativo duradouro que continua trabalhando. Essa pode ser a forma mais respeitosa de honrar o trabalho de algu\xe9m."}},{id:"cf_029",category:"cashflow",title:"O Or\xe7amento de F\xe9rias",scenario:"Voc\xea economiza para f\xe9rias ($150/m\xeas por 8 meses). Tem $1.200. Como gerencia?",choice_liability:{label:"Gastar os $1.200 completos para umas f\xe9rias memor\xe1veis",feedback:"F\xe9rias anuais acess\xedveis s\xe3o saud\xe1veis. Mas se $1.200 \xe9 toda a sua poupan\xe7a, as f\xe9rias custaram toda a sua margem de seguran\xe7a."},choice_asset:{label:"$800 de or\xe7amento de f\xe9rias, investir $400 do valor poupado",feedback:"Aproveite enquanto constr\xf3i. A disciplina de n\xe3o gastar tudo mesmo quando estava 'planejado para isso' \xe9 habilidade financeira avan\xe7ada."}},{id:"cf_030",category:"cashflow",title:"A Academia Abandonada",scenario:"Voc\xea paga $60/m\xeas pela academia mas quase n\xe3o vai. O que faz?",choice_liability:{label:"Manter a assinatura, voc\xea vai 'em breve'",feedback:"$60/m\xeas \xd7 12 = $720/ano por uma inten\xe7\xe3o. Inten\xe7\xf5es n\xe3o executadas s\xe3o as despesas mais caras."},choice_asset:{label:"Cancelar imediatamente, reinvestir os $60/m\xeas, encontrar uma alternativa gratuita",feedback:"Cortar uma despesa in\xfatil e reinvesti-la imediatamente \xe9 um dos atos de otimiza\xe7\xe3o financeira mais concretos. Aja agora, n\xe3o amanh\xe3."}},{id:"dt_001",category:"debt",title:"Cart\xe3o de Cr\xe9dito no Limite",scenario:"Seu cart\xe3o de cr\xe9dito est\xe1 a 90% do limite ($4.500 de saldo). Estrat\xe9gia?",choice_liability:{label:"Pagar o m\xednimo todo m\xeas e continuar usando o cart\xe3o",feedback:"O m\xednimo mant\xe9m o saldo quase permanente. O juro composto em d\xedvida de consumo \xe9 o exato inverso do juro composto de investimento \u2014 igualmente poderoso, mas contra voc\xea."},choice_asset:{label:"Parar todo uso, pagar o m\xe1ximo poss\xedvel todo m\xeas at\xe9 quitar",feedback:"A avalanche de d\xedvida: mire na d\xedvida mais cara primeiro. Cada d\xf3lar acima do m\xednimo \xe9 um retorno garantido \xe0 taxa do cart\xe3o."}},{id:"dt_002",category:"debt",title:"O Empr\xe9stimo Estudantil",scenario:"Voc\xea deve $25.000 em empr\xe9stimos estudantis a 5%. M\xe9todo?",choice_liability:{label:"Pagar exatamente o m\xednimo pelo prazo inteiro",feedback:"A 5%, voc\xea est\xe1 pagando corretamente o custo da sua educa\xe7\xe3o. Mas se pode investir com retornos maiores, a estrat\xe9gia do m\xednimo pode ser racional \u2014 desde que realmente invista a diferen\xe7a."},choice_asset:{label:"Pagar um excedente todo m\xeas para quitar mais r\xe1pido e reduzir o juro total",feedback:"Cada m\xeas de pagamento antecipado reduz o prazo e o juro total. \xc9 um retorno garantido de 5% em cada d\xf3lar extra pago."}},{id:"dt_003",category:"debt",title:"Consolida\xe7\xe3o de D\xedvidas",scenario:"Voc\xea tem 3 d\xedvidas em taxas diferentes. Uma empresa oferece fundi-las em um pagamento mensal menor. Voc\xea aceita?",choice_liability:{label:"Sim! Um pagamento menor, \xe9 mais simples",feedback:"Cuidado: um pagamento menor por mais tempo pode significar pagar muito mais em juro total. Calcule o custo total antes de assinar."},choice_asset:{label:"Analisar a taxa geral, dura\xe7\xe3o total e custo real antes de decidir",feedback:"A consolida\xe7\xe3o pode ser vantajosa \u2014 ou uma armadilha de marketing. A quest\xe3o real: qual \xe9 o custo total da d\xedvida consolidada vs o pagamento atual?"}},{id:"dt_004",category:"debt",title:"Cheque Especial Recorrente",scenario:"Voc\xea usa sistematicamente seu cheque especial de $500 todo m\xeas. Rea\xe7\xe3o?",choice_liability:{label:"O banco permite, ent\xe3o est\xe1 bem",feedback:"O cheque especial est\xe1 entre os cr\xe9ditos mais caros em taxa real. Um cheque especial recorrente sinaliza um problema de fluxo de caixa que piora."},choice_asset:{label:"Tratar o cheque especial como emerg\xeancia e reestruturar meu or\xe7amento imediatamente",feedback:"O cheque especial recorrente \xe9 um sinal de alarme, n\xe3o uma ferramenta de gest\xe3o. Indica que as despesas superam a renda \u2014 um problema estrutural, n\xe3o tempor\xe1rio."}},{id:"dt_005",category:"debt",title:"A Oferta 0% por 12 Meses",scenario:"Uma loja oferece parcelamento em 12 vezes sem juros em uma compra de $1.200. Voc\xea aceita?",choice_liability:{label:"Sim, 0% \xe9 de gra\xe7a, melhor aproveitar",feedback:"O 0% \xe9 real \u2014 mas apenas se voc\xea pagar ANTES do per\xedodo acabar. Depois, a taxa retroativa pode ser extremamente alta."},choice_asset:{label:"N\xe3o, se n\xe3o posso pagar \xe0 vista, provavelmente n\xe3o posso pagar",feedback:"A regra de Kiyosaki: se voc\xea precisa tomar emprestado para comprar um passivo (consumo), voc\xea n\xe3o pode pagar. O 0% torna o passivo mais acess\xedvel, n\xe3o menos passivo."}},{id:"dt_006",category:"debt",title:"O Financiamento do Carro",scenario:"Voc\xea precisa de um carro. A concession\xe1ria oferece financiamento em 60 meses com presta\xe7\xe3o 'confort\xe1vel'. Voc\xea assina?",choice_liability:{label:"Sim, a presta\xe7\xe3o cabe no meu or\xe7amento",feedback:"Um carro \xe9 um passivo que se deprecia ao sair da concession\xe1ria. Financiar um passivo por 60 meses significa pagar juro em algo que perde valor todo m\xeas."},choice_asset:{label:"Comprar um carro usado confi\xe1vel com poupan\xe7a ou financiamento de curto prazo",feedback:"Um carro usado pago \xe0 vista ou em curto prazo reduz o custo total e a press\xe3o mensal. Liberar custos fixos libera capital."}},{id:"dt_007",category:"debt",title:"Avalanche vs Bola de Neve",scenario:"Voc\xea tem v\xe1rias d\xedvidas. Qual m\xe9todo de pagamento escolhe?",choice_liability:{label:"Pagar as menores primeiro para sentir progresso",feedback:"O m\xe9todo bola de neve (a menor primeiro) \xe9 psicologicamente motivador mas matematicamente mais caro. Voc\xea paga mais juro total."},choice_asset:{label:"Pagar a d\xedvida de maior taxa primeiro (m\xe9todo avalanche)",feedback:"O m\xe9todo avalanche \xe9 matematicamente \xf3timo \u2014 voc\xea paga o menor juro total. Se mantiver a disciplina, \xe9 a estrat\xe9gia mais eficiente."}},{id:"dt_008",category:"debt",title:"Refinanciamento do Im\xf3vel",scenario:"As taxas caem e voc\xea pode refinanciar seu im\xf3vel para economizar $150/m\xeas. O que faz com a economia?",choice_liability:{label:"Elevar seu padr\xe3o de vida com este excedente mensal",feedback:"Voc\xea otimizou sua d\xedvida mas absorveu a economia no estilo de vida. A otimiza\xe7\xe3o s\xf3 cria riqueza se for reinvestida."},choice_asset:{label:"Reinvestir os $150/m\xeas economizados em um ativo produtivo",feedback:"Otimiza\xe7\xe3o de d\xedvida + reinvestimento imediato da economia: dupla alavanca de riqueza. Voc\xea trabalha menos e constr\xf3i mais em paralelo."}},{id:"dt_009",category:"debt",title:"Pegar Emprestado para Investir",scenario:"Voc\xea pode tomar $10.000 emprestado a 4% para investir em um ativo que teoricamente rende 8%. Voc\xea faz isso?",choice_liability:{label:"Sim, o spread de 4% est\xe1 a meu favor",feedback:"A alavancagem amplifica ganhos E perdas. Um retorno de 8% \xe9 uma hip\xf3tese, n\xe3o uma garantia. Se o ativo cair, voc\xea ainda deve o empr\xe9stimo a 4%."},choice_asset:{label:"Esperar at\xe9 ter fundos pr\xf3prios, ou limitar estritamente a alavancagem",feedback:"A alavancagem de investimento \xe9 uma ferramenta avan\xe7ada a ser usada com cuidado. Para um iniciante, zero alavancagem \xe9 uma estrat\xe9gia em si \u2014 seguran\xe7a antes da otimiza\xe7\xe3o."}},{id:"dt_010",category:"debt",title:"Compre Agora Pague Depois",scenario:"Um servi\xe7o online oferece 'compre agora, pague em 6 meses'. Voc\xea usa esta op\xe7\xe3o?",choice_liability:{label:"Sim, me d\xe1 tempo para juntar os fundos",feedback:"'Pague em 6 meses' geralmente significa atrasar uma compra que voc\xea n\xe3o pode pagar agora. Em 6 meses, outras despesas se acumulam \u2014 e a d\xedvida permanece."},choice_asset:{label:"N\xe3o, se n\xe3o posso pagar agora, n\xe3o compro agora",feedback:"A disciplina do pagamento imediato \xe9 um poderoso filtro contra compras impulsivas. Se n\xe3o pode pagar hoje, a compra pode n\xe3o ser prioridade."}},{id:"dt_011",category:"debt",title:"Ser Fiador",scenario:"Um amigo pr\xf3ximo pede que voc\xea co-assine o financiamento da casa dele. Voc\xea aceita?",choice_liability:{label:"Sim, \xe9 fam\xedlia/amigo, confio neles",feedback:"Ser fiador significa se comprometer legalmente a pagar a d\xedvida se o devedor n\xe3o puder. A confian\xe7a n\xe3o protege contra os acidentes da vida."},choice_asset:{label:"N\xe3o, ou apenas ap\xf3s entender todas as implica\xe7\xf5es legais e financeiras",feedback:"Ser co-signat\xe1rio \xe9 um compromisso financeiro real que pode afetar sua capacidade de cr\xe9dito futura. Uma decis\xe3o que merece an\xe1lise, n\xe3o apenas amor."}},{id:"dt_012",category:"debt",title:"A Compra de D\xedvida",scenario:"Uma empresa oferece comprar todos os seus empr\xe9stimos para reduzir seu pagamento em $300. Voc\xea aceita sem hesitar?",choice_liability:{label:"Sim, $300 a menos por m\xeas \xe9 exatamente o que preciso",feedback:"Um pagamento menor por mais tempo pode custar milhares a mais no total. Calcule o custo total, n\xe3o apenas a presta\xe7\xe3o."},choice_asset:{label:"Primeiro calcular o custo total antes e depois da compra",feedback:"A presta\xe7\xe3o mensal \xe9 apenas um dado. O custo total (valor \xd7 prazo \xd7 taxa) \xe9 a \xfanica m\xe9trica que importa para comparar ofertas de empr\xe9stimos."}},{id:"dt_013",category:"debt",title:"A D\xedvida Familiar",scenario:"Voc\xea deve dinheiro a um parente. Eles n\xe3o pressionam. Voc\xea prioriza pagar?",choice_liability:{label:"N\xe3o, n\xe3o est\xe3o pressionando, vou pagar outras d\xedvidas primeiro",feedback:"Financeiramente l\xf3gico se a d\xedvida familiar est\xe1 a 0%. Mas n\xe3o reembolsar pode criar uma tens\xe3o relacional invis\xedvel com um custo humano real."},choice_asset:{label:"Sim, reembolso com um plano claro para n\xe3o deixar a d\xedvida contaminar o relacionamento",feedback:"A clareza relacional e financeira est\xe3o ligadas. Um plano de reembolso formalizado, mesmo sem juros, respeita a confian\xe7a dada e mant\xe9m o relacionamento saud\xe1vel."}},{id:"dt_014",category:"debt",title:"O Cart\xe3o de Cr\xe9dito Rotativo",scenario:"O banco te envia um cart\xe3o de cr\xe9dito rotativo com limite de $2.000. Voc\xea o ativa?",choice_liability:{label:"Sim, \xe9 \xfatil para emerg\xeancias e gastos inesperados",feedback:"O cr\xe9dito rotativo \xe9 um dos produtos financeiros mais caros. Um fundo de emerg\xeancia real em uma conta poupan\xe7a cumpre o mesmo papel com zero juros."},choice_asset:{label:"N\xe3o, construo um fundo de emerg\xeancia para nunca precisar de cr\xe9dito rotativo",feedback:"O objetivo final: nunca precisar de cr\xe9dito de emerg\xeancia. Um fundo de emerg\xeancia de 3-6 meses de despesas \xe9 o melhor produto financeiro que existe."}},{id:"dt_015",category:"debt",title:"Empr\xe9stimo a Amigo com Juros",scenario:"Voc\xea tem $1.000 dispon\xedveis. Um amigo prop\xf5e tom\xe1-los emprestado a 5% de juros. Voc\xea prefere...",choice_liability:{label:"Emprestar os $1.000 a 5% para o amigo",feedback:"5% de juro garantido parece atraente. Mas se o amigo n\xe3o pagar, voc\xea perde tanto o dinheiro QUANTO o amigo."},choice_asset:{label:"Investir os $1.000 em um ativo diversificado para evitar misturar dinheiro e amizade",feedback:"Kiyosaki aconselha nunca misturar dinheiro e rela\xe7\xf5es emocionais sem regras muito claras. Um investimento em um ativo mant\xe9m a amizade pura."}},{id:"dt_016",category:"debt",title:"Financiamento vs Aluguel",scenario:"Voc\xea est\xe1 em d\xfavida entre comprar (financiamento $1.400/m\xeas) e alugar ($1.100/m\xeas). Crit\xe9rio de decis\xe3o?",choice_liability:{label:"Comprar \u2014 custa mais mas \xe9 investimento, sempre melhor",feedback:"O im\xf3vel \xe9 frequentemente apresentado como ativo, mas Kiyosaki matiza: sua resid\xeancia principal n\xe3o gera renda. Pode at\xe9 ser um passivo se custar mais do que produz."},choice_asset:{label:"Comparar o custo total de propriedade vs aluguel + investir a diferen\xe7a",feedback:"A quest\xe3o real: se eu investir os $300 mensais de diferen\xe7a por 20 anos, qual \xe9 o valor final vs a valoriza\xe7\xe3o imobili\xe1ria esperada? A resposta n\xe3o \xe9 \xf3bvia."}},{id:"dt_017",category:"debt",title:"O Cr\xe9dito de Consumo F\xe1cil",scenario:"Um vendedor oferece cr\xe9dito 'f\xe1cil' a $50/m\xeas para uma compra de $600. Voc\xea aceita?",choice_liability:{label:"$50/m\xeas n\xe3o \xe9 nada, \xe9 acess\xedvel",feedback:"$50/m\xeas pode parecer insignificante, mas cada cr\xe9dito de consumo reduz sua capacidade de poupan\xe7a e potencialmente sua capacidade de cr\xe9dito futuro para ativos."},choice_asset:{label:"Recusar e esperar at\xe9 economizar os $600 para pagar \xe0 vista",feedback:"A disciplina de esperar: se voc\xea economiza $100/m\xeas, tem os $600 em 6 meses sem juros. A paci\xeancia \xe9 o primeiro capital do investidor."}},{id:"dt_018",category:"debt",title:"Renegocia\xe7\xe3o de Taxa",scenario:"Voc\xea pode dedicar 2 horas a renegociar seu financiamento para potencialmente economizar $5.000 ao longo do prazo. Voc\xea faz?",choice_liability:{label:"2 horas por $5.000 hipot\xe9ticos \xe9 esfor\xe7o demais",feedback:"$5.000 / 2h = $2.500/hora de valor potencial. A renegocia\xe7\xe3o \xe9 muitas vezes a a\xe7\xe3o financeira com melhor ROI dispon\xedvel para um indiv\xedduo."},choice_asset:{label:"Sim, imediatamente. Provavelmente \xe9 a melhor hora da minha vida financeira",feedback:"A renegocia\xe7\xe3o de financiamento \xe9 a alavanca financeira mais acess\xedvel e mais ignorada. Uma hora pode valer milhares \u2014 e nunca \xe9 tarde demais."}},{id:"dt_019",category:"debt",title:"Saldo do Cart\xe3o no Fim do M\xeas",scenario:"Voc\xea n\xe3o consegue pagar completamente o saldo do cart\xe3o neste m\xeas. Quanto voc\xea paga?",choice_liability:{label:"O m\xednimo obrigat\xf3rio, vou compensar no m\xeas seguinte",feedback:"Pagar o m\xednimo ativa o juro composto contra voc\xea. 'M\xeas seguinte' quase nunca chega para saldos pequenos \u2014 que crescem silenciosamente."},choice_asset:{label:"O m\xe1ximo poss\xedvel, e bloqueio o cart\xe3o para n\xe3o piorar",feedback:"Pagar o m\xe1ximo poss\xedvel + bloquear o uso = a\xe7\xe3o dupla. Para o sangramento E acelera a recupera\xe7\xe3o."}},{id:"dt_020",category:"debt",title:"Cr\xe9dito para Treinamento",scenario:"Um curso custa $3.000. Voc\xea pode pagar \xe0 vista ou usar cr\xe9dito a 6%. O que faz?",choice_liability:{label:"Usar cr\xe9dito para manter o dinheiro dispon\xedvel para outra coisa",feedback:"Se 'outra coisa' significa gast\xe1-lo, o cr\xe9dito a 6% \xe9 a decis\xe3o errada. Se 'outra coisa' significa investi-lo a mais de 6%, a matem\xe1tica pode favorecer o cr\xe9dito."},choice_asset:{label:"Pagar \xe0 vista se o treinamento tem ROI claro e mensur\xe1vel na minha renda",feedback:"O treinamento \xe9 um ativo se aumenta mensuravelmente sua capacidade de renda. \xc0 vista ou cr\xe9dito depende do ROI esperado e da sua taxa de juros alternativa."}},{id:"dt_021",category:"debt",title:"D\xedvida vs Reserva de Emerg\xeancia",scenario:"Voc\xea tem $2.000 poupados e $1.500 em d\xedvida a 18%. Usa a poupan\xe7a para pagar?",choice_liability:{label:"N\xe3o, manter a poupan\xe7a para emerg\xeancias, \xe9 seguran\xe7a",feedback:"Manter $2.000 a ~1% enquanto paga 18% em $1.500 te custa ~$250/ano l\xedquido. A 'seguran\xe7a' tem um pre\xe7o real."},choice_asset:{label:"Sim, pagar $1.500 e manter $500 como reserva m\xednima de emerg\xeancia",feedback:"Pagar d\xedvida a 18% com poupan\xe7a a 1% \xe9 um ganho l\xedquido de 17%. Mantenha um buffer m\xednimo de emerg\xeancia ($500), pague o restante."}},{id:"dt_022",category:"debt",title:"Seguro de Cr\xe9dito",scenario:"O banco oferece seguro de cr\xe9dito a $40/m\xeas para cobrir seus pagamentos em caso de acidente. Voc\xea contrata?",choice_liability:{label:"Sim, \xe9 tranquilizador e o banco recomenda",feedback:"O seguro de cr\xe9dito vendido por bancos \xe9 muitas vezes caro e mal adaptado. Compare com seguros independentes ou um fundo de emerg\xeancia autogerenciado."},choice_asset:{label:"Avaliar a necessidade real e comparar com alternativas independentes",feedback:"O seguro pode ser \xfatil \u2014 mas o pre\xe7o e as condi\xe7\xf5es variam enormemente. A alternativa geralmente mais barata: um fundo de emerg\xeancia equivalente a 3-6 meses de encargos."}},{id:"dt_023",category:"debt",title:"Pediu Emprestado para Investir",scenario:"Um amigo conta que pediu emprestado para comprar ativos especulativos. Est\xe1 ganhando muito. Voc\xea faz o mesmo?",choice_liability:{label:"Se ele consegue, eu tamb\xe9m consigo \u2014 os ganhos parecem reais",feedback:"Vi\xe9s de confirma\xe7\xe3o: voc\xea v\xea os ganhos, n\xe3o as perdas. As pessoas n\xe3o te contam sobre os investimentos alavancados que deram errado."},choice_asset:{label:"Parabenizar o amigo, mas analisar o risco real da alavancagem antes de copiar",feedback:"A alavancagem amplifica nas duas dire\xe7\xf5es. Seu amigo pode ter acertado por sorte tanto quanto por estrat\xe9gia. Analise seu pr\xf3prio perfil de risco primeiro."}},{id:"dt_024",category:"debt",title:"Pagamento Extra do Im\xf3vel vs Investir",scenario:"Voc\xea pode pagar $500/m\xeas extra no seu financiamento (a 3%) OU investir esses $500. O que faz?",choice_liability:{label:"Pagar o im\xf3vel mais r\xe1pido para ficar 'livre de d\xedvidas' logo",feedback:"A 3% de financiamento, o pagamento antecipado oferece um retorno garantido de 3%. Excelente em ambientes de baixo rendimento, menos \xf3timo se voc\xea puder investir a 7%+."},choice_asset:{label:"Investir os $500 se os retornos esperados superarem significativamente 3%",feedback:"Matematicamente, se voc\xea pode investir a longo prazo com retorno esperado de 6-8% e seu financiamento \xe9 a 3%, o investimento vence. Mas \xe9 arriscado \u2014 o 3% \xe9 garantido, o 7% n\xe3o \xe9."}},{id:"dt_025",category:"debt",title:"Liquida\xe7\xe3o de D\xedvida",scenario:"Uma empresa oferece comprar sua d\xedvida por 50 centavos por d\xf3lar. Voc\xea aceita?",choice_liability:{label:"Sim! Pagar 50% da minha d\xedvida \xe9 o melhor acordo poss\xedvel",feedback:"Uma liquida\xe7\xe3o de 50% pode impactar seu hist\xf3rico de cr\xe9dito e rela\xe7\xe3o com credores. Tamb\xe9m verifique as poss\xedveis implica\xe7\xf5es fiscais."},choice_asset:{label:"Analisar implica\xe7\xf5es legais, fiscais e de score de cr\xe9dito antes de decidir",feedback:"A liquida\xe7\xe3o de d\xedvida pode ser uma solu\xe7\xe3o vi\xe1vel mas complexa. Entender todas as consequ\xeancias \u2014 particularmente na capacidade de cr\xe9dito futura \u2014 \xe9 essencial."}},{id:"dt_026",category:"debt",title:"O Cr\xe9dito Gratuito do Vendedor",scenario:"Um vendedor imobili\xe1rio oferece financiamento a 0% por 2 anos. Bom demais para ser verdade?",choice_liability:{label:"0% \xe9 \xf3timo, assino sem analisar os detalhes",feedback:"O cr\xe9dito do vendedor a 0% geralmente compensa com um pre\xe7o de venda mais alto. O custo do financiamento est\xe1 embutido no pre\xe7o, n\xe3o na taxa."},choice_asset:{label:"Analisar se o pre\xe7o inclui o custo do financiamento e negociar ambas as vari\xe1veis",feedback:"Um vendedor que oferece financiamento geralmente embute esse custo no pre\xe7o. A quest\xe3o real: qual seria o pre\xe7o com pagamento \xe0 vista?"}},{id:"dt_027",category:"debt",title:"Incapaz de Pagar",scenario:"Voc\xea n\xe3o consegue mais cumprir suas obriga\xe7\xf5es de d\xedvida. Primeira a\xe7\xe3o?",choice_liability:{label:"Esperar e torcer para a situa\xe7\xe3o se resolver sozinha",feedback:"Esperar quase sempre piora a situa\xe7\xe3o. Os juros se acumulam, as penalidades aumentam, as op\xe7\xf5es de negocia\xe7\xe3o diminuem."},choice_asset:{label:"Contatar proativamente os credores e buscar um consultor financeiro imediatamente",feedback:"A a\xe7\xe3o proativa em uma crise financeira \xe9 contraintuitiva mas essencial. Os credores geralmente preferem negociar a processar."}},{id:"dt_028",category:"debt",title:"D\xedvida Estudantil Inicial",scenario:"Voc\xea pode escolher uma universidade mais barata com bolsa ou uma escola top com $60.000 em empr\xe9stimos. Crit\xe9rio de decis\xe3o?",choice_liability:{label:"A escola top \u2014 a rede e o prest\xedgio justificam a d\xedvida",feedback:"O prest\xedgio tem valor real em alguns campos. Mas $60.000 em d\xedvida estudantil representa anos de pagamento que atrasan a constru\xe7\xe3o de riqueza."},choice_asset:{label:"Calcular o ROI real de cada op\xe7\xe3o: diferencial salarial vs custo da d\xedvida",feedback:"A educa\xe7\xe3o \xe9 um investimento \u2014 como qualquer investimento, calcule o retorno. O diferencial salarial esperado deve cobrir o custo extra da d\xedvida em prazo razo\xe1vel."}},{id:"dt_029",category:"debt",title:"O Micro Empr\xe9stimo Empresarial",scenario:"Voc\xea pode tomar $5.000 emprestado para lan\xe7ar seu neg\xf3cio paralelo. O projeto \xe9 s\xf3lido mas incerto. Voc\xea pede?",choice_liability:{label:"Sim, sem risco sem recompensa, o empreendedorismo exige investimento",feedback:"O risco calculado \xe9 saud\xe1vel. Mas pedir emprestado para um projeto incerto significa que se falhar, voc\xea ainda deve o pagamento."},choice_asset:{label:"Bootstrapar at\xe9 validar o conceito, depois financiar o crescimento com receitas",feedback:"O bootstrapping for\xe7a a valida\xe7\xe3o do modelo de neg\xf3cio antes de comprometer capital. Um projeto que pode crescer lentamente com suas pr\xf3prias receitas \xe9 mais robusto."}},{id:"dt_030",category:"debt",title:"Boa D\xedvida vs M\xe1 D\xedvida",scenario:"Duas oportunidades de endividamento: $10.000 para um carro de luxo OU $10.000 para um im\xf3vel que gera renda. Qual \xe9 a diferen\xe7a?",choice_liability:{label:"Ambas s\xe3o d\xedvidas, \xe9 a mesma coisa de qualquer forma",feedback:"N\xe3o, Kiyosaki faz uma distin\xe7\xe3o fundamental: a boa d\xedvida financia um ativo que gera renda maior que o custo da d\xedvida. A m\xe1 d\xedvida financia um passivo."},choice_asset:{label:"A d\xedvida de aluguel \xe9 potencialmente 'boa' se o aluguel cobre os juros e gera excedente",feedback:"Esta \xe9 a distin\xe7\xe3o-chave de Kiyosaki entre boa e m\xe1 d\xedvida. Tomar emprestado para adquirir um ativo produtivo cujo retorno supera a taxa de juros \xe9 uma alavanca leg\xedtima."}},{id:"inv_001",category:"investment",title:"Os Primeiros $1.000",scenario:"Voc\xea economizou $1.000 para investir pela primeira vez. Para onde vai?",choice_liability:{label:"Comprar a\xe7\xf5es de uma empresa de que todo mundo fala",feedback:"Seguir o hype da m\xeddia \xe9 a forma mais eficaz de pagar caro no topo e vender em p\xe2nico na queda. A popularidade frequentemente precede a bolha."},choice_asset:{label:"Investir em um fundo de \xedndice diversificado para come\xe7ar sem vi\xe9s de sele\xe7\xe3o",feedback:"Para um primeiro investimento, a m\xe1xima diversifica\xe7\xe3o a baixo custo \xe9 estatisticamente a estrat\xe9gia mais s\xf3lida."}},{id:"inv_002",category:"investment",title:"A Queda do Mercado",scenario:"Os mercados caem 20%. Sua carteira perde $2.000 em 48 horas. O que faz?",choice_liability:{label:"Vender antes de piorar \u2014 melhor proteger o que sobrou",feedback:"Vender durante uma queda transforma uma perda no papel em uma perda real. Historicamente, investidores que vendem em crises quase sempre perdem a recupera\xe7\xe3o."},choice_asset:{label:"N\xe3o fazer nada \u2014 ou comprar mais se tiver dinheiro dispon\xedvel",feedback:"Crises s\xe3o promo\xe7\xf5es para investidores de longo prazo. Buffett diz para ser ganancioso quando os outros t\xeam medo."}},{id:"inv_003",category:"investment",title:"A Dica Quente",scenario:"Um colega diz que tem uma 'dica' sobre uma a\xe7\xe3o que vai explodir. Voc\xea investe?",choice_liability:{label:"Sim, se ele est\xe1 seguro, \xe9 oportunidade que n\xe3o se pode perder",feedback:"Investir em 'dicas' te exp\xf5e a dois riscos: a dica est\xe1 errada (frequente) ou constitui uso de informa\xe7\xe3o privilegiada (risco legal real)."},choice_asset:{label:"N\xe3o, analise o ativo voc\xea mesmo ou passe \u2014 nunca por um rumor",feedback:"Um bom investimento deve resistir \xe0 an\xe1lise pessoal. Se voc\xea n\xe3o entende por que o ativo deve subir, tamb\xe9m n\xe3o vai saber quando vender."}},{id:"inv_004",category:"investment",title:"Diversifica\xe7\xe3o",scenario:"Voc\xea colocou tudo em 2 a\xe7\xf5es que se sa\xedram bem por um ano. Estrat\xe9gia?",choice_liability:{label:"Manter a concentra\xe7\xe3o, est\xe1 funcionando e diversificar diluiria os ganhos",feedback:"A concentra\xe7\xe3o amplifica ganhos E perdas. 2 a\xe7\xf5es representam risco extremo de carteira."},choice_asset:{label:"Diversificar progressivamente para uma carteira de 15+ ativos n\xe3o correlacionados",feedback:"A diversifica\xe7\xe3o reduz o risco sem necessariamente reduzir o retorno esperado."}},{id:"inv_005",category:"investment",title:"Im\xf3veis vs Bolsa",scenario:"Voc\xea tem $30.000 poupados. Im\xf3vel para alugar ou bolsa de valores? Crit\xe9rio principal?",choice_liability:{label:"Im\xf3vel, \xe9 tang\xedvel e 'em im\xf3vel nunca se perde'",feedback:"Im\xf3veis podem perder valor. E 'tang\xedvel' n\xe3o \xe9 uma estrat\xe9gia \u2014 \xe9 um vi\xe9s emocional."},choice_asset:{label:"Analisar retorno l\xedquido, liquidez e n\xedvel de gest\xe3o necess\xe1rio para cada op\xe7\xe3o",feedback:"Nenhum \xe9 universalmente superior. O retorno l\xedquido do im\xf3vel alugado (aluguel - despesas - impostos - tempo) \xe9 frequentemente menor do que parece."}},{id:"inv_006",category:"investment",title:"Timing do Mercado",scenario:"Um analista prev\xea que os mercados cair\xe3o em 3 meses. Voc\xea espera para investir?",choice_liability:{label:"Esperar a queda para investir a um pre\xe7o melhor",feedback:"Ningu\xe9m pode prever mercados de curto prazo de forma confi\xe1vel \u2014 nem analistas, nem algoritmos. Esperar geralmente significa perder ganhos que compensam as quedas antecipadas."},choice_asset:{label:"Investir agora com meu plano regular \u2014 o tempo no mercado supera o momento de entrada",feedback:"'O tempo no mercado supera o momento de entrada' \xe9 uma das conclus\xf5es mais robustas em finan\xe7as comportamentais."}},{id:"inv_007",category:"investment",title:"Taxas de Administra\xe7\xe3o",scenario:"Voc\xea est\xe1 escolhendo entre um fundo com 0,2%/ano de taxa e um com 2% mas 'gerenciado ativamente'. Qual escolher?",choice_liability:{label:"O 2% \xe9 justificado se o gestor for especialista",feedback:"Estatisticamente, a maioria dos fundos gerenciados ativamente tem desempenho inferior ao \xedndice em 10 anos, especialmente depois das taxas."},choice_asset:{label:"O fundo 0,2% \u2014 estudos mostram que taxas baixas s\xe3o o melhor preditor de desempenho l\xedquido",feedback:"1,8% de taxa extra anual em $10.000 por 20 anos representa uma diferen\xe7a de milhares de d\xf3lares. Taxas baixas s\xe3o uma das poucas vantagens que um investidor individual pode controlar."}},{id:"inv_008",category:"investment",title:"Investimento Socialmente Respons\xe1vel",scenario:"Voc\xea pode escolher entre um fundo ESG (menos diversificado, taxas ligeiramente mais altas) ou um fundo de \xedndice amplo. O que prioriza?",choice_liability:{label:"ESG sem hesitar \u2014 valores antes dos retornos",feedback:"Os valores importam. Mas 'ESG' n\xe3o garante melhores retornos nem impacto real. Verifique a metodologia ESG e as taxas reais antes de escolher."},choice_asset:{label:"Analisar impacto real, taxas e retorno hist\xf3rico antes de decidir",feedback:"O investimento \xe9tico \xe9 leg\xedtimo \u2014 mas merece tanto rigor quanto qualquer outro investimento."}},{id:"inv_009",category:"investment",title:"DCA vs Montante Total",scenario:"Voc\xea tem $5.000 para investir. Colocar tudo de uma vez ou distribuir em 12 meses?",choice_liability:{label:"Distribuir em 12 meses para 'reduzir o risco de mal momento'",feedback:"Matematicamente, o montante total (tudo de uma vez) supera o DCA (distribuir) 2/3 do tempo historicamente, pois os mercados sobem mais do que caem."},choice_asset:{label:"Tudo de uma vez se os mercados s\xe3o 'normais', DCA se estiverem muito altos ou vol\xe1teis",feedback:"Ambos t\xeam seu lugar. O montante total vence estatisticamente mas o DCA reduz o estresse emocional."}},{id:"inv_010",category:"investment",title:"Criptomoedas",scenario:"Um amigo multiplicou seu investimento em cripto por 5. Voc\xea quer entrar?",choice_liability:{label:"Investir pesado \u2014 o potencial de ganhos \xe9 enorme",feedback:"Ativos que podem multiplicar por 5 tamb\xe9m podem dividir por 5. Criptos s\xe3o uma classe de ativo de alta volatilidade adequada para uma fra\xe7\xe3o da carteira (5-10% no m\xe1ximo para a maioria)."},choice_asset:{label:"Se interessado, alocar uma fra\xe7\xe3o limitada que voc\xea esteja preparado para perder completamente",feedback:"A regra respons\xe1vel das criptos: invista apenas o que est\xe1 preparado para perder completamente. A volatilidade \xe9 real e os ciclos podem ser muito longos."}},{id:"inv_011",category:"investment",title:"T\xedtulos vs A\xe7\xf5es",scenario:"Voc\xea est\xe1 se aproximando da aposentadoria. Mant\xe9m 100% em a\xe7\xf5es ou reequilibra?",choice_liability:{label:"Manter 100% em a\xe7\xf5es para maximizar ganhos at\xe9 o final",feedback:"O risco de sequ\xeancia de retornos \xe9 crucial perto da aposentadoria: uma queda abrupta no momento errado pode reduzir drasticamente a longevidade da carteira."},choice_asset:{label:"Reequilibrar progressivamente para ativos menos vol\xe1teis ao se aproximar",feedback:"A regra cl\xe1ssica: (100 - idade)% em a\xe7\xf5es. Perto da aposentadoria, reduzir a volatilidade \xe9 t\xe3o importante quanto maximizar os retornos."}},{id:"inv_012",category:"investment",title:"Investir no Que Voc\xea Conhece",scenario:"Voc\xea trabalha com tecnologia. Investe principalmente em empresas de tecnologia?",choice_liability:{label:"Sim, invisto onde tenho uma vantagem informacional real",feedback:"Peter Lynch recomenda 'investir no que voc\xea conhece' \u2014 mas o vi\xe9s de familiaridade tamb\xe9m pode levar \xe0 over-concentra\xe7\xe3o em um setor."},choice_asset:{label:"Usar o conhecimento setorial para sele\xe7\xe3o, mas manter diversifica\xe7\xe3o global",feedback:"O conhecimento setorial \xe9 uma vantagem real \u2014 desde que sirva para sele\xe7\xe3o, n\xe3o para over-concentra\xe7\xe3o."}},{id:"inv_013",category:"investment",title:"Reequil\xedbrio Anual",scenario:"Ap\xf3s um ano de ganhos, as a\xe7\xf5es representam 80% da sua carteira em vez de 60%. Voc\xea reequilibra?",choice_liability:{label:"N\xe3o, as a\xe7\xf5es est\xe3o indo bem, deixa crescer",feedback:"N\xe3o reequilibrar permite que o perfil de risco derive para mais volatilidade do que o pretendido."},choice_asset:{label:"Sim, vender algumas a\xe7\xf5es para voltar \xe0 aloca\xe7\xe3o-alvo",feedback:"O reequil\xedbrio sistem\xe1tico aplica mecanicamente 'vender caro, comprar barato'. \xc9 uma das poucas a\xe7\xf5es mec\xe2nicas que produz melhor desempenho ajustado ao risco."}},{id:"inv_014",category:"investment",title:"Im\xf3vel para Alugar",scenario:"Voc\xea pode comprar um apartamento por $150.000 e alug\xe1-lo por $700/m\xeas. \xc9 um bom neg\xf3cio?",choice_liability:{label:"$700/m\xeas \xe9 renda garantida, \xe9 excelente",feedback:"$700/m\xeas bruto \u2260 $700 de renda l\xedquida. Condom\xednio, IPTU, vac\xe2ncia, reparos, administra\xe7\xe3o: o retorno l\xedquido pode cair para 2-3%."},choice_asset:{label:"Calcular o retorno l\xedquido (aluguel - todas as despesas - impostos) e comparar alternativas",feedback:"O rendimento real do aluguel: (aluguel anual - despesas - impostos - vac\xe2ncia - administra\xe7\xe3o) / pre\xe7o de compra. Um im\xf3vel a 3% l\xedquido n\xe3o \xe9 necessariamente melhor que um fundo de \xedndice de baixo custo."}},{id:"inv_015",category:"investment",title:"Investir em Seu Pr\xf3prio Treinamento",scenario:"Um curso avan\xe7ado custa $2.500 e poderia potencialmente aumentar sua renda em $300/m\xeas. Faz as contas?",choice_liability:{label:"Caro demais para resultados incertos",feedback:"$2.500 / $300 = 8,3 meses de retorno. Se o treinamento realmente entrega $300/m\xeas extra, \xe9 um dos melhores retornos sobre investimento dispon\xedveis."},choice_asset:{label:"Sim, um ROI de ~8 meses \xe9 excelente \u2014 mas verifique os resultados comprovados do treinamento",feedback:"O investimento em si mesmo \xe9 frequentemente o mais rent\xe1vel. Mas 'potencialmente' n\xe3o \xe9 garantia. Busque depoimentos verific\xe1veis antes de investir."}},{id:"inv_016",category:"investment",title:"Carteira Concentrada vs Diversificada",scenario:"Investir em 5 ativos que voc\xea entende perfeitamente OU em 50 ativos atrav\xe9s de um fundo. O que prefere?",choice_liability:{label:"5 ativos que entendo bem, a concentra\xe7\xe3o maximiza os ganhos",feedback:"A concentra\xe7\xe3o pode maximizar ganhos \u2014 e perdas. Warren Buffett pode fazer isso porque passa 12 horas/dia em an\xe1lise. Para a maioria dos investidores, a concentra\xe7\xe3o \xe9 risco excessivo."},choice_asset:{label:"50 ativos diversificados para reduzir o risco idiossincr\xe1tico de cada um",feedback:"A diversifica\xe7\xe3o \xe9 o \xfanico almo\xe7o gr\xe1tis em finan\xe7as. 50 ativos n\xe3o correlacionados reduzem dramaticamente a volatilidade sem necessariamente reduzir o retorno esperado de longo prazo."}},{id:"inv_017",category:"investment",title:"Vender Antes da Queda",scenario:"Especialistas preveem uma recess\xe3o. Voc\xea vende tudo para esperar?",choice_liability:{label:"Sim, melhor proteger os ganhos enquanto espero certeza",feedback:"A certeza n\xe3o existe em finan\xe7as. Vender tudo cria dois problemas: quando reentrar? E se a queda n\xe3o ocorrer, voc\xea perdeu o ganho enquanto esperava."},choice_asset:{label:"Permanecer investido conforme minha aloca\xe7\xe3o-alvo e talvez aumentar a poupan\xe7a para comprar a queda",feedback:"Estar pronto para comprar durante uma queda sem vender em p\xe2nico \xe9 a estrat\xe9gia do investidor maduro."}},{id:"inv_018",category:"investment",title:"Investimento em Start-up",scenario:"Um amigo est\xe1 lan\xe7ando uma start-up e busca investidores. Ele oferece participa\xe7\xe3o por $5.000. Voc\xea entra?",choice_liability:{label:"Sim, start-ups podem retornar 10x se voc\xea entrar cedo",feedback:"As estat\xedsticas: 90% das start-ups fracassam. Um investimento de $5.000 na start-up de um amigo tem alta probabilidade de ir a zero E criar tens\xe3o no relacionamento."},choice_asset:{label:"Avaliar como qualquer investimento: plano de neg\xf3cios, tra\xe7\xe3o, equipe e risco de perda total",feedback:"Um investimento em start-up merece tanto rigor quanto um investimento em bolsa. S\xf3 invista se aceitar a prov\xe1vel perda total e realmente entender o modelo de neg\xf3cios."}},{id:"inv_019",category:"investment",title:"Liquidez",scenario:"Todos os seus ativos est\xe3o investidos a longo prazo e surge uma emerg\xeancia de $1.500. O que faz?",choice_liability:{label:"Vender rapidamente parte dos meus investimentos",feedback:"Vender ativos de longo prazo para uma emerg\xeancia de curto prazo \xe9 exatamente o que o fundo de emerg\xeancia deve prevenir."},choice_asset:{label:"Usar meu fundo de emerg\xeancia l\xedquido \u2014 \xe9 exatamente para isso que existe",feedback:"O fundo de emerg\xeancia \xe9 o amortecedor que permite nunca tocar nos investimentos de longo prazo."}},{id:"inv_020",category:"investment",title:"ESG na Carteira",scenario:"Voc\xea descobre que uma empresa da sua carteira tem comportamento ambiental contestado. O que faz?",choice_liability:{label:"N\xe3o fazer nada \u2014 \xe9 problema deles, n\xe3o meu",feedback:"Como acionista, voc\xea \xe9 propriet\xe1rio parcial da empresa e suas pr\xe1ticas. Seu investimento as financia indiretamente."},choice_asset:{label:"Avaliar se vender ou manter baseado tanto em seus valores QUANTO nas perspectivas financeiras",feedback:"Ambos os crit\xe9rios podem se alinhar: pr\xe1ticas contestadas frequentemente criam riscos regulat\xf3rios e reputacionais a longo prazo."}},{id:"inv_021",category:"investment",title:"Dividendos vs Ganhos de Capital",scenario:"Voc\xea prefere a\xe7\xf5es de dividendo (4%/ano) ou a\xe7\xf5es de crescimento (0% dividendo mas 12% de crescimento esperado)?",choice_liability:{label:"Dividendos \u2014 \xe9 renda regular real",feedback:"Dividendos s\xe3o atraentes mas fiscalmente menos eficientes em alguns pa\xedses. Uma a\xe7\xe3o crescendo 12% cria tanto valor quanto 4% de dividendo + 8% de valoriza\xe7\xe3o de pre\xe7o."},choice_asset:{label:"Analisar retorno total (dividendo + valoriza\xe7\xe3o) e tratamento fiscal no seu pa\xeds",feedback:"O retorno total (dividendo + crescimento) \xe9 a m\xe9trica verdadeira. A prefer\xeancia por dividendo vs crescimento tamb\xe9m depende da sua faixa de imposto e necessidade de renda atual."}},{id:"inv_022",category:"investment",title:"Investir em Ouro",scenario:"Durante incerteza econ\xf4mica, um consultor recomenda 'colocar tudo em ouro'. Voc\xea concorda?",choice_liability:{label:"Sim, ouro \xe9 um porto seguro universal",feedback:"O ouro \xe9 uma reserva de valor, n\xe3o um ativo produtivo. N\xe3o gera dividendo, aluguel nem juro. No longo prazo, seu retorno real \xe9 pr\xf3ximo a zero ap\xf3s a infla\xe7\xe3o."},choice_asset:{label:"Alocar uma fra\xe7\xe3o limitada em ouro como diversifica\xe7\xe3o, n\xe3o como estrat\xe9gia principal",feedback:"O ouro tem seu lugar em uma carteira diversificada como prote\xe7\xe3o contra a infla\xe7\xe3o. Mas 'tudo' em ouro substitui um risco por outro."}},{id:"inv_023",category:"investment",title:"ETFs vs Fundos Ativos",scenario:"Voc\xea deve escolher entre um ETF a 0,15%/ano e um fundo ativo que afirma superar o mercado a 1,5%/ano. Crit\xe9rio?",choice_liability:{label:"O fundo ativo se seu gestor tiver boa reputa\xe7\xe3o",feedback:"A reputa\xe7\xe3o passada n\xe3o prev\xea o desempenho futuro. 90% dos gestores ativos t\xeam desempenho inferior ao \xedndice em 15 anos ap\xf3s as taxas."},choice_asset:{label:"O ETF na grande maioria dos casos \u2014 os dados mostram a superioridade dos \xedndices a longo prazo",feedback:"Os estudos acad\xeamicos s\xe3o un\xe2nimes: em 15+ anos, mais de 90% dos fundos ativos t\xeam desempenho inferior ao \xedndice de refer\xeancia ap\xf3s as taxas."}},{id:"inv_024",category:"investment",title:"Aloca\xe7\xe3o de Ativos no In\xedcio da Carreira",scenario:"Voc\xea tem 25 anos e come\xe7a a investir. Qual aloca\xe7\xe3o escolher?",choice_liability:{label:"50% a\xe7\xf5es, 50% t\xedtulos para 'risco equilibrado'",feedback:"Aos 25, voc\xea tem um horizonte de investimento de 40 anos. Os t\xedtulos over-diversificam para baixo. Nessa idade, a resili\xeancia ao ciclo favorece uma aloca\xe7\xe3o mais agressiva em ativos produtivos."},choice_asset:{label:"Aloca\xe7\xe3o majorit\xe1ria em ativos produtivos \u2014 o longo horizonte compensa a volatilidade",feedback:"Aos 25, o tempo \xe9 seu melhor ativo. A volatilidade de curto prazo \xe9 absorvida pelas d\xe9cadas \xe0 frente. Uma aloca\xe7\xe3o adequada a um longo horizonte maximiza o potencial de crescimento."}},{id:"inv_025",category:"investment",title:"Not\xedcias Financeiras",scenario:"As not\xedcias financeiras anunciam uma crise iminente. Voc\xea verifica seus investimentos?",choice_liability:{label:"Sim, monitorar diariamente para reagir r\xe1pido se algo der errado",feedback:"Estudos mostram que quanto mais um investidor verifica sua carteira, mais opera (muitas vezes no momento errado). O monitoramento di\xe1rio aumenta a ansiedade sem melhorar os resultados."},choice_asset:{label:"N\xe3o, minha estrat\xe9gia est\xe1 definida. Reavalia no m\xe1ximo trimestralmente",feedback:"O investidor apaixonado que monitora diariamente geralmente tem desempenho inferior ao que define sua estrat\xe9gia e executa sem olhar as not\xedcias."}},{id:"inv_026",category:"investment",title:"Investir Atrav\xe9s de uma Estrutura Dedicada",scenario:"Voc\xea pode investir atrav\xe9s de uma empresa ou holding de investimentos para otimizar sua situa\xe7\xe3o. Vale o custo da estrutura?",choice_liability:{label:"N\xe3o, muito complexo e caro para gerenciar",feedback:"Para valores significativos, uma estrutura dedicada pode representar vantagens que superam em muito os custos de gest\xe3o. Avalie com base nos valores envolvidos e nas regulamenta\xe7\xf5es locais."},choice_asset:{label:"Analisar o ponto de equil\xedbrio entre custos da estrutura e vantagens reais com base nos valores e na sua jurisdi\xe7\xe3o",feedback:"Uma estrutura de investimento dedicada se torna relevante acima de certo n\xedvel de patrim\xf4nio. Abaixo disso, os custos de cria\xe7\xe3o e gest\xe3o superam os benef\xedcios \u2014 e as regras variam muito por pa\xeds."}},{id:"inv_027",category:"investment",title:"Investir em Seu Pr\xf3prio Neg\xf3cio",scenario:"Voc\xea pode investir $10.000 na bolsa ou no seu pr\xf3prio neg\xf3cio. O que escolhe?",choice_liability:{label:"Bolsa \u2014 \xe9 mais segura e mais l\xedquida",feedback:"A bolsa \xe9 l\xedquida mas voc\xea n\xe3o tem controle sobre as empresas. Seu pr\xf3prio neg\xf3cio oferece controle total e potencialmente os melhores retornos \u2014 mas tamb\xe9m o maior risco."},choice_asset:{label:"Depende do est\xe1gio do neg\xf3cio: est\xe1gio inicial vai para o neg\xf3cio, neg\xf3cio maduro \u2192 diversificar",feedback:"As melhores oportunidades de retorno est\xe3o frequentemente em seu pr\xf3prio neg\xf3cio em est\xe1gio inicial. \xc0 medida que o neg\xf3cio amadurece, diversificar progressivamente reduz o risco de concentra\xe7\xe3o."}},{id:"inv_028",category:"investment",title:"A Carteira Herdada",scenario:"Voc\xea herda uma carteira investida em t\xedtulos que n\xe3o entende. Voc\xea mant\xe9m ou reestrutura?",choice_liability:{label:"Manter sem mudar \u2014 funcionou para o falecido",feedback:"Uma carteira adequada para outra pessoa (idade, objetivos, situa\xe7\xe3o fiscal diferentes) n\xe3o \xe9 necessariamente adequada para a sua. Entender o que voc\xea possui \xe9 um m\xednimo."},choice_asset:{label:"Entender cada posi\xe7\xe3o, avaliar se est\xe1 alinhada com meus objetivos, reestruturar se necess\xe1rio",feedback:"Herdar uma carteira merece tanto an\xe1lise quanto construir a pr\xf3pria. Alinhar os investimentos herdados com seus pr\xf3prios objetivos e horizonte temporal \xe9 uma responsabilidade fiduci\xe1ria consigo mesmo."}},{id:"inv_029",category:"investment",title:"O Investimento Clim\xe1tico",scenario:"Voc\xea acredita que a transi\xe7\xe3o energ\xe9tica criar\xe1 as maiores oportunidades da d\xe9cada. Como investe?",choice_liability:{label:"Tudo em empresas verdes e energias renov\xe1veis",feedback:"A convic\xe7\xe3o tem\xe1tica pode estar certa mas o timing e a sele\xe7\xe3o continuam sendo cruciais. Um setor pode ter um futuro brilhante mas j\xe1 ter valuations excessivos."},choice_asset:{label:"Alocar uma fra\xe7\xe3o da carteira neste tema mantendo uma base diversificada",feedback:"Uma convic\xe7\xe3o tem\xe1tica justifica uma sobrepondera\xe7\xe3o, n\xe3o uma concentra\xe7\xe3o total. Manter uma base diversificada protege contra a possibilidade de que o tema esteja certo mas o timing errado."}},{id:"inv_030",category:"investment",title:"Im\xf3vel Direto vs FIIs",scenario:"Voc\xea quer exposi\xe7\xe3o ao setor imobili\xe1rio. Im\xf3vel direto ou fundo imobili\xe1rio?",choice_liability:{label:"Im\xf3vel direto \u2014 \xe9 tang\xedvel e voc\xea controla tudo",feedback:"O im\xf3vel direto oferece controle total mas tamb\xe9m gest\xe3o ativa, baixa liquidez e concentra\xe7\xe3o geogr\xe1fica. N\xe3o \xe9 um ativo passivo."},choice_asset:{label:"Avaliar ambos por liquidez, diversifica\xe7\xe3o, retorno l\xedquido e tempo de gest\xe3o",feedback:"Os fundos imobili\xe1rios oferecem diversifica\xe7\xe3o, liquidez e zero gest\xe3o. O im\xf3vel direto oferece alavancagem, controle e poss\xedveis vantagens fiscais. Ambos t\xeam seu lugar segundo o perfil."}},{id:"mn_001",category:"mindset",title:"O Reflexo E vs B",scenario:"Voc\xea tem uma ideia de neg\xf3cio mas seu emprego atual \xe9 est\xe1vel e bem pago. O que faz?",choice_liability:{label:"Manter o emprego est\xe1vel \u2014 seguran\xe7a em primeiro lugar",feedback:"A mentalidade de Empregado (E) valoriza a seguran\xe7a do sal\xe1rio. A estabilidade tem valor real \u2014 mas tamb\xe9m pode se tornar um teto que impede a verdadeira liberdade financeira."},choice_asset:{label:"Testar a ideia em paralelo nas noites/fins de semana antes de dar o salto",feedback:"O quadrante B (Dono de Neg\xf3cio) frequentemente come\xe7a fora do hor\xe1rio de trabalho. Testar com baixo risco antes de pular \xe9 a estrat\xe9gia da maioria dos empreendedores bem-sucedidos."}},{id:"mn_002",category:"mindset",title:"A Defini\xe7\xe3o de Risco",scenario:"Seu c\xedrculo diz 'investir \xe9 arriscado'. Como voc\xea reage?",choice_liability:{label:"Eles t\xeam raz\xe3o \u2014 melhor manter o dinheiro em uma poupan\xe7a segura",feedback:"N\xe3o investir tamb\xe9m tem um risco: o risco da infla\xe7\xe3o que erode o poder de compra e o risco de n\xe3o atingir os objetivos financeiros de longo prazo."},choice_asset:{label:"N\xe3o investir tamb\xe9m \xe9 um risco \u2014 perder poder de compra e d\xe9cadas de crescimento",feedback:"Kiyosaki diz que a educa\xe7\xe3o financeira reduz o risco. O que \xe9 arriscado para algu\xe9m sem forma\xe7\xe3o n\xe3o \xe9 arriscado para algu\xe9m que entende o que est\xe1 fazendo."}},{id:"mn_003",category:"mindset",title:"O Dinheiro e as Emo\xe7\xf5es",scenario:"Voc\xea toma uma m\xe1 decis\xe3o financeira e perde $500. Como lida?",choice_liability:{label:"Se punir mentalmente e evitar riscos por meses",feedback:"A avers\xe3o a perdas \xe9 o vi\xe9s comportamental mais documentado. Um investidor que se autopune ap\xf3s um erro toma piores decis\xf5es futuras por excesso de cautela."},choice_asset:{label:"Analisar objetivamente o erro, tirar uma li\xe7\xe3o e seguir em frente",feedback:"Os melhores investidores cometem erros \u2014 e tiram li\xe7\xf5es sem se afogar emocionalmente neles. A objetividade p\xf3s-erro \xe9 uma habilidade que se cultiva."}},{id:"mn_004",category:"mindset",title:"A Riqueza Vis\xedvel",scenario:"Seu vizinho compra um carro de luxo. Qual \xe9 sua rea\xe7\xe3o interior?",choice_liability:{label:"Ele chegou l\xe1 \u2014 pode se dar ao luxo, eu deveria trabalhar mais duro",feedback:"A s\xedndrome do vizinho rico. Estudos sobre milion\xe1rios mostram que a riqueza real \xe9 frequentemente invis\xedvel: carros modestos, casas moderadas, riqueza em ativos n\xe3o exibidos."},choice_asset:{label:"O carro n\xe3o prova nada \u2014 a riqueza real est\xe1 em ativos invis\xedveis",feedback:"'O Milion\xe1rio da Porta ao Lado' documenta que a maioria dos verdadeiramente ricos n\xe3o o exibe. Um carro de luxo pode sinalizar riqueza real ou d\xedvida bem escondida."}},{id:"mn_005",category:"mindset",title:"Educa\xe7\xe3o Financeira",scenario:"Voc\xea tem 2 horas livres neste fim de semana. O que faz?",choice_liability:{label:"Assistir a uma s\xe9rie ou descansar \u2014 voc\xea trabalhou duro esta semana",feedback:"O descanso \xe9 leg\xedtimo e necess\xe1rio. Mas 2 horas de conte\xfado educativo financeiro por semana podem transformar sua rela\xe7\xe3o com o dinheiro em 1 ano."},choice_asset:{label:"Ler um livro ou ouvir um podcast sobre finan\xe7as e investimentos",feedback:"Kiyosaki diz que a diferen\xe7a entre os ricos e os demais \xe9 o que fazem com seu tempo livre. A educa\xe7\xe3o financeira \xe9 um investimento em si mesmo que paga por toda a vida."}},{id:"mn_006",category:"mindset",title:"Conselhos dos Ricos",scenario:"Voc\xea tem a oportunidade de almo\xe7ar com uma pessoa muito abastada. Qual pergunta faz?",choice_liability:{label:"Como voc\xea come\xe7ou? Qual foi seu grande lance de sorte?",feedback:"A pergunta do 'lance de sorte' busca o atalho. Mas a maioria das fortunas duradouras resulta de uma constru\xe7\xe3o met\xf3dica, n\xe3o de um \xfanico dado de azar."},choice_asset:{label:"Qual erro voc\xea me pouparia? Qual h\xe1bito mais mudou sua trajet\xf3ria?",feedback:"Perguntas sobre erros e h\xe1bitos d\xe3o informa\xe7\xf5es acion\xe1veis. Os que t\xeam sucesso no longo prazo geralmente t\xeam sistemas e h\xe1bitos mais do que golpes de sorte."}},{id:"mn_007",category:"mindset",title:"O Medo de Come\xe7ar",scenario:"Voc\xea quer investir mas pensa 'ainda n\xe3o, preciso saber mais primeiro'. H\xe1 2 anos. O que faz?",choice_liability:{label:"Continuar aprendendo \u2014 melhor ter certeza antes de come\xe7ar",feedback:"A espera perfeita \xe9 inimiga da realidade imperfeita. 2 anos sem investir tem um custo de oportunidade real. O conhecimento perfeito n\xe3o existe \u2014 a a\xe7\xe3o com incerteza existe."},choice_asset:{label:"Come\xe7ar pequeno com o que voc\xea sabe, e aprender fazendo",feedback:"As habilidades financeiras reais se desenvolvem na pr\xe1tica, n\xe3o apenas na teoria. Um pequeno investimento real ensina mais do que cem horas de leitura."}},{id:"mn_008",category:"mindset",title:"A Cr\xedtica do Seu C\xedrculo",scenario:"Voc\xea decide investir e sua fam\xedlia diz 'vai perder tudo'. Como voc\xea reage?",choice_liability:{label:"Desistir ou manter os planos em segredo para evitar conflito",feedback:"Esconder seus projetos financeiros ou ceder \xe0 press\xe3o social ambos permitem que seu ambiente controle sua trajet\xf3ria financeira."},choice_asset:{label:"Ouvir a preocupa\xe7\xe3o, analis\xe1-la racionalmente, depois decidir com base em sua pr\xf3pria pesquisa",feedback:"A cr\xedtica familiar geralmente vem do medo, n\xe3o da expertise. Ou\xe7a sem obedecer automaticamente. Analise o fundo do argumento, n\xe3o a forma emocional."}},{id:"mn_009",category:"mindset",title:"Tempo vs Dinheiro",scenario:"Voc\xea pode aceitar uma tarefa extra por $500 a mais este m\xeas. Mas levaria 20 horas do seu tempo livre. Voc\xea aceita?",choice_liability:{label:"Sim, $500 s\xe3o $500 \u2014 n\xe3o se recusa dinheiro",feedback:"$500 / 20h = $25/h. A quest\xe3o real: quanto vale seu tempo livre? E essas 20 horas poderiam ser usadas para construir algo que paga mais no longo prazo?"},choice_asset:{label:"Depende das minhas finan\xe7as e do que eu faria com esse tempo de outra forma",feedback:"O tempo \xe9 o ativo n\xe3o renov\xe1vel. A $25/h, a tarefa pode valer \u2014 ou n\xe3o. A decis\xe3o deve considerar o que 20 horas de tempo livre poderiam criar alternativamente."}},{id:"mn_010",category:"mindset",title:"A Vergonha de Falar de Dinheiro",scenario:"Voc\xea nunca fala de dinheiro com amigos por medo de parecer 'obcecado'. \xc9 saud\xe1vel?",choice_liability:{label:"Sim, dinheiro \xe9 um assunto privado que n\xe3o deve ser mencionado",feedback:"O tabu do dinheiro \xe9 culturalmente constru\xeddo \u2014 e muito caro. Impede compartilhar boas pr\xe1ticas, descobrir erros comuns e ajudar-se mutuamente financeiramente."},choice_asset:{label:"N\xe3o, falar de dinheiro com gentileza \xe9 uma fonte de aprendizado coletivo",feedback:"Pessoas que discutem abertamente o dinheiro com seu c\xedrculo aprendem mais r\xe1pido e cometem menos erros. O tabu financeiro protege os que vendem produtos caros e mal adaptados."}},{id:"mn_011",category:"mindset",title:"Identidade Financeira",scenario:"Voc\xea se descreve como 'algu\xe9m que n\xe3o \xe9 bom com dinheiro'. \xc9 verdade?",choice_liability:{label:"Sim, algumas pessoas simplesmente t\xeam esse dom e outras n\xe3o",feedback:"A identidade financeira negativa \xe9 uma profecia que se cumpre. Acreditar que 'n\xe3o \xe9 bom com dinheiro' impede de aprender e mudar comportamentos."},choice_asset:{label:"N\xe3o, \xe9 uma habilidade que se aprende \u2014 n\xe3o um tra\xe7o de car\xe1ter inato",feedback:"A educa\xe7\xe3o financeira \xe9 uma habilidade, n\xe3o um talento inato. Kiyosaki era pobre antes de ser rico. Bons h\xe1bitos financeiros podem ser aprendidos em qualquer idade."}},{id:"mn_012",category:"mindset",title:"O Ci\xfame do Sucesso",scenario:"Voc\xea v\xea o sucesso financeiro de um colega e sente ci\xfame. Como o transforma?",choice_liability:{label:"Evitar encontr\xe1-lo \u2014 o sucesso dele te incomoda",feedback:"O ci\xfame evitado estagna. N\xe3o se transforma em motiva\xe7\xe3o sem reflex\xe3o consciente sobre o que revela sobre seus pr\xf3prios desejos e bloqueios."},choice_asset:{label:"Usar o ci\xfame como sinal para identificar o que voc\xea realmente quer e como conseguir",feedback:"O ci\xfame \xe9 uma b\xfassola emocional. Aponta para algo que voc\xea valoriza mas n\xe3o tem. Usado conscientemente, torna-se motiva\xe7\xe3o e clarifica\xe7\xe3o de prioridades."}},{id:"mn_013",category:"mindset",title:"Generosidade e Riqueza",scenario:"Voc\xea pensa que ser rico significa ser ganancioso. Kiyosaki concordaria?",choice_liability:{label:"Sim, os ricos guardam tudo para si, por isso enriquecem",feedback:"A correla\xe7\xe3o riqueza-gan\xe2ncia \xe9 um mito. Estudos sobre milion\xe1rios mostram que a generosidade \xe9 mais prevalente entre os ricos do que entre os que buscam aparentar serem ricos."},choice_asset:{label:"N\xe3o, generosidade e riqueza s\xe3o compat\xedveis \u2014 a riqueza real vem do excedente, n\xe3o da priva\xe7\xe3o",feedback:"Kiyosaki enfatiza que a riqueza real cria abund\xe2ncia para compartilhar. A generosidade de uma pessoa rica com ativos produtivos custa proporcionalmente menos do que a generosidade for\xe7ada pela culpa."}},{id:"mn_014",category:"mindset",title:"Disciplina Financeira Di\xe1ria",scenario:"Voc\xea tem um or\xe7amento mensal que frequentemente n\xe3o cumpre. Por qu\xea?",choice_liability:{label:"Porque a vida \xe9 imprevis\xedvel e os or\xe7amentos s\xe3o r\xedgidos demais",feedback:"Um or\xe7amento pode ser flex\xedvel sem ser ignorado. O imprevis\xedvel pode ser or\xe7ado (fundo de emerg\xeancia, or\xe7amento diverso). O problema real \xe9 frequentemente falta de acompanhamento, n\xe3o rigidez."},choice_asset:{label:"Porque o or\xe7amento n\xe3o est\xe1 automatizado e a for\xe7a de vontade sozinha n\xe3o \xe9 suficiente",feedback:"A for\xe7a de vontade \xe9 um m\xfasculo que se esgota. Sistemas autom\xe1ticos (transfer\xeancias autom\xe1ticas, or\xe7amentos categorizados por apps) substituem a for\xe7a de vontade por mecanismos confi\xe1veis."}},{id:"mn_015",category:"mindset",title:"O Dinheiro e a Felicidade",scenario:"Um amigo diz: 'O dinheiro n\xe3o traz felicidade'. O que voc\xea responde?",choice_liability:{label:"Ele tem raz\xe3o, a felicidade vem das rela\xe7\xf5es e das experi\xeancias, n\xe3o do dinheiro",feedback:"Parcialmente verdadeiro. Mas abaixo de certo patamar de seguran\xe7a financeira, a falta de dinheiro causa estresse cr\xf4nico real que afeta diretamente a felicidade."},choice_asset:{label:"O dinheiro n\xe3o traz felicidade, mas sua aus\xeancia pode causar muito sofrimento",feedback:"A pesquisa psicol\xf3gica mostra que o dinheiro aumenta a felicidade at\xe9 um patamar de seguran\xe7a. Abaixo desse patamar, os problemas financeiros s\xe3o a principal fonte de estresse cr\xf4nico."}},{id:"mn_016",category:"mindset",title:"A Liberdade Financeira como Objetivo",scenario:"Seu objetivo de 10 anos: liberdade financeira ou promo\xe7\xe3o de carreira?",choice_liability:{label:"Promo\xe7\xe3o \u2014 \xe9 concreto, mensur\xe1vel e socialmente valorizado",feedback:"A promo\xe7\xe3o aumenta o sal\xe1rio \u2014 uma renda ativa. A liberdade financeira visa renda passiva. Ambos podem coexistir, mas a promo\xe7\xe3o sozinha n\xe3o leva automaticamente \xe0 liberdade."},choice_asset:{label:"Os dois n\xe3o se op\xf5em \u2014 usar a promo\xe7\xe3o para acelerar a liberdade financeira",feedback:"A promo\xe7\xe3o pode financiar o investimento que leva \xe0 liberdade. O erro \xe9 gastar o aumento em vez de investi-lo. A promo\xe7\xe3o \xe9 um acelerador, n\xe3o um destino."}},{id:"mn_017",category:"mindset",title:"Paci\xeancia e Riqueza",scenario:"Voc\xea quer resultados financeiros r\xe1pidos. \xc9 realista?",choice_liability:{label:"Sim, com os investimentos certos voc\xea pode enriquecer r\xe1pido",feedback:"A busca por riqueza r\xe1pida \xe9 a fonte da maioria dos golpes financeiros. Retornos excepcionais de curto prazo implicam risco excepcional \u2014 frequentemente mal compreendido."},choice_asset:{label:"A riqueza real \xe9 lenta e previs\xedvel \u2014 atalhos quase sempre custam mais",feedback:"A riqueza duradoura \xe9 constru\xedda ao longo de d\xe9cadas, n\xe3o meses. As pessoas mais ricas do mundo se beneficiaram massivamente de d\xe9cadas de juros compostos, n\xe3o de golpes de g\xeanio."}},{id:"mn_018",category:"mindset",title:"O Erro Financeiro",scenario:"Voc\xea percebe que pagou caro demais por um ativo. Voc\xea vende com preju\xedzo ou mant\xe9m?",choice_liability:{label:"Manter para n\xe3o 'realizar o preju\xedzo'",feedback:"Este \xe9 o vi\xe9s de avers\xe3o a perdas. Uma perda no papel \xe9 uma perda econ\xf4mica real independentemente da coluna cont\xe1bil. Manter um mau ativo esperando recupera\xe7\xe3o \xe9 irracional se a an\xe1lise mudou."},choice_asset:{label:"Analisar objetivamente se as perspectivas justificam manter \u2014 independentemente do pre\xe7o pago",feedback:"A an\xe1lise de 'o que faria se n\xe3o tivesse j\xe1 esse ativo? Compraria hoje?' elimina o vi\xe9s do pre\xe7o pago. A decis\xe3o deve ser baseada nas perspectivas futuras, n\xe3o no custo passado."}},{id:"mn_019",category:"mindset",title:"Trabalho Duro vs Sistema",scenario:"Voc\xea acredita que trabalhar mais duro do que todos \xe9 a chave do sucesso financeiro. Kiyosaki concordaria?",choice_liability:{label:"Sim, esfor\xe7o e perseveran\xe7a s\xe3o a chave absoluta",feedback:"O trabalho duro \xe9 necess\xe1rio mas insuficiente. Kiyosaki observa que os empregados que trabalham mais duro s\xe3o frequentemente os menos ricos, porque seu esfor\xe7o enriquece a empresa, n\xe3o a sua pr\xf3pria coluna de ativos."},choice_asset:{label:"N\xe3o, Kiyosaki insiste: o sistema certo > trabalho duro sozinho",feedback:"'Trabalhe duro para voc\xea mesmo, n\xe3o para outra pessoa' \xe9 a mensagem central de Pai Rico Pai Pobre. Construir sistemas (neg\xf3cio, ativos) que trabalham sem voc\xea \xe9 a verdadeira liberdade."}},{id:"mn_020",category:"mindset",title:"Compara\xe7\xe3o Social",scenario:"Seus amigos parecem 'ter sucesso' nas redes sociais. Isso te afeta financeiramente?",choice_liability:{label:"Sim, as postagens deles me impulsionam a gastar para parecer no mesmo n\xedvel",feedback:"A compara\xe7\xe3o alimentada pelas redes sociais \xe9 um poderoso motor de gastos impulsivos. Voc\xea paga despesas reais por uma imagem virtual."},choice_asset:{label:"N\xe3o, sei que as redes mostram o melhor de todos \u2014 s\xf3 me comparo com meu eu do passado",feedback:"Comparar sua realidade com a vitrine dos outros \xe9 uma ilus\xe3o. A \xfanica compara\xe7\xe3o relevante: voc\xea est\xe1 em melhor situa\xe7\xe3o do que h\xe1 um ano? O progresso pessoal \xe9 a verdadeira m\xe9trica."}},{id:"mn_021",category:"mindset",title:"Delega\xe7\xe3o",scenario:"Voc\xea gerencia tudo sozinho para 'evitar golpes'. \xc9 \xf3timo?",choice_liability:{label:"Sim, ningu\xe9m gerencia meu dinheiro melhor do que eu",feedback:"A sobrecentraliza\xe7\xe3o \xe9 um gargalo. Pessoas muito abastadas delegam a execu\xe7\xe3o enquanto mant\xeam a supervis\xe3o estrat\xe9gica."},choice_asset:{label:"Delegar a execu\xe7\xe3o de certas tarefas financeiras mantendo a supervis\xe3o estrat\xe9gica",feedback:"A riqueza escal\xe1vel envolve delega\xe7\xe3o. Contador, consultor, administrador de propriedades: delegar a execu\xe7\xe3o libera seu tempo para decis\xf5es de alto valor."}},{id:"mn_022",category:"mindset",title:"Aprender com os Erros dos Outros",scenario:"Voc\xea conhece algu\xe9m que faliu. Como usa essa experi\xeancia?",choice_liability:{label:"Evitar tudo o que eles fizeram, mesmo que os contextos sejam diferentes",feedback:"Copiar o medo de algu\xe9m sem analisar o contexto \xe9 t\xe3o irracional quanto copiar suas a\xe7\xf5es sem reflex\xe3o. Cada situa\xe7\xe3o financeira \xe9 \xfanica."},choice_asset:{label:"Analisar as causas estruturais do fracasso para extrair princ\xedpios aplic\xe1veis",feedback:"Os fracassos alheios s\xe3o li\xe7\xf5es gratuitas. Entender os mecanismos (alavancagem excessiva, falta de liquidez, concentra\xe7\xe3o) mais do que as anedotas espec\xedficas extrai princ\xedpios transfer\xedveis."}},{id:"mn_023",category:"mindset",title:"O Luxo e o Valor",scenario:"Voc\xea est\xe1 hesitando sobre um item de luxo de $800. Como decide?",choice_liability:{label:"O luxo recompensa o trabalho duro \u2014 voc\xea merece se atingiu o objetivo",feedback:"A recompensa material n\xe3o \xe9 problem\xe1tica em si \u2014 se for or\xe7ada e proporcional aos ativos constru\xeddos. O problema \xe9 quando o luxo precede os ativos."},choice_asset:{label:"Comprar se meus ativos cobrem facilmente \u2014 n\xe3o se comprometer meu investimento mensal",feedback:"A regra de Kiyosaki: os ricos compram o luxo por \xfaltimo, com a renda dos seus ativos. Os pobres e a classe m\xe9dia compram o luxo primeiro, com sua renda ativa."}},{id:"mn_024",category:"mindset",title:"A Liberdade do Empregado",scenario:"Seu chefe oferece uma grande promo\xe7\xe3o com mais responsabilidade mas mais restri\xe7\xf5es. Voc\xea aceita?",choice_liability:{label:"Sim, a promo\xe7\xe3o \xe9 a progress\xe3o natural da carreira",feedback:"Uma promo\xe7\xe3o que te acorrenta mais \xe0 troca tempo-por-dinheiro n\xe3o \xe9 progresso rumo \xe0 liberdade. \xc9 progresso dentro do quadrante E/S."},choice_asset:{label:"Aceitar se a promo\xe7\xe3o financia um projeto de ativo \u2014 recusar se consome mais tempo sem criar independ\xeancia",feedback:"A promo\xe7\xe3o n\xe3o \xe9 boa nem ruim \u2014 \xe9 o que voc\xea faz com ela. Se financia um investimento que reduz a depend\xeancia do sal\xe1rio, \xe9 alavancagem. Caso contr\xe1rio, \xe9 uma corrente de ouro."}},{id:"mn_025",category:"mindset",title:"Mentalidade de Abund\xe2ncia",scenario:"Um concorrente copia sua ideia de neg\xf3cio. Primeira rea\xe7\xe3o?",choice_liability:{label:"\xc9 uma trai\xe7\xe3o \u2014 voc\xea far\xe1 tudo para bloque\xe1-los",feedback:"A mentalidade de escassez v\xea a concorr\xeancia como uma amea\xe7a existencial. A mentalidade de abund\xe2ncia a v\xea como valida\xe7\xe3o do mercado e oportunidade de diferencia\xe7\xe3o."},choice_asset:{label:"A concorr\xeancia valida o mercado \u2014 foque no que te diferencia",feedback:"Um concorrente que copia sua ideia prova que o mercado existe. Kiyosaki fala de abund\xe2ncia: h\xe1 sucesso suficiente para todos. A corrida pela diferencia\xe7\xe3o \xe9 mais produtiva do que a batalha legal."}},{id:"mn_026",category:"mindset",title:"Primeiro Emprego e Dinheiro",scenario:"Voc\xea consegue seu primeiro emprego aos 22. Primeira decis\xe3o financeira?",choice_liability:{label:"Se instalar confortavelmente: bom apartamento, carro, sa\xeddas",feedback:"A armadilha do primeiro sal\xe1rio: infla\xe7\xe3o de estilo de vida desde o in\xedcio. H\xe1bitos estabelecidos aos 22 ser\xe3o dif\xedceis de mudar aos 30."},choice_asset:{label:"Automatizar 20% do sal\xe1rio para investimento desde o primeiro m\xeas, antes de se acostumar com o valor",feedback:"Pague-se primeiro \xe9 o princ\xedpio de Kiyosaki. Antes de se acostumar com o sal\xe1rio completo, alocar automaticamente uma parte para investimento cria um h\xe1bito fundamental."}},{id:"mn_027",category:"mindset",title:"O Respeito pelo Dinheiro",scenario:"Voc\xea recebe $20 a mais de troco no supermercado. O que faz?",choice_liability:{label:"Ficar com ele \u2014 n\xe3o \xe9 sua culpa que o caixa errou",feedback:"Uma quest\xe3o de valores al\xe9m das finan\xe7as. Mas como voc\xea trata o dinheiro em quantias pequenas reflete seu relacionamento com o dinheiro em geral."},choice_asset:{label:"Apontar e devolver o troco \u2014 a integridade se aplica tamb\xe9m \xe0s pequenas quantias",feedback:"Kiyosaki fala de respeitar o dinheiro em todas as suas formas. A integridade financeira nas coisas pequenas \xe9 a base da autoconfian\xe7a nas grandes decis\xf5es."}},{id:"mn_028",category:"mindset",title:"A Mentalidade E\u2192S\u2192B\u2192I",scenario:"Voc\xea \xe9 empregado e quer se tornar 'propriet\xe1rio de ativos'. Por onde come\xe7a?",choice_liability:{label:"Largar imediatamente o emprego para lan\xe7ar algo",feedback:"O salto imediato de E para B sem rede de seguran\xe7a \xe9 arriscado. A maioria dos empreendedores bem-sucedidos preparou sua transi\xe7\xe3o junto com o emprego, n\xe3o o largando abruptamente."},choice_asset:{label:"Construir progressivamente: E \u2192 projeto paralelo S \u2192 neg\xf3cio B \u2192 ativos passivos I em paralelo",feedback:"O quadrante de Kiyosaki n\xe3o \xe9 um salto \u2014 \xe9 uma progress\xe3o. Cada etapa se constr\xf3i sobre a anterior. A transi\xe7\xe3o \xe9 preparada enquanto se est\xe1 em seguran\xe7a."}},{id:"mn_029",category:"mindset",title:"Recusar a Mediocridade",scenario:"Voc\xea se pergunta se aspirar \xe0 liberdade financeira \xe9 arrogante ou pouco realista. Isso te para?",choice_liability:{label:"Um pouco sim \u2014 quem sou eu para querer mais do que a m\xe9dia?",feedback:"A normaliza\xe7\xe3o da mediocridade financeira \xe9 culturalmente constru\xedda. Perguntar 'quem sou eu para querer mais?' \xe9 um limite mental com um custo financeiro real ao longo de d\xe9cadas."},choice_asset:{label:"N\xe3o \u2014 aspirar \xe0 liberdade financeira n\xe3o \xe9 arrog\xe2ncia, \xe9 responsabilidade",feedback:"A liberdade financeira n\xe3o \xe9 um luxo \u2014 \xe9 a capacidade de escolher seu tempo, seus projetos e suas contribui\xe7\xf5es. Aspirar a ela \xe9 um ato de responsabilidade consigo mesmo e com seus entes queridos."}},{id:"mn_030",category:"mindset",title:"A Defini\xe7\xe3o de Sucesso",scenario:"Como voc\xea define o sucesso financeiro? Alto sal\xe1rio ou liberdade de tempo?",choice_liability:{label:"Alto sal\xe1rio \u2014 o reconhecimento e a compensa\xe7\xe3o provam o valor",feedback:"Um alto sal\xe1rio \xe9 sucesso no quadrante E. Mas Kiyosaki pergunta: se voc\xea parasse de trabalhar amanh\xe3, seu estilo de vida mudaria? Se sim, voc\xea ainda n\xe3o \xe9 financeiramente livre."},choice_asset:{label:"Liberdade de tempo \u2014 ter ativos que cobrem minhas despesas sem eu trabalhar",feedback:"Esta \xe9 a defini\xe7\xe3o de Kiyosaki: a liberdade financeira \xe9 quando seus ativos geram mais do que suas despesas. O sal\xe1rio \xe9 um meio, n\xe3o um fim. A liberdade de tempo \xe9 o destino."}},{id:"cf_031",category:"cashflow",title:"O Or\xe7amento de Alimenta\xe7\xe3o Inesperado",scenario:"Voc\xea percebe que gasta $400/m\xeas em alimenta\xe7\xe3o e delivery, $200 a mais do que planejado. O que faz?",choice_liability:{label:"\xc9 normal, a vida \xe9 cara \u2014 ajusto o or\xe7amento para cima",feedback:"Ajustar o or\xe7amento para cima para justificar uma despesa n\xe3o otimizada \xe9 o inverso da gest\xe3o financeira. O or\xe7amento guia as despesas, n\xe3o o contr\xe1rio."},choice_asset:{label:"Identificar os $200 em vazamentos (deliveries impulsivos, desperd\xedcio) e redirecion\xe1-los",feedback:"$200/m\xeas = $2.400/ano = um investimento significativo. Analisar vazamentos e redirecionar para um ativo \xe9 uma decis\xe3o de poucos minutos para um impacto anual maior."}}]}},1517,[]);
